/// Shared HTTP client for every cluster-peer / external / self-loop
/// call in this file. Previously ~40 API handlers each built their
/// own `reqwest::Client::builder()...build()`, leaking a connection
/// pool per handler invocation. Timeouts are set per-request via
/// `RequestBuilder::timeout` because each call site uses a different
/// deadline (3s health-check through 600s VM migration). A 3s
/// `connect_timeout` at Client level makes dead peers fail fast
/// without burning the full per-request budget on TCP handshake.
pub(crate) static API_HTTP_CLIENT: std::sync::LazyLock<reqwest::Client> =
    std::sync::LazyLock::new(|| {
        ipv4_only_client_builder()
            .connect_timeout(std::time::Duration::from_secs(3))
            .danger_accept_invalid_certs(true)
            // Aggressively trim the idle-connection pool so orphaned
            // sockets don't sit in CLOSE_WAIT for 90s (the default).
            // Reported by Bel: 5827 outbound CLOSE_WAIT against peer
            // :8553 endpoints built up alongside server-side leaks.
            .pool_idle_timeout(std::time::Duration::from_secs(15))
            .pool_max_idle_per_host(8)
            // Enable SO_KEEPALIVE so half-dead connections are
            // detected and torn down by the kernel rather than
            // lingering for minutes.
            .tcp_keepalive(std::time::Duration::from_secs(30))
            .build()
            .unwrap_or_else(|_| reqwest::Client::new())
    });

/// Start a reqwest ClientBuilder pinned to IPv4. Wolfstacks run on
/// mixed-stack hosts where AAAA records exist but the peer's :8553
/// is only bound to 0.0.0.0 — without this, hyper will happily try
/// the v6 address first, time out, and only then try the v4 one,
/// adding seconds of latency per call. `local_address` bound to
/// `Ipv4Addr::UNSPECIFIED` forces the outgoing socket into the IPv4
/// stack so v6 candidates are skipped.
pub(crate) fn ipv4_only_client_builder() -> reqwest::ClientBuilder {
    reqwest::Client::builder()
        .local_address(Some(std::net::IpAddr::V4(std::net::Ipv4Addr::UNSPECIFIED)))
}

/// Drain a response body before discarding so the socket returns to
/// the keep-alive pool. Used by handlers that only care about
/// `.status()` and would otherwise drop the Response unread.
#[allow(dead_code)]
async fn drain_response(resp: reqwest::Response) {
    let _ = resp.bytes().await;
}

/// Build ordered URLs to try for inter-node communication.
/// Check if an address is blocked for SSRF prevention (loopback, link-local, localhost)
fn is_ssrf_blocked_address(addr: &str) -> bool {
    use std::net::IpAddr;
    // URL hosts carry IPv6 literals in brackets — strip them so the
    // parse below sees the bare address ("[::1]" must not slip past).
    let bare = addr.strip_prefix('[').and_then(|a| a.strip_suffix(']')).unwrap_or(addr);
    // Only block if it parses as a bare IP — hostnames are legitimate
    if let Ok(ip) = bare.parse::<IpAddr>() {
        return ip.is_loopback()
            || matches!(ip, IpAddr::V4(a) if a.octets()[0] == 169 && a.octets()[1] == 254)
            // RFC 4291: fe80::/10 is IPv6 link-local — same class of
            // target as v4 169.254.0.0/16 above.
            || matches!(ip, IpAddr::V6(a) if (a.segments()[0] & 0xffc0) == 0xfe80);
    }
    // Reject "localhost" by name too
    addr.eq_ignore_ascii_case("localhost")
}

/// Address-keyed cache of each peer's host WolfNet IP. Populated from
/// StatusReport (`wolfnet_ips[0]` is the host's own WolfNet address).
/// Read by `build_node_urls` to insert a WolfNet-routed HTTP attempt
/// between the HTTPS and the plain-HTTP fallbacks — encrypted at the
/// WolfNet overlay layer instead of riding plaintext across the LAN.
///
/// Empty until the first peer reports — in that window `build_node_urls`
/// behaves identically to the pre-v20.9.9 3-URL chain. Stale entries are
/// harmless: a fail on the WolfNet URL falls through to the existing
/// HTTP fallbacks.
static NODE_WOLFNET_IPS: std::sync::LazyLock<std::sync::Mutex<std::collections::HashMap<String, String>>> =
    std::sync::LazyLock::new(|| std::sync::Mutex::new(std::collections::HashMap::new()));

/// Record the given peer's host WolfNet IP. Called from agent::poll_peers
/// when a StatusReport comes back. Empty `wolfnet_ip` clears the entry.
pub fn record_node_wolfnet_ip(address: &str, wolfnet_ip: &str) {
    if let Ok(mut map) = NODE_WOLFNET_IPS.lock() {
        if wolfnet_ip.is_empty() {
            map.remove(address);
        } else {
            map.insert(address.to_string(), wolfnet_ip.to_string());
        }
    }
}

pub fn lookup_node_wolfnet_ip(address: &str) -> Option<String> {
    NODE_WOLFNET_IPS.lock().ok().and_then(|m| m.get(address).cloned())
}

/// Build the URLs to try for an inter-node API call, in preference order:
/// 1. HTTPS on the main port (TLS — secure; outbound clients all use
///    `danger_accept_invalid_certs(true)` so self-signed peers work too)
/// 2. HTTP on the peer's WolfNet IP, internal port (encrypted at L3 by
///    the WolfNet overlay; only works if the peer is self-signed and
///    therefore still binds the second listener, AND we've seen its
///    WolfNet IP via a StatusReport)
/// 3. HTTP on the main address, main port (plain — last resort, only
///    succeeds against genuinely-HTTP-only peers, i.e. pre-v23.11
///    installs running with `--no-tls`)
///
/// v23.12 removed the `http://address:port+1` step. CA-signed-cert peers
/// no longer bind the second listener at all (Frigate clash avoidance);
/// HTTPS-with-cert-bypass on the main port reaches every TLS peer including
/// those still on a self-signed cert.
pub fn build_node_urls(address: &str, port: u16, path: &str) -> Vec<String> {
    // Bracket bare IPv6 literals — node addresses are stored bare; a raw
    // v6 literal in `host:port` makes the port colon ambiguous. v4 and
    // hostnames pass through unchanged. WolfNet IPs are v4 by design.
    let host = crate::netaddr::bracket_host(address);
    let mut urls = Vec::with_capacity(3);
    urls.push(format!("https://{}:{}{}", host, port, path));
    if let Some(wn) = lookup_node_wolfnet_ip(address) {
        urls.push(format!("http://{}:{}{}", wn, port + 1, path));
    }
    urls.push(format!("http://{}:{}{}", host, port, path));
    urls
}

/// Build ordered URLs to try for external (cross-cluster) communication.
/// All destination nodes run WolfStack (HTTPS 8553, HTTP 8554), so we try those ports
/// automatically — the user only needs to provide the hostname.
pub fn build_external_urls(target_url: &str, path: &str) -> Vec<String> {
    let trimmed = target_url.trim_end_matches('/');

    // Ensure we have a scheme — prepend https:// if missing
    let with_scheme = if trimmed.contains("://") {
        trimmed.to_string()
    } else {
        format!("https://{}", trimmed)
    };

    // Extract host from URL (scheme://host:port/path → host). A
    // bracketed IPv6 host ("[2001:db8::1]:8553") splits on the colon
    // AFTER the closing bracket. A bare IPv6 literal must NOT split at
    // all — its last group usually parses as a u16 ("::1" → port 1,
    // host ":"), which both mangles the host and slips it past the
    // SSRF guard below. Unbracketed-colon-in-head = bare v6 literal.
    let after_scheme = &with_scheme[with_scheme.find("://").unwrap() + 3..];
    let host_port = after_scheme.split('/').next().unwrap_or(after_scheme);
    let (host, user_port) = match host_port.rfind(':') {
        Some(pos) if !host_port[pos..].contains(']') => {
            let head = &host_port[..pos];
            if head.contains(':') && !head.ends_with(']') {
                (host_port, None)
            } else {
                let port_str = &host_port[pos + 1..];
                match port_str.parse::<u16>() {
                    Ok(port) => (head, Some(port)),
                    Err(_) => (host_port, None),
                }
            }
        }
        _ => (host_port, None),
    };

    // SSRF prevention: block loopback and link-local addresses
    if is_ssrf_blocked_address(host) {
        return Vec::new();
    }

    let mut urls = Vec::new();

    // If user specified a port, try their exact URL first
    if user_port.is_some() {
        urls.push(format!("{}{}", with_scheme, path));
    }

    // Always try WolfStack's main HTTPS port. The old code also tried
    // http://host:8554 (legacy inter-node), but v23.12 dropped the
    // second listener for CA-signed-cert peers — and HTTPS-with-cert-
    // bypass already reaches self-signed peers via the main port, so
    // the 8554 attempt was always redundant when the main port is
    // reachable. Cross-cluster operators wanting plain HTTP can still
    // pass an explicit `http://host:port` URL — that's why we try the
    // user-supplied URL first above.
    if user_port != Some(8553) {
        urls.push(format!("https://{}:8553{}", crate::netaddr::bracket_host(host), path));
    }

    urls
}

/// Progress state for PBS restore operations
