#[derive(Deserialize)]
pub struct UnblockRequest {
    pub ip: String,
    /// If true, also tell every peer to unblock. Defaults to true so
    /// the operator's "unblock my home IP" works fleet-wide.
    #[serde(default = "default_true_propagate")]
    pub propagate: bool,
}

fn default_true_propagate() -> bool { true }

/// POST /api/security/auth-unblock — operator-triggered IP unblock.
pub async fn security_auth_unblock(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<UnblockRequest>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let body = body.into_inner();
    state.login_limiter.unblock(&body.ip);
    if body.propagate {
        let cluster = state.cluster.clone();
        let secret = state.cluster_secret.clone();
        let ip = body.ip.clone();
        tokio::spawn(async move {
            propagate_kernel_unblock_to_peers(cluster, secret, ip).await;
        });
    }
    HttpResponse::Ok().json(serde_json::json!({ "ok": true, "ip": body.ip }))
}

pub async fn propagate_kernel_unblock_to_peers(
    cluster: std::sync::Arc<crate::agent::ClusterState>,
    secret: String,
    ip: String,
) {
    let nodes: Vec<crate::agent::Node> = {
        let n = cluster.nodes.read().unwrap();
        n.values()
            .filter(|p| p.id != cluster.self_id && p.node_type == "wolfstack")
            .cloned()
            .collect()
    };
    let client = match reqwest::Client::builder()
        .danger_accept_invalid_certs(true)
        .timeout(std::time::Duration::from_secs(8))
        .build()
    {
        Ok(c) => c,
        Err(_) => return,
    };
    let payload = serde_json::json!({ "ip": ip, "propagate": false });
    for node in nodes {
        let urls = build_node_urls(&node.address, node.port, "/api/security/auth-unblock-peer");
        let mut last_err = String::from("no attempts");
        let mut acked = false;
        for url in &urls {
            let r = client.post(url)
                .header("X-WolfStack-Secret", &secret)
                .json(&payload)
                .send().await;
            match r {
                Ok(resp) if resp.status().is_success() => { acked = true; break; }
                Ok(resp) => {
                    let status = resp.status();
                    let body = resp.text().await.unwrap_or_default();
                    last_err = format!("{} -> HTTP {}: {}", url, status, body.chars().take(200).collect::<String>());
                }
                Err(e) => { last_err = format!("{} -> transport: {}", url, e); }
            }
        }
        if !acked {
            tracing::error!(
                "kernel-unblock fanout to {} ({}) FAILED. Last error: {}",
                node.hostname, node.address, last_err
            );
        } else {
            tracing::info!("kernel-unblock fanout: {} ack'd unblock of {}", node.hostname, ip);
        }
    }
}

/// POST /api/security/auth-unblock-peer — receive a fleet-propagated
/// unblock. Cluster-secret only.
pub async fn security_auth_unblock_peer(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<UnblockRequest>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    state.login_limiter.unblock(&body.ip);
    HttpResponse::Ok().json(serde_json::json!({ "ok": true }))
}

/// Strip the trailing `:port` from a `peer_addr()` string. Actix
/// returns `1.2.3.4:56789` (or `[::1]:56789` for v6) — we want the
/// bare IP for the rate limiter so all connections from one client
/// share a bucket. Delegates to netaddr::strip_port, which also keeps
/// a bare (portless) IPv6 literal intact instead of eating its last
/// group as a "port".
fn strip_port(addr: &str) -> String {
    crate::netaddr::strip_port(addr).to_string()
}

/// GET /api/settings/login-disabled — check if direct login is disabled (no auth needed)
pub async fn login_disabled_status(state: web::Data<AppState>) -> HttpResponse {
    let disabled = {
        let nodes = state.cluster.nodes.read().unwrap();
        nodes.get(&state.cluster.self_id).map(|n| n.login_disabled).unwrap_or(false)
    };
    HttpResponse::Ok().json(serde_json::json!({ "login_disabled": disabled }))
}

/// POST /api/settings/site — set the operator-declared site tag on
/// this node. Called by the master node when an admin edits a remote
/// node's Site field (push path for immediate effect; gossip still
/// propagates the value if the push happens to miss). Empty string
/// clears the tag.
pub async fn set_site(req: HttpRequest, state: web::Data<AppState>, body: web::Json<serde_json::Value>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let site_raw = body.get("site").and_then(|v| v.as_str()).unwrap_or("").trim().to_string();
    // Cap at 64 chars so a malformed payload can't bloat the on-disk
    // file or the gossip payload. Operators use short labels in
    // practice ("home", "office-vlan10"); anything longer is a typo
    // or an abuse attempt.
    if site_raw.len() > 64 {
        return HttpResponse::BadRequest().json(serde_json::json!({
            "error": "site tag too long (max 64 chars)"
        }));
    }
    let new_site = if site_raw.is_empty() { None } else { Some(site_raw.clone()) };
    {
        let mut nodes = state.cluster.nodes.write().unwrap();
        if let Some(node) = nodes.get_mut(&state.cluster.self_id) {
            node.site = new_site.clone();
        }
    }
    crate::agent::ClusterState::save_self_site(&site_raw);
    HttpResponse::Ok().json(serde_json::json!({ "site": new_site }))
}

/// POST /api/settings/login-disabled — set login_disabled on this node (cluster-auth required)
pub async fn set_login_disabled(req: HttpRequest, state: web::Data<AppState>, body: web::Json<serde_json::Value>) -> HttpResponse {
    // Accept both cluster auth (from remote dashboard) and session auth (local admin)
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let disabled = body.get("login_disabled").and_then(|v| v.as_bool()).unwrap_or(false);
    {
        let mut nodes = state.cluster.nodes.write().unwrap();
        if let Some(node) = nodes.get_mut(&state.cluster.self_id) {
            node.login_disabled = disabled;
        }
    }
    // Persist to disk
    crate::agent::ClusterState::save_login_disabled_file(disabled);

    HttpResponse::Ok().json(serde_json::json!({ "login_disabled": disabled }))
}

/// POST /api/auth/logout — destroy session
pub async fn logout(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Some(token) = get_session_token(&req) {
        state.sessions.destroy(&token);
    }
    let mut cookie = Cookie::build("wolfstack_session", "")
        .path("/")
        // Match the login cookie's SameSite=Lax so the removal reliably
        // clears it on a top-level navigation (don't rely on the browser
        // default, which could tighten to Strict and strand the cookie).
        .same_site(actix_web::cookie::SameSite::Lax)
        .finish();
    cookie.make_removal();

    HttpResponse::Ok()
        .cookie(cookie)
        .json(serde_json::json!({ "success": true }))
}

/// GET /api/auth/check — check if session is valid
pub async fn auth_check(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    match require_auth(&req, &state) {
        Ok(username) => HttpResponse::Ok().json(serde_json::json!({
            "authenticated": true,
            "username": username
        })),
        Err(_) => HttpResponse::Ok().json(serde_json::json!({
            "authenticated": false
        })),
    }
}

// ─── Passkey / WebAuthn (additive — coexists with PAM/WolfStack login) ───

/// Derive (rp_id, origin) from the inbound request's Host header. Strips the
/// port for the RP ID; the origin keeps it. Returns an error if the host
/// header is missing or unparseable.
///
/// Reverse-proxy compatibility: when X-Forwarded-Proto is present we trust
/// it for the scheme (and X-Forwarded-Host for the hostname when set), so
/// a wolfstack behind nginx/Caddy/Traefik that terminates TLS reports
/// `https://...` to webauthn-rs even though wolfstack itself only sees a
/// plain HTTP connection. Without this, the browser presents
/// origin=https://example.com and we expect origin=http://example.com →
/// webauthn-rs rejects with an origin mismatch and the user gets a
/// "host header is incorrect for passkeys" failure.
fn passkey_rp_origin(req: &HttpRequest, state: &web::Data<AppState>) -> Result<(String, String), String> {
    let fwd_host  = req.headers().get("X-Forwarded-Host").and_then(|v| v.to_str().ok());
    let host      = req.headers().get("Host").and_then(|v| v.to_str().ok());
    let fwd_proto = req.headers().get("X-Forwarded-Proto").and_then(|v| v.to_str().ok());
    derive_passkey_rp_origin(host, fwd_host, fwd_proto, state.tls_enabled)
}

/// Pure function that derives (rp_id, origin) from raw header values.
/// Factored out of `passkey_rp_origin` so it's unit-testable without
/// constructing an HttpRequest + full AppState. Behaviour:
///
/// - Host comes from X-Forwarded-Host first (reverse proxy preserves original
///   client Host here), falling back to the Host header.
/// - Multi-hop proxies produce comma-separated values — take the first entry,
///   which is the original client-facing value.
/// - Scheme comes from X-Forwarded-Proto when present and valid (http|https),
///   otherwise from the local TLS state.
/// - rp_id is the host with the port stripped; origin keeps the port.
pub fn derive_passkey_rp_origin(
    host: Option<&str>,
    fwd_host: Option<&str>,
    fwd_proto: Option<&str>,
    tls_enabled: bool,
) -> Result<(String, String), String> {
    let host_hdr = fwd_host
        .filter(|s| !s.is_empty())
        .or(host)
        .ok_or_else(|| "Missing Host header".to_string())?;
    let host_hdr = host_hdr.split(',').next().unwrap_or("").trim();
    if host_hdr.is_empty() {
        return Err("Missing Host header".to_string());
    }

    let host_no_port = match host_hdr.rsplit_once(':') {
        Some((h, p)) if !h.is_empty() && p.chars().all(|c| c.is_ascii_digit()) => h,
        _ => host_hdr,
    };

    let scheme = fwd_proto
        .map(|s| s.split(',').next().unwrap_or("").trim())
        .filter(|s| *s == "http" || *s == "https")
        .map(|s| s.to_string())
        .unwrap_or_else(|| if tls_enabled { "https".into() } else { "http".into() });

    let origin = format!("{}://{}", scheme, host_hdr);
    Ok((host_no_port.to_string(), origin))
}

#[derive(Deserialize)]
pub struct PasskeyRegisterStartRequest {
    #[serde(default)]
    pub label: String,
}

/// POST /api/auth/passkey/register/start — issue a registration challenge for the
/// currently-logged-in user. Requires an existing session.
pub async fn passkey_register_start(req: HttpRequest, state: web::Data<AppState>, body: web::Json<PasskeyRegisterStartRequest>) -> HttpResponse {
    let username = match require_auth(&req, &state) { Ok(u) => u, Err(resp) => return resp };
    if username == "cluster-node" {
        return HttpResponse::Forbidden().json(serde_json::json!({ "error": "Inter-node calls cannot register passkeys" }));
    }
    let (rp_id, origin) = match passkey_rp_origin(&req, &state) {
        Ok(p) => p, Err(e) => return HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
    };
    let display_name = if body.label.is_empty() { username.as_str() } else { body.label.as_str() };
    let config = crate::auth::webauthn::WebAuthnConfig::load();
    match crate::auth::webauthn::start_registration(&config, &rp_id, &origin, &username, display_name) {
        Ok((challenge, ceremony_id)) => HttpResponse::Ok().json(serde_json::json!({
            "challenge": challenge,
            "ceremony_id": ceremony_id,
        })),
        Err(e) => HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
    }
}

#[derive(Deserialize)]
pub struct PasskeyRegisterFinishRequest {
    pub ceremony_id: String,
    #[serde(default)]
    pub label: String,
    pub response: serde_json::Value,
}

/// POST /api/auth/passkey/register/finish — verify the attestation and persist the credential.
pub async fn passkey_register_finish(req: HttpRequest, state: web::Data<AppState>, body: web::Json<PasskeyRegisterFinishRequest>) -> HttpResponse {
    let username = match require_auth(&req, &state) { Ok(u) => u, Err(resp) => return resp };
    if username == "cluster-node" {
        return HttpResponse::Forbidden().json(serde_json::json!({ "error": "Inter-node calls cannot register passkeys" }));
    }
    let (rp_id, origin) = match passkey_rp_origin(&req, &state) {
        Ok(p) => p, Err(e) => return HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
    };
    let label = if body.label.is_empty() { "Passkey".to_string() } else { body.label.clone() };
    let mut config = crate::auth::webauthn::WebAuthnConfig::load();
    match crate::auth::webauthn::finish_registration(&mut config, &rp_id, &origin, &body.ceremony_id, &username, &label, &body.response) {
        Ok(stored) => HttpResponse::Ok().json(serde_json::json!({
            "credential_id": stored.credential_id,
            "label": stored.label,
            "registered_at": stored.registered_at,
        })),
        Err(e) => HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
    }
}

/// GET /api/auth/passkey/available — anonymous lightweight probe used by the
/// login page to decide whether to render the "Sign in with passkey" button.
/// Returns `{available: bool}` without creating any ceremony state.
pub async fn passkey_available(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    let config = crate::auth::webauthn::WebAuthnConfig::load();
    if config.credentials.is_empty() {
        return HttpResponse::Ok().json(serde_json::json!({ "available": false }));
    }
    // Verify the request hostname can actually do WebAuthn — bare-IP
    // origins will fail at registration/auth time, so don't pretend
    // they can sign in.
    let hostname_ok = match passkey_rp_origin(&req, &state) {
        Ok((rp_id, _)) => rp_id.parse::<std::net::IpAddr>().is_err(),
        Err(_) => false,
    };
    HttpResponse::Ok().json(serde_json::json!({ "available": hostname_ok }))
}

/// POST /api/auth/passkey/login/start — issue a discoverable-credential challenge.
/// Anonymous endpoint — does NOT require a session.
pub async fn passkey_login_start(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    // If passkey login is unconfigured (no credentials registered) return 404
    // so the frontend can hide the "Sign in with passkey" button quickly.
    let config = crate::auth::webauthn::WebAuthnConfig::load();
    if config.credentials.is_empty() {
        return HttpResponse::NotFound().json(serde_json::json!({ "error": "No passkeys registered on this server" }));
    }
    // Check rate limit on this IP — same budget as the password login.
    // canonical_ip_str: see login() — dual-stack [::] reports mapped v4.
    let client_ip = crate::netaddr::canonical_ip_str(
        req.connection_info().peer_addr().unwrap_or("unknown")).into_owned();
    if state.login_limiter.is_locked_out(&client_ip) {
        return HttpResponse::TooManyRequests().json(serde_json::json!({
            "error": "Too many failed login attempts. Please try again later."
        }));
    }
    let (rp_id, origin) = match passkey_rp_origin(&req, &state) {
        Ok(p) => p, Err(e) => return HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
    };
    match crate::auth::webauthn::start_authentication(&rp_id, &origin) {
        Ok((challenge, ceremony_id)) => HttpResponse::Ok().json(serde_json::json!({
            "challenge": challenge,
            "ceremony_id": ceremony_id,
        })),
        Err(e) => HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
    }
}

#[derive(Deserialize)]
pub struct PasskeyLoginFinishRequest {
    pub ceremony_id: String,
    pub response: serde_json::Value,
}

/// POST /api/auth/passkey/login/finish — verify the assertion, create a session, set cookie.
/// Anonymous endpoint.
pub async fn passkey_login_finish(req: HttpRequest, state: web::Data<AppState>, body: web::Json<PasskeyLoginFinishRequest>) -> HttpResponse {
    // canonical_ip_str: see login() — dual-stack [::] reports mapped v4.
    let client_ip = crate::netaddr::canonical_ip_str(
        req.connection_info().peer_addr().unwrap_or("unknown")).into_owned();
    if state.login_limiter.is_locked_out(&client_ip) {
        return HttpResponse::TooManyRequests().json(serde_json::json!({
            "error": "Too many failed login attempts. Please try again later."
        }));
    }
    // Same direct-login-disabled check the password endpoint does.
    {
        let nodes = state.cluster.nodes.read().unwrap();
        if let Some(self_node) = nodes.get(&state.cluster.self_id) {
            if self_node.login_disabled {
                return HttpResponse::Forbidden().json(serde_json::json!({
                    "error": "Direct login is disabled on this server. Access it via the primary dashboard."
                }));
            }
        }
    }
    let (rp_id, origin) = match passkey_rp_origin(&req, &state) {
        Ok(p) => p, Err(e) => return HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
    };
    let mut config = crate::auth::webauthn::WebAuthnConfig::load();
    match crate::auth::webauthn::finish_authentication(&mut config, &rp_id, &origin, &body.ceremony_id, &body.response) {
        Ok(username) => {
            state.login_limiter.clear(&client_ip);
            let token = state.sessions.create_session(&username);
            let mut cookie = Cookie::build("wolfstack_session", &token)
                .path("/")
                .http_only(true)
                // Lax, not Strict: Strict withholds the session cookie on
                // top-level navigations/redirects, which broke login on
                // Microsoft Edge (stricter tracking-prevention than Chrome) —
                // users authenticated then immediately appeared logged out.
                // Lax still blocks cross-site POSTs (CSRF) for this same-origin SPA.
                .same_site(actix_web::cookie::SameSite::Lax)
                .max_age(actix_web::cookie::time::Duration::hours(8))
                .finish();
            if state.tls_enabled { cookie.set_secure(true); }
            HttpResponse::Ok()
                .cookie(cookie)
                .json(serde_json::json!({ "success": true, "username": username }))
        }
        Err(e) => {
            state.login_limiter.record_failure(&client_ip);
            HttpResponse::Unauthorized().json(serde_json::json!({ "success": false, "error": e }))
        }
    }
}

/// GET /api/auth/passkeys — list the current user's registered passkeys.
pub async fn passkey_list(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    let username = match require_auth(&req, &state) { Ok(u) => u, Err(resp) => return resp };
    if username == "cluster-node" {
        return HttpResponse::Forbidden().json(serde_json::json!({ "error": "Inter-node calls cannot list passkeys" }));
    }
    let config = crate::auth::webauthn::WebAuthnConfig::load();
    let creds = crate::auth::webauthn::list_credentials(&config, &username);
    let out: Vec<serde_json::Value> = creds.iter().map(|c| serde_json::json!({
        "credential_id": c.credential_id,
        "label": c.label,
        "registered_at": c.registered_at,
        "last_used_at": c.last_used_at,
    })).collect();
    HttpResponse::Ok().json(serde_json::json!({ "passkeys": out }))
}

/// DELETE /api/auth/passkeys/{id} — remove a passkey owned by the current user.
pub async fn passkey_delete(req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>) -> HttpResponse {
    let username = match require_auth(&req, &state) { Ok(u) => u, Err(resp) => return resp };
    if username == "cluster-node" {
        return HttpResponse::Forbidden().json(serde_json::json!({ "error": "Inter-node calls cannot delete passkeys" }));
    }
    let credential_id = path.into_inner();
    let mut config = crate::auth::webauthn::WebAuthnConfig::load();
    // Ownership check — only the owning user can delete their own passkeys.
    let owns = config.credentials.iter().any(|c| c.credential_id == credential_id && c.username == username);
    if !owns {
        return HttpResponse::NotFound().json(serde_json::json!({ "error": "Passkey not found" }));
    }
    match crate::auth::webauthn::remove_credential(&mut config, &credential_id) {
        Ok(true) => HttpResponse::Ok().json(serde_json::json!({ "removed": true })),
        Ok(false) => HttpResponse::NotFound().json(serde_json::json!({ "error": "Passkey not found" })),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": e })),
    }
}

// ─── Threat Intelligence (WolfRouter integration) ───

/// Helper: collect the cluster's known node addresses for the safe-filter.
/// Filters out the unspecified address (0.0.0.0 / ::) — that's the
/// "listen on all interfaces" sentinel some nodes report instead of a
/// real public address; passing it to threat-intel as an exempt creates
/// no value and confuses the self-blacklist scan.

/// Helper: best-effort extraction of the requesting client's IP. Used as a
/// transient exemption so an admin can't accidentally lock themselves out
/// of their own dashboard if their public IP appears on a feed.
fn ti_request_client_ip(req: &HttpRequest) -> Vec<String> {
    // ConnectionInfo::peer_addr() is already the bare IP — actix builds
    // it as `req.peer_addr.map(|addr| addr.ip().to_string())`
    // (actix-web-4.13.0/src/info.rs:146). The old rsplit_once(':') here
    // assumed "ip:port" and silently truncated IPv6 peers to
    // "2001:db8:"-style garbage, so the safe-filter compare never
    // matched a v6 client. canonical_ip_str: a dual-stack [::] listener
    // reports v4 admins as ::ffff:a.b.c.d, which would miss the v4
    // safe-filter entry.
    let ip = crate::netaddr::canonical_ip_str(
        req.connection_info().peer_addr().unwrap_or("")).into_owned();
    if ip.is_empty() { Vec::new() } else { vec![ip] }
}

/// Per-peer outcome for a cluster-wide threat-intel operation (config
/// propagation, ipset install, pause/resume). Surfaced back to the
/// frontend so the operator sees exactly which nodes diverged from the
/// requested state instead of trusting a fire-and-forget warning log.
#[derive(serde::Serialize, Clone, Debug)]
pub struct TiPeerOpResult {
    pub hostname: String,
    pub address: String,
    pub ok: bool,
    pub error: Option<String>,
}

/// Normalise a cluster name for comparison. Nodes without an explicit
/// `cluster_name` (legacy single-cluster installs, freshly-onboarded
/// nodes) fall under the "WolfStack" default. Same normalisation rule
/// the cluster-status endpoint uses so the peer-filter agrees with
/// what the operator sees in the cluster status table.
fn ti_normalize_cluster(name: &str) -> String {
    if name.is_empty() { "WolfStack".to_string() } else { name.to_string() }
}

/// Extract the target cluster name from `?cluster=` on a threat-intel
/// request. Defaults to the bastion's own cluster_name when missing —
/// preserves single-cluster behaviour for installs that haven't named
/// their cluster yet.
fn ti_target_cluster(req: &HttpRequest, state: &web::Data<AppState>) -> String {
    if let Some(q) = req.uri().query() {
        for pair in q.split('&') {
            if let Some(rest) = pair.strip_prefix("cluster=") {
                if let Ok(decoded) = urlencoding::decode(rest) {
                    let val = decoded.into_owned();
                    if !val.is_empty() {
                        return val;
                    }
                }
            }
        }
    }
    state.cluster.get_self_cluster_name()
}

/// True when `target` matches the bastion's own cluster — used by every
/// threat-intel handler to decide whether to (a) load/save the default
/// config file vs a per-cluster file, and (b) actually apply kernel
/// rules locally vs only update on-disk + propagated state. The
/// normalisation rule must match `ti_normalize_cluster` so cluster
/// identity is consistent across endpoints.
fn ti_is_local_cluster(state: &web::Data<AppState>, target: &str) -> bool {
    ti_normalize_cluster(target) == ti_normalize_cluster(state.cluster.get_self_cluster_name().as_str())
}

/// On-disk slug for a cluster. Empty for the bastion's own cluster
/// (uses legacy `threat-intel.json` for backward compat); otherwise
/// the normalised cluster name. This is what the threat_intel module
/// expects as its `cluster` parameter — keeping the mapping in one
/// place stops the handlers and the propagation code from drifting.
fn ti_storage_cluster(state: &web::Data<AppState>, target: &str) -> String {
    if ti_is_local_cluster(state, target) {
        String::new()
    } else {
        ti_normalize_cluster(target)
    }
}

/// Fan out an `ipset` install request to every online WolfStack peer in
/// parallel and await the results. Used when the local admin flips
/// Threat Intel to enforce mode — peers need ipset present before they
/// can apply kernel rules. Per-peer timeout is 90 seconds (apt/dnf can
/// genuinely take that long); each peer runs concurrently so total wait
/// is bounded by the slowest peer, not the sum.
///
/// Skips: this node, offline nodes, non-wolfstack nodes (Proxmox-only
/// entries can't install packages).
///
/// Returns one [`TiPeerOpResult`] per attempted peer. The caller — the
/// HTTP handler that triggered the enforcement change — includes these
/// in its response so the UI can name the failing nodes.
async fn ti_install_ipset_on_peers(state: &web::Data<AppState>, target_cluster: &str) -> Vec<TiPeerOpResult> {
    let nodes = state.cluster.get_all_nodes();
    let secret = state.cluster_secret.clone();
    let self_id = state.cluster.self_id.clone();
    // Threat Intel is per-cluster. Fan out to peers in the TARGET
    // cluster (the one the operator is modifying), not the bastion's
    // own cluster — without this scope, the bastion would push ipset
    // installs to every cluster it manages, including ones whose
    // operators haven't enabled threat-intel.
    let target = ti_normalize_cluster(target_cluster);
    let peers: Vec<(String, String, u16)> = nodes.iter()
        .filter(|n| !n.is_self && n.id != self_id && n.online && n.node_type == "wolfstack"
                    && ti_normalize_cluster(n.cluster_name.as_deref().unwrap_or("")) == target)
        .map(|n| (n.hostname.clone(), n.address.clone(), n.port))
        .collect();
    if peers.is_empty() { return Vec::new(); }

    let client = &*API_HTTP_CLIENT;
    let body = serde_json::json!({ "package": "ipset" });
    let mut futures = Vec::with_capacity(peers.len());
    for (hostname, address, port) in peers {
        let secret = secret.clone();
        let client = client.clone();
        let body = body.clone();
        futures.push(async move {
            let urls = build_node_urls(&address, port, "/api/system/install-package");
            for url in &urls {
                match client.post(url)
                    .timeout(std::time::Duration::from_secs(90))
                    .header("X-WolfStack-Secret", &secret)
                    .json(&body)
                    .send()
                    .await
                {
                    Ok(resp) if resp.status().is_success() => {
                        match resp.json::<serde_json::Value>().await {
                            Ok(data) => {
                                let ok = data.get("success").and_then(|v| v.as_bool()).unwrap_or(false);
                                let msg = data.get("message").and_then(|v| v.as_str())
                                    .or_else(|| data.get("error").and_then(|v| v.as_str()))
                                    .unwrap_or("(no message)").to_string();
                                if ok {
                                    tracing::info!("threat-intel: ipset installed on peer '{}' ({}): {}", hostname, address, msg);
                                    return TiPeerOpResult { hostname, address, ok: true, error: None };
                                }
                                tracing::warn!("threat-intel: ipset install on peer '{}' ({}) reported failure: {}", hostname, address, msg);
                                return TiPeerOpResult { hostname, address, ok: false, error: Some(msg) };
                            }
                            Err(e) => {
                                return TiPeerOpResult {
                                    hostname, address, ok: false,
                                    error: Some(format!("install response unparseable: {}", e)),
                                };
                            }
                        }
                    }
                    Ok(resp) => {
                        let status = resp.status();
                        let _ = resp.bytes().await;
                        tracing::warn!("threat-intel: ipset install on peer '{}' ({}) returned HTTP {}", hostname, address, status);
                        return TiPeerOpResult {
                            hostname, address, ok: false,
                            error: Some(format!("HTTP {}", status)),
                        };
                    }
                    Err(_) => continue,
                }
            }
            tracing::warn!("threat-intel: could not reach peer '{}' ({}) for ipset install", hostname, address);
            TiPeerOpResult {
                hostname, address, ok: false,
                error: Some("unreachable".into()),
            }
        });
    }
    futures::future::join_all(futures).await
}

/// Push the local Threat Intel config to every online WolfStack peer
/// in parallel and await the results. Peers receive the unmasked config
/// (real API keys, not "***") so their own scheduler can actually fetch
/// feeds. Per-peer timeout 30s; nodes run concurrently so the call
/// completes as soon as the slowest peer responds.
///
/// Cycle-breaker: peers that receive this call have caller == "cluster-node"
/// in their PATCH handler, which skips the re-propagation step.
///
/// Returns one [`TiPeerOpResult`] per peer attempted. The caller surfaces
/// these so the UI can name nodes that didn't apply the change — without
/// this, a peer in a divergent state was invisible to the operator.
async fn ti_propagate_config_to_peers(state: &web::Data<AppState>, target_cluster: &str) -> Vec<TiPeerOpResult> {
    let nodes = state.cluster.get_all_nodes();
    let secret = state.cluster_secret.clone();
    let self_id = state.cluster.self_id.clone();
    // Fan out to peers in the TARGET cluster only — see comment on
    // ti_install_ipset_on_peers. Each peer in the target cluster
    // stores the config as its own (default-slot) file because, from
    // its own perspective, the target cluster IS its cluster.
    let target = ti_normalize_cluster(target_cluster);
    let peers: Vec<(String, String, u16)> = nodes.iter()
        .filter(|n| !n.is_self && n.id != self_id && n.online && n.node_type == "wolfstack"
                    && ti_normalize_cluster(n.cluster_name.as_deref().unwrap_or("")) == target)
        .map(|n| (n.hostname.clone(), n.address.clone(), n.port))
        .collect();
    if peers.is_empty() { return Vec::new(); }

    // Read the unmasked on-disk config for the target cluster and
    // serialise the full struct. The receiving peer's PATCH handler
    // will use its own ProviderConfig sentinel logic — including a
    // real key value (not "***") replaces the on-disk key.
    let cfg = crate::threat_intel::ThreatIntelConfig::load_for(&ti_storage_cluster(state, target_cluster));
    let payload = serde_json::json!({
        "enabled": cfg.enabled,
        "dry_run": cfg.dry_run,
        "paused": cfg.paused,
        "refresh_hours": cfg.refresh_hours,
        "providers": cfg.providers,
        "allowlist": cfg.allowlist,
    });

    let client = &*API_HTTP_CLIENT;
    let mut futures = Vec::with_capacity(peers.len());
    for (hostname, address, port) in peers {
        let secret = secret.clone();
        let client = client.clone();
        let payload = payload.clone();
        futures.push(async move {
            let urls = build_node_urls(&address, port, "/api/threat-intel/config");
            for url in &urls {
                match client.patch(url)
                    .timeout(std::time::Duration::from_secs(30))
                    .header("X-WolfStack-Secret", &secret)
                    .json(&payload)
                    .send()
                    .await
                {
                    Ok(resp) if resp.status().is_success() => {
                        let _ = resp.bytes().await;
                        tracing::info!("threat-intel: config propagated to peer '{}' ({})", hostname, address);
                        return TiPeerOpResult { hostname, address, ok: true, error: None };
                    }
                    Ok(resp) => {
                        let status = resp.status();
                        let body = resp.text().await.unwrap_or_default();
                        // Try to extract a structured error from the JSON body.
                        let err_msg = serde_json::from_str::<serde_json::Value>(&body)
                            .ok()
                            .and_then(|v| v.get("error").and_then(|e| e.as_str()).map(|s| s.to_string()))
                            .unwrap_or_else(|| format!("HTTP {}", status));
                        tracing::warn!("threat-intel: config push to peer '{}' ({}) failed: {}", hostname, address, err_msg);
                        return TiPeerOpResult {
                            hostname, address, ok: false,
                            error: Some(err_msg),
                        };
                    }
                    Err(_) => continue,
                }
            }
            tracing::warn!("threat-intel: could not reach peer '{}' ({}) for config propagation", hostname, address);
            TiPeerOpResult {
                hostname, address, ok: false,
                error: Some("unreachable".into()),
            }
        });
    }
    futures::future::join_all(futures).await
}

/// Mask API keys before returning a config to the frontend. Empty fields
/// stay empty; non-empty fields become "***" so the UI knows a key is
/// configured without seeing the value.
fn ti_mask_keys(mut cfg: crate::threat_intel::ThreatIntelConfig) -> crate::threat_intel::ThreatIntelConfig {
    for (_, p) in cfg.providers.iter_mut() {
        if !p.api_key.is_empty() {
            p.api_key = "***".to_string();
        }
    }
    cfg
}

/// GET /api/threat-intel/config — return the persisted config (API keys masked).
/// `?cluster=NAME` selects which cluster's config to return; default is
/// the bastion's own cluster. Peers (cluster-node auth) always read
/// their own config slot.
pub async fn threat_intel_get_config(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    let caller = match require_auth(&req, &state) { Ok(u) => u, Err(resp) => return resp };
    let from_peer = caller == "cluster-node";
    let storage_slug = if from_peer {
        String::new()
    } else {
        let target = ti_target_cluster(&req, &state);
        ti_storage_cluster(&state, &target)
    };
    let cfg = crate::threat_intel::ThreatIntelConfig::load_for(&storage_slug);
    HttpResponse::Ok().json(ti_mask_keys(cfg))
}

#[derive(Deserialize)]
pub struct ThreatIntelPatchRequest {
    #[serde(default)] pub enabled: Option<bool>,
    #[serde(default)] pub dry_run: Option<bool>,
    #[serde(default)] pub paused: Option<bool>,
    #[serde(default)] pub refresh_hours: Option<u64>,
    #[serde(default)] pub providers: Option<std::collections::HashMap<String, crate::threat_intel::ProviderConfig>>,
    #[serde(default)] pub allowlist: Option<Vec<String>>,
}

/// PATCH /api/threat-intel/config — partial update. If the enabled / dry_run /
/// paused triplet changes, runs `apply_state_change()` to make the kernel
/// state catch up.
///
/// API key sentinel: a provider value of `"***"` means "don't change",
/// preserving the existing on-disk key. Anything else (including empty
/// string to clear) is used verbatim.
pub async fn threat_intel_patch_config(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<ThreatIntelPatchRequest>,
) -> HttpResponse {
    let caller = match require_auth(&req, &state) { Ok(u) => u, Err(resp) => return resp };
    // Cycle-breaker: when a peer receives a propagated config push, the
    // caller is "cluster-node" (X-WolfStack-Secret auth). Don't re-propagate
    // back out — the originating bastion is already fanning to every node.
    // Peers always treat the propagated config as THEIR OWN cluster's
    // config (cluster slug = "") regardless of any ?cluster= the bastion
    // tacked on, since from the peer's perspective the target IS their
    // cluster. Operator-driven calls use the requested target cluster.
    let from_peer = caller == "cluster-node";
    let target_cluster = ti_target_cluster(&req, &state);
    let storage_slug = if from_peer {
        String::new()
    } else {
        ti_storage_cluster(&state, &target_cluster)
    };
    let is_local_kernel = from_peer || ti_is_local_cluster(&state, &target_cluster);

    let mut cfg = crate::threat_intel::ThreatIntelConfig::load_for(&storage_slug);
    let prev_enforcement = crate::threat_intel::enforcement_active(&cfg);

    if let Some(v) = body.enabled { cfg.enabled = v; }
    if let Some(v) = body.dry_run { cfg.dry_run = v; }
    if let Some(v) = body.paused { cfg.paused = v; }
    if let Some(v) = body.refresh_hours {
        // Clamp at the API boundary too so the saved config matches what the
        // scheduler will actually use.
        cfg.refresh_hours = v.clamp(1, 168);
    }
    if let Some(allowlist) = &body.allowlist { cfg.allowlist = allowlist.clone(); }
    if let Some(providers) = &body.providers {
        for (id, incoming) in providers.iter() {
            let entry = cfg.providers.entry(id.clone()).or_insert_with(|| crate::threat_intel::ProviderConfig {
                enabled: false, api_key: String::new(), url_override: String::new(),
            });
            entry.enabled = incoming.enabled;
            // Sentinel "***" means "don't change". Anything else replaces.
            if incoming.api_key != "***" {
                entry.api_key = incoming.api_key.clone();
            }
            entry.url_override = incoming.url_override.clone();
        }
    }

    if let Err(e) = cfg.save_for(&storage_slug) {
        return HttpResponse::InternalServerError().json(serde_json::json!({ "error": e }));
    }

    let new_enforcement = crate::threat_intel::enforcement_active(&cfg);
    let mut apply_error: Option<String> = None;
    let mut ipset_install_results: Vec<TiPeerOpResult> = Vec::new();
    if new_enforcement != prev_enforcement {
        // The kernel state needs to catch up. Run on a blocking thread —
        // apply_state_change_for shells out to ipset/iptables-restore
        // (only when is_local_kernel; otherwise it just refreshes the
        // cached `applied` flag for the target cluster).
        let slug_for_apply = storage_slug.clone();
        match tokio::task::spawn_blocking(move || crate::threat_intel::apply_state_change_for(&slug_for_apply, is_local_kernel)).await {
            Ok(Ok(())) => {
                // Enforcement just activated for the target cluster.
                // Fan out an ipset install to peers in THAT cluster so
                // they can apply kernel rules themselves.
                if new_enforcement && !from_peer {
                    ipset_install_results = ti_install_ipset_on_peers(&state, &target_cluster).await;
                }
            }
            Ok(Err(e)) => apply_error = Some(e),
            Err(e) => apply_error = Some(format!("apply task panicked: {}", e)),
        }
        // If the apply failed, roll the config back so on-disk state matches kernel state.
        if apply_error.is_some() {
            let mut rolled = crate::threat_intel::ThreatIntelConfig::load_for(&storage_slug);
            rolled.enabled = false;
            rolled.dry_run = true;
            rolled.paused = false;
            let _ = rolled.save_for(&storage_slug);
        }
    }

    if let Some(e) = apply_error {
        return HttpResponse::BadRequest().json(serde_json::json!({
            "error": format!("Config saved, but enforcement could not be activated: {}. Configuration was rolled back to a safe state.", e),
        }));
    }

    // Cluster-wide propagation. Peers process the same PATCH (with
    // caller=cluster-node) which short-circuits their own re-propagation
    // so we won't loop. Awaited so the response can name peers that
    // failed to apply the change — see comment on ti_propagate_config_to_peers.
    let mut propagation_results: Vec<TiPeerOpResult> = Vec::new();
    if !from_peer {
        propagation_results = ti_propagate_config_to_peers(&state, &target_cluster).await;
    }

    HttpResponse::Ok().json(serde_json::json!({
        "config": ti_mask_keys(crate::threat_intel::ThreatIntelConfig::load_for(&storage_slug)),
        "peers": propagation_results,
        "ipset_install": ipset_install_results,
    }))
}

/// POST /api/threat-intel/refresh — trigger an immediate refresh.
/// `?cluster=NAME` selects the cluster whose feeds to refresh; default
/// is the bastion's own cluster.
pub async fn threat_intel_refresh(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let target = ti_target_cluster(&req, &state);
    let storage_slug = ti_storage_cluster(&state, &target);
    let is_local_kernel = ti_is_local_cluster(&state, &target);
    // Only exempt cluster_node_ips from peers in the TARGET cluster —
    // unrelated clusters' IPs shouldn't get a free pass.
    let target_norm = ti_normalize_cluster(&target);
    let cluster_ips: Vec<String> = state.cluster.get_all_nodes().iter()
        .filter(|n| ti_normalize_cluster(n.cluster_name.as_deref().unwrap_or("")) == target_norm)
        .map(|n| n.address.clone())
        .filter(|a| match a.parse::<std::net::IpAddr>() {
            Ok(ip) => !ip.is_unspecified(),
            Err(_) => false,
        })
        .collect();
    let admin_ip = ti_request_client_ip(&req);
    let new_state = crate::threat_intel::refresh_all_for(&storage_slug, cluster_ips, admin_ip, is_local_kernel).await;
    HttpResponse::Ok().json(new_state)
}

/// POST /api/threat-intel/pause — emergency-off. Drops the kernel rule
/// immediately while preserving config + ipset state for a one-click
/// resume. Cluster-scoped: `?cluster=NAME` pauses just that cluster.
pub async fn threat_intel_pause(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    let caller = match require_auth(&req, &state) { Ok(u) => u, Err(resp) => return resp };
    let from_peer = caller == "cluster-node";
    let target = ti_target_cluster(&req, &state);
    let storage_slug = if from_peer { String::new() } else { ti_storage_cluster(&state, &target) };
    let is_local_kernel = from_peer || ti_is_local_cluster(&state, &target);

    let mut cfg = crate::threat_intel::ThreatIntelConfig::load_for(&storage_slug);
    if cfg.paused {
        return HttpResponse::Ok().json(serde_json::json!({ "paused": true, "no_op": true, "peers": [] }));
    }
    cfg.paused = true;
    if let Err(e) = cfg.save_for(&storage_slug) {
        return HttpResponse::InternalServerError().json(serde_json::json!({ "error": e }));
    }
    let slug_for_apply = storage_slug.clone();
    match tokio::task::spawn_blocking(move || crate::threat_intel::apply_state_change_for(&slug_for_apply, is_local_kernel)).await {
        Ok(Ok(())) => {
            // Pause is the operator's "emergency off" for THIS cluster.
            // Propagate to peers in the target cluster only — pausing
            // cluster A's view shouldn't take cluster B offline.
            let mut peers: Vec<TiPeerOpResult> = Vec::new();
            if !from_peer { peers = ti_propagate_config_to_peers(&state, &target).await; }
            HttpResponse::Ok().json(serde_json::json!({ "paused": true, "peers": peers }))
        }
        Ok(Err(e)) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": e })),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": format!("apply task panicked: {}", e) })),
    }
}

/// POST /api/threat-intel/resume — undo a pause. Cluster-scoped.
pub async fn threat_intel_resume(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    let caller = match require_auth(&req, &state) { Ok(u) => u, Err(resp) => return resp };
    let from_peer = caller == "cluster-node";
    let target = ti_target_cluster(&req, &state);
    let storage_slug = if from_peer { String::new() } else { ti_storage_cluster(&state, &target) };
    let is_local_kernel = from_peer || ti_is_local_cluster(&state, &target);

    let mut cfg = crate::threat_intel::ThreatIntelConfig::load_for(&storage_slug);
    if !cfg.paused {
        return HttpResponse::Ok().json(serde_json::json!({ "paused": false, "no_op": true, "peers": [], "ipset_install": [] }));
    }
    cfg.paused = false;
    if let Err(e) = cfg.save_for(&storage_slug) {
        return HttpResponse::InternalServerError().json(serde_json::json!({ "error": e }));
    }
    let slug_for_apply = storage_slug.clone();
    match tokio::task::spawn_blocking(move || crate::threat_intel::apply_state_change_for(&slug_for_apply, is_local_kernel)).await {
        Ok(Ok(())) => {
            // If unpausing actually re-activated enforcement (the common
            // case — pause was the only thing turning it off), make sure
            // peers in the target cluster have ipset and the same config.
            let mut ipset_install: Vec<TiPeerOpResult> = Vec::new();
            let mut peers: Vec<TiPeerOpResult> = Vec::new();
            if !from_peer
                && crate::threat_intel::enforcement_active(&crate::threat_intel::ThreatIntelConfig::load_for(&storage_slug))
            {
                ipset_install = ti_install_ipset_on_peers(&state, &target).await;
                peers = ti_propagate_config_to_peers(&state, &target).await;
            }
            HttpResponse::Ok().json(serde_json::json!({
                "paused": false,
                "peers": peers,
                "ipset_install": ipset_install,
            }))
        }
        Ok(Err(e)) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": e })),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": format!("apply task panicked: {}", e) })),
    }
}

/// GET /api/threat-intel/status — current state for the UI: per-provider
/// fetch status, total blocklist size, applied flag, sample of recently
/// added IPs (first 50 of each family — the UI uses these for "preview"
/// rendering without shipping 200k entries to the browser).
pub async fn threat_intel_status(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    let caller = match require_auth(&req, &state) { Ok(u) => u, Err(resp) => return resp };
    let from_peer = caller == "cluster-node";
    let storage_slug = if from_peer {
        String::new()
    } else {
        let target = ti_target_cluster(&req, &state);
        ti_storage_cluster(&state, &target)
    };
    let snapshot = crate::threat_intel::snapshot_cache_for(&storage_slug);
    let cfg = crate::threat_intel::ThreatIntelConfig::load_for(&storage_slug);

    let sample_v4: Vec<String> = snapshot.blocklist_v4.iter().take(50).cloned().collect();
    let sample_v6: Vec<String> = snapshot.blocklist_v6.iter().take(50).cloned().collect();

    // Annotate self-blacklisted entries with hostnames for the UI banner.
    // Mapping IP → hostname is best-effort: we look in the cluster node
    // list. If the mapping fails (IP not in cluster, race during node
    // removal), the UI just shows "(unknown)" — non-blocking.
    //
    // Filter unspecified addresses (0.0.0.0 / ::) at read time too —
    // covers the in-memory cache when it was populated from a state file
    // written by an older release before the upstream filter existed.
    let nodes = state.cluster.get_all_nodes();
    let self_blacklisted: Vec<serde_json::Value> = snapshot.self_blacklisted.iter()
        .filter(|(ip, _)| {
            match ip.parse::<std::net::IpAddr>() {
                Ok(p) => !p.is_unspecified(),
                Err(_) => false,
            }
        })
        .map(|(ip, providers)| {
            let hostname = nodes.iter()
                .find(|n| n.address == *ip)
                .map(|n| n.hostname.clone())
                .unwrap_or_default();
            serde_json::json!({
                "ip": ip,
                "hostname": hostname,
                "listed_by": providers,
            })
        }).collect();

    HttpResponse::Ok().json(serde_json::json!({
        "enabled": cfg.enabled,
        "dry_run": cfg.dry_run,
        "paused": cfg.paused,
        "enforcement_active": crate::threat_intel::enforcement_active(&cfg),
        "applied": snapshot.applied,
        "last_refresh_secs": snapshot.last_refresh_secs,
        "blocklist_size": snapshot.blocklist_size,
        "blocklist_v4_count": snapshot.blocklist_v4.len(),
        "blocklist_v6_count": snapshot.blocklist_v6.len(),
        "sample_v4": sample_v4,
        "sample_v6": sample_v6,
        "providers": snapshot.providers,
        "self_blacklisted": self_blacklisted,
        "ipset_available": crate::threat_intel::ipset::ipset_available(),
        "max_blocklist_size": crate::threat_intel::MAX_BLOCKLIST_SIZE,
    }))
}

/// GET /api/threat-intel/cluster-status — aggregate Threat Intel status
/// across every WolfStack node in the cluster, so the bastion's UI can
/// show "node X is enforcing 12k entries, last refresh 5min ago" for
/// every peer at once instead of just the local node.
///
/// Self status comes from in-memory cache (cheap). Online peers are
/// queried in parallel via the inter-node HTTP channel with a 4-second
/// timeout each — slow peers don't block the response. Offline /
/// non-WolfStack nodes are listed with status: null and a reason.
pub async fn threat_intel_cluster_status(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }

    // WolfRouter (and its Threat Intel tab) is per-cluster — a bastion
    // managing 5 clusters across 14 servers should NOT see every cluster's
    // peers lumped into every cluster view. Honour the same `?cluster=NAME`
    // filter the topology endpoint uses; nameless nodes normalise to
    // "WolfStack". Caveat (intentional, surfaced via the UI): the actual
    // ThreatIntelConfig is one global file at /etc/wolfstack/threat-intel.json
    // — propagation is cluster-wide. Adam Cogswell 2026-04-29: noticed
    // the status panel was showing all 14 servers regardless of which
    // cluster's WolfRouter view was open.
    let cluster_filter = req.uri().query()
        .and_then(|q| {
            for pair in q.split('&') {
                if let Some(rest) = pair.strip_prefix("cluster=") {
                    return urlencoding::decode(rest).ok().map(|s| s.into_owned());
                }
            }
            None
        });
    let normalize = |n: Option<&str>| -> String {
        match n {
            Some(s) if !s.is_empty() => s.to_string(),
            _ => "WolfStack".into(),
        }
    };
    let self_cluster_raw = state.cluster.get_self_cluster_name();
    let self_cluster_norm = normalize(
        if self_cluster_raw.is_empty() { None } else { Some(self_cluster_raw.as_str()) }
    );
    let include_self = match &cluster_filter {
        Some(want) => &self_cluster_norm == want,
        None => true,
    };

    let all_nodes = state.cluster.get_all_nodes();
    let nodes: Vec<_> = all_nodes.into_iter()
        .filter(|n| {
            if n.is_self || n.id == state.cluster.self_id {
                include_self
            } else {
                match &cluster_filter {
                    Some(want) => &normalize(n.cluster_name.as_deref()) == want,
                    None => true,
                }
            }
        })
        .collect();
    let secret = state.cluster_secret.clone();
    let self_id = state.cluster.self_id.clone();

    // Build the local node's summary up front from the in-memory cache.
    // Cheap; doesn't do any HTTP. Same shape as the per-peer fetch result
    // so the aggregator stays uniform.
    let local_summary = {
        let cfg = crate::threat_intel::ThreatIntelConfig::load();
        let snapshot = crate::threat_intel::snapshot_cache();
        serde_json::json!({
            "enabled": cfg.enabled,
            "dry_run": cfg.dry_run,
            "paused": cfg.paused,
            "enforcement_active": crate::threat_intel::enforcement_active(&cfg),
            "applied": snapshot.applied,
            "last_refresh_secs": snapshot.last_refresh_secs,
            "blocklist_size": snapshot.blocklist_size,
            "blocklist_v4_count": snapshot.blocklist_v4.len(),
            "blocklist_v6_count": snapshot.blocklist_v6.len(),
            "providers": snapshot.providers,
            "ipset_available": crate::threat_intel::ipset::ipset_available(),
        })
    };

    // Fetch peer statuses concurrently. Each fetch has its own short
    // timeout; one slow peer doesn't drag the whole aggregation.
    let client = &*API_HTTP_CLIENT;
    let mut futures: Vec<std::pin::Pin<Box<dyn std::future::Future<Output = serde_json::Value> + Send>>> = Vec::new();
    for node in nodes.iter() {
        if node.is_self || node.id == self_id {
            // Local entry — emit synchronously.
            let entry = serde_json::json!({
                "id": node.id,
                "hostname": node.hostname,
                "address": node.address,
                "is_self": true,
                "online": true,
                "reachable": true,
                "status": local_summary.clone(),
                "error": serde_json::Value::Null,
            });
            futures.push(Box::pin(async move { entry }));
            continue;
        }
        if !node.online {
            let entry = serde_json::json!({
                "id": node.id, "hostname": node.hostname, "address": node.address,
                "is_self": false, "online": false, "reachable": false,
                "status": serde_json::Value::Null,
                "error": "Node is offline",
            });
            futures.push(Box::pin(async move { entry }));
            continue;
        }
        if node.node_type != "wolfstack" {
            let entry = serde_json::json!({
                "id": node.id, "hostname": node.hostname, "address": node.address,
                "is_self": false, "online": node.online, "reachable": false,
                "status": serde_json::Value::Null,
                "error": format!("Node type '{}' does not run threat-intel", node.node_type),
            });
            futures.push(Box::pin(async move { entry }));
            continue;
        }
        // Online wolfstack peer — fetch over inter-node.
        let id = node.id.clone();
        let hostname = node.hostname.clone();
        let address = node.address.clone();
        let port = node.port;
        let secret = secret.clone();
        let client = client.clone();
        futures.push(Box::pin(async move {
            let urls = build_node_urls(&address, port, "/api/threat-intel/status");
            for url in &urls {
                match client.get(url)
                    .timeout(std::time::Duration::from_secs(4))
                    .header("X-WolfStack-Secret", &secret)
                    .send().await
                {
                    Ok(resp) if resp.status().is_success() => {
                        if let Ok(body) = resp.json::<serde_json::Value>().await {
                            return serde_json::json!({
                                "id": id, "hostname": hostname, "address": address,
                                "is_self": false, "online": true, "reachable": true,
                                "status": body, "error": serde_json::Value::Null,
                            });
                        }
                    }
                    Ok(resp) => {
                        let code = resp.status();
                        let _ = resp.bytes().await;
                        return serde_json::json!({
                            "id": id, "hostname": hostname, "address": address,
                            "is_self": false, "online": true, "reachable": false,
                            "status": serde_json::Value::Null,
                            "error": format!("Peer returned HTTP {}", code),
                        });
                    }
                    Err(_) => continue,
                }
            }
            serde_json::json!({
                "id": id, "hostname": hostname, "address": address,
                "is_self": false, "online": true, "reachable": false,
                "status": serde_json::Value::Null,
                "error": "Could not reach peer (timeout / network)",
            })
        }));
    }

    let results = futures::future::join_all(futures).await;
    HttpResponse::Ok().json(serde_json::json!({ "nodes": results }))
}

/// GET /api/threat-intel/lookup/{ip} — is this IP currently blocked, and which feed CIDRs match?
/// `?cluster=NAME` picks which cluster's blocklist to check against;
/// default is the bastion's own.
pub async fn threat_intel_lookup(req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>) -> HttpResponse {
    let caller = match require_auth(&req, &state) { Ok(u) => u, Err(resp) => return resp };
    let from_peer = caller == "cluster-node";
    let ip = path.into_inner();
    if ip.parse::<std::net::IpAddr>().is_err() {
        return HttpResponse::BadRequest().json(serde_json::json!({ "error": "Not a valid IP address" }));
    }
    let storage_slug = if from_peer {
        String::new()
    } else {
        let target = ti_target_cluster(&req, &state);
        ti_storage_cluster(&state, &target)
    };
    let matches = crate::threat_intel::lookup_ip_for(&storage_slug, &ip);
    HttpResponse::Ok().json(serde_json::json!({
        "ip": ip,
        "blocked": !matches.is_empty(),
        "matches": matches,
    }))
}

// ─── Password Reset API (no auth required) ───

/// GET /api/auth/smtp-configured — check if SMTP is configured (controls "Lost Password" visibility)
pub async fn smtp_configured() -> HttpResponse {
    let config = crate::ai::AiConfig::load();
    // Host is the only hard requirement — auth (user/pass) is optional for
    // unauthenticated relays, consistent with the send path and abuse-report gate.
    let configured = !config.smtp_host.is_empty();
    HttpResponse::Ok().json(serde_json::json!({ "smtp_configured": configured, "version": env!("CARGO_PKG_VERSION") }))
}

/// POST /api/auth/forgot-password — send a password reset email
pub async fn forgot_password(state: web::Data<AppState>, body: web::Json<serde_json::Value>) -> HttpResponse {
    let username = body["username"].as_str().unwrap_or("").trim();
    if username.is_empty() {
        return HttpResponse::BadRequest().json(serde_json::json!({"error": "Username is required"}));
    }

    // Rate limit by IP is already handled at the login level, but let's not leak user existence.
    // Always return success to prevent user enumeration.
    let generic_ok = HttpResponse::Ok().json(serde_json::json!({
        "success": true,
        "message": "If an account with that username exists and has an email address, a reset link has been sent."
    }));

    // Look up the WolfStack user
    let store = crate::auth::users::UserStore::load();
    let user = match store.find(username) {
        Some(u) => u.clone(),
        None => return generic_ok,
    };

    if user.email.is_empty() {
        return generic_ok;
    }

    // Check SMTP is configured. Host is the only hard requirement — auth is
    // optional (unauthenticated relays). If the From/host turn out unsendable we
    // still return the generic response below to avoid leaking account state.
    let config = crate::ai::AiConfig::load();
    if config.smtp_host.is_empty() {
        return generic_ok;
    }

    // Create reset token
    let token = state.password_reset_tokens.create(username);

    // Send the email
    let subject = "WolfStack — Password Reset";
    let body_text = format!(
        "A password reset was requested for your WolfStack account '{}'.\n\n\
         Your reset code is:\n\n    {}\n\n\
         Enter this code on the login page to set a new password.\n\
         This code expires in 30 minutes.\n\n\
         If you did not request this, you can safely ignore this email.",
        username, token
    );

    match crate::ai::send_alert_email(&config, subject, &body_text) {
        Ok(()) => generic_ok,
        Err(e) => {
            tracing::warn!("Failed to send password reset email: {}", e);
            generic_ok // Don't leak SMTP errors
        }
    }
}

/// POST /api/auth/reset-password — validate reset token and set new password
pub async fn reset_password(state: web::Data<AppState>, body: web::Json<serde_json::Value>) -> HttpResponse {
    let token = body["token"].as_str().unwrap_or("").trim();
    let new_password = body["password"].as_str().unwrap_or("");

    if token.is_empty() || new_password.is_empty() {
        return HttpResponse::BadRequest().json(serde_json::json!({"error": "Token and new password are required"}));
    }

    if new_password.len() < 6 {
        return HttpResponse::BadRequest().json(serde_json::json!({"error": "Password must be at least 6 characters"}));
    }

    // Validate and consume the token
    let username = match state.password_reset_tokens.validate_and_consume(token) {
        Some(u) => u,
        None => return HttpResponse::BadRequest().json(serde_json::json!({"error": "Invalid or expired reset code"})),
    };

    // Hash the new password and update the user
    let password_hash = match crate::auth::users::hash_password(new_password) {
        Ok(h) => h,
        Err(e) => return HttpResponse::InternalServerError().json(serde_json::json!({"error": e})),
    };

    let mut store = crate::auth::users::UserStore::load();
    if let Some(user) = store.find_mut(&username) {
        user.password_hash = password_hash;
        if let Err(e) = store.save() {
            return HttpResponse::InternalServerError().json(serde_json::json!({"error": e}));
        }
        trigger_control_plane_push(&state);
        HttpResponse::Ok().json(serde_json::json!({"success": true, "message": "Password has been reset. You can now log in."}))
    } else {
        HttpResponse::BadRequest().json(serde_json::json!({"error": "User no longer exists"}))
    }
}

