    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let st = state.into_inner();
    let (top_cpu, top_mem) = tokio::task::spawn_blocking(move || {
        st.monitor.lock().unwrap().top_processes(10)
    }).await.unwrap_or_default();
