// ─── Cluster Browser Sessions ───────────────────────────────────────────

/// GET /api/cluster-browser/sessions — active browser sessions from all nodes in the cluster.
pub async fn cluster_browser_list(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    
    let mut sessions = crate::cluster_browser::list_sessions();
    
    // Try to fetch sessions from all remote nodes (timeout per node)
    let nodes: Vec<_> = state.cluster.nodes.read().unwrap()
        .values()
        .filter(|n| !n.is_self && n.online)
        .cloned()
        .collect();
    
    let client = &*API_HTTP_CLIENT;
    for node in nodes {
        let urls = build_node_urls(&node.address, node.port, "/api/cluster-browser/sessions");

        for url in urls {
            match client
                .get(&url)
                .header("X-WolfStack-Secret", state.cluster_secret.clone())
                .timeout(std::time::Duration::from_secs(3))
                .send()
                .await
            {
                Ok(resp) => {
                    if let Ok(bytes) = resp.bytes().await {
                        if let Ok(remote_sessions) = serde_json::from_slice::<Vec<crate::cluster_browser::BrowserSession>>(&bytes) {
                            sessions.extend(remote_sessions);
                        }
                    }
                    break; // Got a response, don't try other URLs for this node
                }
                Err(_) => continue, // Try next URL
            }
        }
    }
    
    HttpResponse::Ok().json(sessions)
}

#[derive(Deserialize)]
pub struct StartBrowserRequest {
    /// Optional override for the homepage URL the in-container Firefox
    /// loads at startup. Defaults to /cluster-home on this node.
    #[serde(default)]
    pub homepage: Option<String>,
}

/// POST /api/cluster-browser/sessions — start a new browser session,
/// returning the session metadata + the connect URL for the user.
pub async fn cluster_browser_start(
    req: HttpRequest, state: web::Data<AppState>,
    body: web::Json<StartBrowserRequest>,
) -> HttpResponse {
    let user = match require_auth(&req, &state) {
        Ok(u) => u,
        Err(resp) => return resp,
    };
    // Default homepage = our /cluster-home reachable from inside the
    // browser container. Two cases:
    //
    // - Docker backend: bridge containers can't reach 127.0.0.1 / the
    //   host's wolfnet0 IP, so we use `host.docker.internal` — wired
    //   up via `--add-host=host.docker.internal:host-gateway` in
    //   spawn_container. Resolves to the bridge gateway; the host
    //   listens there for any 0.0.0.0-bound service.
    //
    // - Kubernetes backend: pods have no host-gateway alias and
    //   `host.docker.internal` doesn't resolve. Pods CAN reach the
    //   node's IP directly via the cluster network, so we use
    //   self_address (this WolfStack daemon's own IP).
    //
    // Plain HTTP regardless of WolfStack's TLS mode: a fresh Firefox
    // profile rejects self-signed certs, and the inter_node port is
    // always plain HTTP on TLS installs.
    let port_cfg = crate::ports::PortConfig::load();
    let homepage_port = if state.tls_enabled { port_cfg.inter_node } else { port_cfg.api };
    let homepage_host = if crate::cluster_browser::detect_local_kube().is_some() {
        state.cluster.self_address.clone()
    } else {
        "host.docker.internal".to_string()
    };
    // Embed the user as a query param so /cluster-home renders that
    // user's pinned URLs alongside the cluster-wide discovered list.
    let default_homepage = format!(
        "http://{}:{}/cluster-home?user={}",
        crate::netaddr::bracket_host(&homepage_host),
        homepage_port,
        urlencoding_simple(&user)
    );
    let homepage = body.homepage.clone().filter(|s| !s.trim().is_empty()).unwrap_or(default_homepage);
    let tls = state.tls_enabled;

    // Capture the host:port the client used to reach WolfStack BEFORE
    // spawn_blocking — connection_info() returns a borrow that can't
    // cross the await. This becomes the base of the proxy URL so the
    // browser's ws/wss goes back to WolfStack on the same port the
    // user is already connected to.
    let wolfstack_authority = req.connection_info().host().to_string();
    let wolfstack_scheme = if state.tls_enabled { "https" } else { "http" };

    let result = tokio::task::spawn_blocking(move || {
        crate::cluster_browser::start_session(&user, &homepage, tls)
    }).await;

    match result {
        Ok(Ok(session)) => HttpResponse::Ok().json(serde_json::json!({
            "session": session,
            "connect_url": format!(
                "{}://{}/api/cluster-browser/session/{}/",
                wolfstack_scheme, wolfstack_authority, session.id
            ),
        })),
        Ok(Err(e)) => HttpResponse::InternalServerError().json(serde_json::json!({"error": e})),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({"error": e.to_string()})),
    }
}

/// GET /api/cluster-browser/image-status — quick "is the browser image
/// pre-pulled on this node?" so the UI can show "First run will download
/// ~700 MB" if not.
pub async fn cluster_browser_image_status(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    HttpResponse::Ok().json(serde_json::json!({
        "image_present": crate::cluster_browser::image_present(),
    }))
}

/// POST /api/cluster-browser/sessions/start-stream — same as /sessions
/// but streams `docker pull` progress (image download, layers, container
/// start) as Server-Sent Events so the user has visible feedback during
/// the multi-minute first-time pull instead of a silent spinner.
/// Final event: `[done] {json}` with the connect_url.
pub async fn cluster_browser_start_stream(
    req: HttpRequest, state: web::Data<AppState>,
    body: web::Json<StartBrowserRequest>,
) -> HttpResponse {
    let user = match require_auth(&req, &state) {
        Ok(u) => u,
        Err(resp) => return resp,
    };

    // Homepage host: host.docker.internal for the Docker backend
    // (wired up via --add-host), self_address for the Kubernetes
    // backend (pods can reach the node's IP directly). See
    // cluster_browser_start for the full rationale.
    let port_cfg = crate::ports::PortConfig::load();
    let homepage_port = if state.tls_enabled { port_cfg.inter_node } else { port_cfg.api };
    let homepage_host = if crate::cluster_browser::detect_local_kube().is_some() {
        state.cluster.self_address.clone()
    } else {
        "host.docker.internal".to_string()
    };
    // Embed the user as a query param so /cluster-home renders that
    // user's pinned URLs alongside the cluster-wide discovered list.
    let default_homepage = format!(
        "http://{}:{}/cluster-home?user={}",
        crate::netaddr::bracket_host(&homepage_host),
        homepage_port,
        urlencoding_simple(&user)
    );
    let homepage = body.homepage.clone().filter(|s| !s.trim().is_empty()).unwrap_or(default_homepage);
    let tls = state.tls_enabled;

    // Capture the host:port and scheme the client used to reach
    // WolfStack BEFORE the blocking thread spawn — connection_info()
    // borrows from req which is !Send across the thread boundary.
    // Connect URL points to the in-process reverse proxy, not a
    // per-session port, so ws/wss rides whatever port WolfStack is on.
    let wolfstack_authority = req.connection_info().host().to_string();
    let wolfstack_scheme = if state.tls_enabled { "https" } else { "http" };

    let (std_tx, std_rx) = std::sync::mpsc::channel::<String>();
    let (tok_tx, mut tok_rx) = tokio::sync::mpsc::channel::<String>(256);

    std::thread::spawn(move || {
        let result = crate::cluster_browser::start_session_streamed(&user, &homepage, tls, std_tx.clone());
        match result {
            Ok(session) => {
                let payload = serde_json::json!({
                    "session": session,
                    "connect_url": format!(
                        "{}://{}/api/cluster-browser/session/{}/",
                        wolfstack_scheme, wolfstack_authority, session.id
                    ),
                });
                let _ = std_tx.send(format!("[done] {}", payload));
            }
            Err(e) => { let _ = std_tx.send(format!("[error] {}", e)); }
        }
    });

    tokio::task::spawn_blocking(move || {
        while let Ok(msg) = std_rx.recv() {
            if tok_tx.blocking_send(msg).is_err() { break; }
        }
    });

    let stream = async_stream::stream! {
        while let Some(msg) = tok_rx.recv().await {
            let event = format!("data: {}\n\n", msg.replace('\n', "\ndata: "));
            yield Ok::<_, actix_web::Error>(actix_web::web::Bytes::from(event));
        }
    };

    HttpResponse::Ok()
        .insert_header(("Content-Type", "text/event-stream"))
        // identity encoding so the Compress middleware leaves this stream
        // alone — gzip-ing an SSE stream buffers it and breaks the live
        // progress/console output the UI relies on.
        .insert_header(("Content-Encoding", "identity"))
        .insert_header(("Cache-Control", "no-cache"))
        .insert_header(("Connection", "keep-alive"))
        .insert_header(("X-Accel-Buffering", "no"))
        .streaming(stream)
}

pub async fn cluster_browser_stop(
    req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let id = path.into_inner();
    let result = tokio::task::spawn_blocking(move || {
        crate::cluster_browser::stop_session(&id)
    }).await;
    match result {
        Ok(Ok(())) => HttpResponse::Ok().json(serde_json::json!({"stopped": true})),
        Ok(Err(e)) => HttpResponse::BadRequest().json(serde_json::json!({"error": e})),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({"error": e.to_string()})),
    }
}

/// GET /cluster-home[?user=alice] — the homepage HTML that the
/// in-container Firefox loads at startup. Lists discovered services as
/// click-cards plus an open-URL bar at the top. Intentionally
/// unauthenticated: the Firefox inside the container has a fresh
/// profile and no cookies, and the page only exposes information
/// that's already visible to anything on the WolfNet routing fabric.
/// The optional `user` query param scopes the homepage to that user's
/// pinned manual URLs in addition to auto-discovered services — the
/// session-start endpoint embeds the user in the homepage URL when it
/// spawns the container so each user lands on their own grid.
pub async fn cluster_browser_homepage(
    req: HttpRequest, _state: web::Data<AppState>,
    query: web::Query<std::collections::HashMap<String, String>>,
) -> HttpResponse {
    let _ = req; // intentional — unauthenticated by design
    let user = query.get("user").map(|s| s.as_str()).unwrap_or("");
    let html = crate::cluster_browser::render_homepage(user);
    HttpResponse::Ok()
        .insert_header(("Content-Type", "text/html; charset=utf-8"))
        .insert_header(("Cache-Control", "no-cache"))
        .body(html)
}

/// Minimal percent-encoder for the `user` query param embedded in the
/// in-container browser's homepage URL. Avoids pulling in a full
/// urlencoding crate just for one call site. Encodes everything that
/// isn't alphanumeric or `-_.` (RFC 3986 unreserved-ish).
fn urlencoding_simple(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    for byte in s.as_bytes() {
        let c = *byte;
        if c.is_ascii_alphanumeric() || c == b'-' || c == b'_' || c == b'.' || c == b'~' {
            out.push(c as char);
        } else {
            out.push_str(&format!("%{:02X}", c));
        }
    }
    out
}

/// GET /api/wolfnet/used-ips — returns WolfNet IPs in use on this node
/// Requires cluster auth — used for inter-node route discovery
pub async fn wolfnet_used_ips_endpoint(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_cluster_auth(&req, &state) { return resp; }
    let ips = containers::wolfnet_used_ips();
    HttpResponse::Ok().json(ips)
}

/// GET /api/wolfnet/active-ips — WolfNet IPs of workloads ACTIVE (running)
/// on this node. Peers use this for routing (so a stopped container stops
/// attracting traffic) and for start-time conflict detection. Distinct from
/// /used-ips, which also reports stopped workloads' reserved IPs.
pub async fn wolfnet_active_ips_endpoint(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_cluster_auth(&req, &state) { return resp; }
    // Enumeration spawns ip/docker/lxc-ls subprocesses — keep it off the
    // async worker thread.
    let ips = web::block(containers::wolfnet_active_ips).await.unwrap_or_default();
    HttpResponse::Ok().json(ips)
}

/// POST /api/wolfnet/routes/announce — accept a route push from a peer.
///
/// Body shape: `{ "host_ip": "10.10.10.171", "routes": { "10.10.10.100":
/// "10.10.10.171", ... } }`. Every value MUST equal `host_ip` (a peer
/// can only announce routes that point at itself — it can't claim to
/// own a container that lives on someone else's node).
///
/// This is the PUSH side of route propagation, redundant with the
/// pull-based poll loop in `agent::poll_remote_nodes`. The pull path
/// can silently fail (TLS mismatch, cluster-state staleness, peer's
/// /api/agent/status not returning a parseable StatusReport) and leave
/// receivers without container routes for hours. The push side adds
/// an independent path: even if mouse can't successfully poll dreamer,
/// dreamer announcing its routes TO mouse still keeps the routing
/// table converged. dreamer was reporting `10.10.10.100→10.10.10.171`
/// locally but mouse's `routes.json` had no dreamer entries — exactly
/// the failure mode this endpoint defends against.
#[derive(Deserialize)]
pub struct WolfnetRouteAnnounce {
    pub host_ip: String,
    pub routes: std::collections::HashMap<String, String>,
}

pub async fn wolfnet_routes_announce(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<WolfnetRouteAnnounce>,
) -> HttpResponse {
    // Cluster-secret only — this is an inter-node call and must never
    // be reachable via session/UI auth. WolfNet is intentionally
    // cluster-scoped: container routes don't propagate across cluster
    // boundaries even when the wolfnet mesh is shared, so a peer in a
    // different cluster cannot inject routes here.
    if let Err(resp) = require_cluster_auth(&req, &state) { return resp; }

    let announce = body.into_inner();
    // Anti-spoof: the host_ip and every route value must be IPv4, and
    // every route value MUST equal host_ip. A peer that tried to
    // announce `10.10.10.55: 10.10.10.171` would be claiming to own a
    // container that lives on dreamer — refuse it.
    if announce.host_ip.parse::<std::net::Ipv4Addr>().is_err() {
        return HttpResponse::BadRequest().json(serde_json::json!({
            "error": "host_ip is not a valid IPv4 address"
        }));
    }
    let mut accepted = std::collections::HashMap::new();
    for (container_ip, claimed_host) in announce.routes.iter() {
        if container_ip.parse::<std::net::Ipv4Addr>().is_err() {
            continue;
        }
        if claimed_host != &announce.host_ip {
            tracing::warn!(
                "wolfnet_routes_announce: refusing route {} → {} (host_ip is {}); peer cannot announce routes pointing elsewhere",
                container_ip, claimed_host, announce.host_ip
            );
            continue;
        }
        if container_ip == &announce.host_ip {
            // Host's own IP — not a container route. Skip silently.
            continue;
        }
        accepted.insert(container_ip.clone(), claimed_host.clone());
    }

    // First sweep stale entries pointing at this host from this peer
    // (so a container that moved off the peer doesn't linger). Then
    // merge the fresh set. Atomic w.r.t. the WOLFNET_ROUTES lock so the
    // single routes.json write below reflects a consistent state (wolfnetd
    // picks it up on its 15s tick — flush_routes_to_disk no longer SIGHUPs).
    let host_ip = announce.host_ip.clone();
    let cache_changed = tokio::task::spawn_blocking(move || {
        use std::collections::HashMap;
        let mut cache = containers::WOLFNET_ROUTES.lock().unwrap();
        let before = cache.clone();
        // Drop entries pointing at this host that aren't in the fresh
        // announce — they've been deleted on the source.
        cache.retain(|k, v| {
            if v == &host_ip { accepted.contains_key(k) } else { true }
        });
        for (k, v) in &accepted {
            cache.insert(k.clone(), v.clone());
        }
        let changed = *cache != before;
        if changed {
            // Drop the lock before flush_routes_to_disk reacquires it.
            let snapshot: HashMap<String, String> = cache.clone();
            drop(cache);
            containers::flush_routes_to_disk(&snapshot);
        }
        changed
    }).await.unwrap_or(false);

    HttpResponse::Ok().json(serde_json::json!({
        "accepted": true,
        "host_ip": announce.host_ip,
        "changed": cache_changed
    }))
}

/// Push the local WOLFNET_ROUTES (entries that point at THIS host) to
/// every online wolfstack peer in the cluster. Fire-and-forget; each
/// peer can fail independently without holding up the others.
///
/// Runs on a 30s tick from `main.rs`. Symmetric to `poll_remote_nodes`
/// — they pull, this pushes. The combination is robust against either
/// path failing on its own.
pub async fn announce_wolfnet_routes_to_peers(
    cluster: std::sync::Arc<crate::agent::ClusterState>,
    cluster_secret: String,
) {
    // Build the announce payload first — shared by both discovery paths.
    let local_ips = containers::wolfnet_used_ips_cached();
    let host_ip = match local_ips.first() {
        Some(ip) if !ip.is_empty() => ip.clone(),
        _ => {
            // No wolfnet0 IP yet — nothing to announce.
            return;
        }
    };
    let local_routes: std::collections::HashMap<String, String> = {
        let cache = containers::WOLFNET_ROUTES.lock().unwrap();
        cache
            .iter()
            .filter(|(_, v)| *v == &host_ip)
            .map(|(k, v)| (k.clone(), v.clone()))
            .collect()
    };

    let payload = serde_json::json!({
        "host_ip": host_ip,
        "routes": local_routes,
    });

    // ── Path 1: Cluster node list (existing mechanism) ──
    // Push to every online wolfstack peer in OUR cluster.
    let self_cluster = cluster.get_self_cluster_name();
    let cluster_peers: Vec<(String, u16)> = {
        let nodes = cluster.nodes.read().unwrap();
        nodes
            .values()
            .filter(|n| !n.is_self)
            .filter(|n| n.node_type == "wolfstack")
            .filter(|n| n.online)
            .filter(|n| n.cluster_name.as_deref().unwrap_or("WolfStack") == self_cluster)
            .map(|n| (n.address.clone(), n.port))
            .collect()
    };

    let client = API_HTTP_CLIENT.clone();
    let mut pushed_hosts: std::collections::HashSet<String> = std::collections::HashSet::new();
    for (address, port) in &cluster_peers {
        pushed_hosts.insert(address.clone());
        let urls = build_node_urls(address, *port, "/api/wolfnet/routes/announce");
        for url in &urls {
            let r = client
                .post(url)
                .timeout(std::time::Duration::from_secs(5))
                .header("X-WolfStack-Secret", &cluster_secret)
                .json(&payload)
                .send()
                .await;
            match r {
                Ok(resp) => {
                    let success = resp.status().is_success();
                    let _ = resp.bytes().await;
                    if success {
                        break;
                    }
                }
                Err(_) => { /* try next URL in the fallback chain */ }
            }
        }
    }

    // ── Path 2: WolfNet config.toml peers (ground-truth) ──
    // The config.toml defines exactly which nodes share this WolfNet
    // mesh. Push to any peers not already covered by the cluster list.
    // This is the primary mechanism — it works even when the cluster
    // node list has stale cluster_names or the peer is temporarily
    // marked offline.
    if let Ok(config_str) = std::fs::read_to_string("/etc/wolfnet/config.toml") {
        if let Ok(config) = config_str.parse::<toml::Value>() {
            if let Some(peers) = config.get("peers").and_then(|p| p.as_array()) {
                for peer in peers {
                    let endpoint = match peer.get("endpoint").and_then(|v| v.as_str()) {
                        Some(e) => e,
                        None => continue,
                    };
                    // endpoint is "hostname:port" — extract hostname
                    // (port-aware: a bare/bracketed IPv6 endpoint must not
                    // be truncated at its first group)
                    let hostname = crate::netaddr::strip_port(endpoint);
                    if hostname.is_empty() { continue; }
                    // Skip if we already pushed to this host via Path 1
                    if pushed_hosts.contains(hostname) { continue; }
                    // Also check against wolfnet IP — Path 1 might have
                    // used a numeric address while config has a hostname
                    let allowed_ip = peer.get("allowed_ip").and_then(|v| v.as_str()).unwrap_or("");
                    if pushed_hosts.contains(allowed_ip) { continue; }
                    pushed_hosts.insert(hostname.to_string());

                    // Try HTTPS on default port, then HTTP, then via wolfnet IP
                    let hostname_url = crate::netaddr::bracket_host(hostname);
                    let urls = vec![
                        format!("https://{}:8553/api/wolfnet/routes/announce", hostname_url),
                        format!("http://{}:8554/api/wolfnet/routes/announce", hostname_url),
                        format!("http://{}:8554/api/wolfnet/routes/announce", allowed_ip),
                    ];
                    for url in &urls {
                        let r = client
                            .post(url)
                            .timeout(std::time::Duration::from_secs(5))
                            .header("X-WolfStack-Secret", &cluster_secret)
                            .json(&payload)
                            .send()
                            .await;
                        match r {
                            Ok(resp) => {
                                let success = resp.status().is_success();
                                let _ = resp.bytes().await;
                                if success {
                                    break;
                                }
                            }
                            Err(_) => {}
                        }
                    }
                }
            }
        }
    }
}

/// GET /api/wolfnet/routes — returns the full WOLFNET_ROUTES cache + local used IPs for debugging
pub async fn wolfnet_routes_debug(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }

    // Get the WOLFNET_ROUTES cache (container_ip -> gateway_host_ip)
    let routes = containers::WOLFNET_ROUTES.lock().unwrap().clone();

    // Get local used IPs with labels
    let local_ips = containers::wolfnet_used_ips();
    let host_ip = local_ips.first().cloned().unwrap_or_default();

    // Build a combined view: each IP with its type and route info
    let mut entries: Vec<serde_json::Value> = Vec::new();

    // Local used IPs
    for (i, ip) in local_ips.iter().enumerate() {
        entries.push(serde_json::json!({
            "ip": ip,
            "type": if i == 0 { "host" } else { "local" },
            "gateway": if i == 0 { "self" } else { &host_ip },
            "source": "local"
        }));
    }

    // Remote routes from cache
    for (ip, gateway) in &routes {
        // Skip if already in local list
        if local_ips.contains(ip) { continue; }
        entries.push(serde_json::json!({
            "ip": ip,
            "type": "remote",
            "gateway": gateway,
            "source": "cache"
        }));
    }

    // Also read routes.json for comparison
    let routes_json = std::fs::read_to_string("/var/run/wolfnet/routes.json")
        .ok()
        .and_then(|c| serde_json::from_str::<std::collections::HashMap<String, String>>(&c).ok())
        .unwrap_or_default();

    HttpResponse::Ok().json(serde_json::json!({
        "entries": entries,
        "routes_cache_count": routes.len(),
        "routes_json_count": routes_json.len(),
        "host_ip": host_ip,
        "local_ips": local_ips,
    }))
}

