/// GET /api/containers/docker/{id}/volumes — list Docker container volumes
pub async fn docker_volumes(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let id = path.into_inner();
    let mounts = containers::docker_list_volumes(&id);
    HttpResponse::Ok().json(mounts)
}

#[derive(Deserialize)]
pub struct DockerUpdateConfigReq {
    pub autostart: Option<bool>,
    pub memory_mb: Option<u64>,
    pub cpus: Option<f32>,
    #[serde(default)]
    pub wolfnet_ip: Option<String>,
}

pub async fn docker_update_config(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
    body: web::Json<DockerUpdateConfigReq>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let id = path.into_inner();

    match containers::docker_update_config(&id, body.autostart, body.memory_mb, body.cpus, body.wolfnet_ip.clone()) {
         Ok(msg) => {
            // Re-inspect AFTER the update (and after any compose-file
            // edit + docker-update retry) and return the authoritative
            // autostart state. Frontend uses this value directly to
            // set the checkbox — it does NOT trust the user's intent.
            // That closes the class of bugs where `docker update`
            // succeeded, the verify passed, but the subsequent list
            // fetch somehow returned a stale/different value (cache,
            // combined-inspect parse edge case, multi-writer race,
            // whatever). The checkbox now renders exactly what
            // `docker inspect` says right now.
            let verified_autostart: Option<bool> = std::process::Command::new("docker")
                .args(["inspect", "-f", "{{.HostConfig.RestartPolicy.Name}}", &id])
                .output().ok()
                .and_then(|o| if o.status.success() {
                    Some(String::from_utf8_lossy(&o.stdout).trim().to_string())
                } else { None })
                .map(|p| !p.is_empty() && p != "no");
            HttpResponse::Ok().json(serde_json::json!({
                "message": msg,
                "autostart": verified_autostart,
            }))
         }
         Err(e) => HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
    }
}

/// POST /api/containers/docker/{id}/env — update environment variables (recreates container)
pub async fn docker_update_env(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
    body: web::Json<serde_json::Value>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let id = path.into_inner();

    let env: Vec<String> = match body.get("env").and_then(|v| v.as_array()) {
        Some(arr) => arr.iter()
            .filter_map(|v| v.as_str().map(|s| s.to_string()))
            .filter(|s| !s.is_empty())
            .collect(),
        None => return HttpResponse::BadRequest().json(serde_json::json!({ "error": "Missing 'env' array" })),
    };

    match containers::docker_recreate_with_env(&id, &env) {
        Ok(msg) => HttpResponse::Ok().json(serde_json::json!({ "message": msg })),
        Err(e) => HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
    }
}

/// POST /api/containers/docker/{id}/raw-config — rebuild the container
/// from an edited `docker inspect` JSON. This lets operators add binds,
/// change ports, tweak labels, adjust any config field without having
/// to `docker rm` and re-run by hand. Recreation is rename-based: the
/// old container is kept renamed until the new one is successfully
/// created, then removed; on failure we rename back so nothing is
/// lost.
///
/// The request body is the inspect JSON the UI fetched from
/// `GET /inspect`, with the operator's edits applied. We don't diff
/// against the current state — we just treat the JSON as the new
/// spec. Fields that aren't part of a container spec (State,
/// NetworkSettings.IPAddress, Created timestamps, etc.) are ignored,
/// so the operator can't break things by leaving those stale.
pub async fn docker_update_raw_config(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
    body: web::Json<serde_json::Value>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let id = path.into_inner();

    // Docker's inspect output is always a single-element array. The
    // UI may send it either way (bare object OR 1-element array),
    // accommodate both.
    let spec = match &*body {
        serde_json::Value::Array(arr) if arr.len() == 1 => arr[0].clone(),
        serde_json::Value::Object(_) => body.clone(),
        _ => return HttpResponse::BadRequest().json(serde_json::json!({
            "error": "Body must be a docker-inspect JSON object (or a 1-element array of one)",
        })),
    };

    let spec_for_task = spec.clone();
    let id_for_task = id.clone();
    let res = tokio::task::spawn_blocking(move || {
        containers::docker_recreate_from_inspect(&id_for_task, &spec_for_task)
    }).await;
    match res {
        Ok(Ok(msg)) => HttpResponse::Ok().json(serde_json::json!({ "message": msg })),
        Ok(Err(e)) => HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({
            "error": format!("recreate task panicked: {}", e)
        })),
    }
}

/// GET /api/containers/docker/{id}/inspect — inspect raw docker config
pub async fn docker_inspect(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let id = path.into_inner();
    
    match containers::docker_inspect(&id) {
        Ok(json) => HttpResponse::Ok().json(json),
        Err(e) => HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
    }
}

