/// GET /api/ai/config — get AI configuration (keys masked)
pub async fn ai_get_config(
    req: HttpRequest, state: web::Data<AppState>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let config = state.ai_agent.config.lock().unwrap();
    HttpResponse::Ok().json(config.masked())
}

/// POST /api/ai/config — save AI configuration
pub async fn ai_save_config(
    req: HttpRequest, state: web::Data<AppState>,
    body: web::Json<serde_json::Value>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let config_json;
    {
        let mut config = state.ai_agent.config.lock().unwrap();

        // Update fields — only update keys if not masked values
        if let Some(v) = body.get("agent_enabled").and_then(|v| v.as_bool()) {
            config.agent_enabled = v;
        }
        if let Some(v) = body.get("provider").and_then(|v| v.as_str()) {
            config.provider = v.to_string();
        }
        if let Some(v) = body.get("cloudflare_account_id").and_then(|v| v.as_str()) {
            config.cloudflare_account_id = v.trim().to_string();
        }
        if let Some(v) = body.get("cloudflare_api_key").and_then(|v| v.as_str()) {
            if !v.contains("••••") && !v.is_empty() {
                config.cloudflare_api_key = v.to_string();
            }
        }
        if let Some(v) = body.get("claude_api_key").and_then(|v| v.as_str()) {
            if !v.contains("••••") && !v.is_empty() {
                config.claude_api_key = v.to_string();
            }
        }
        if let Some(v) = body.get("gemini_api_key").and_then(|v| v.as_str()) {
            if !v.contains("••••") && !v.is_empty() {
                config.gemini_api_key = v.to_string();
            }
        }
        if let Some(v) = body.get("openrouter_api_key").and_then(|v| v.as_str()) {
            if !v.contains("••••") && !v.is_empty() {
                config.openrouter_api_key = v.to_string();
            }
        }
        if let Some(v) = body.get("openai_api_key").and_then(|v| v.as_str()) {
            if !v.contains("••••") && !v.is_empty() {
                config.openai_api_key = v.to_string();
            }
        }
        if let Some(v) = body.get("local_url").and_then(|v| v.as_str()) {
            config.local_url = v.to_string();
        }
        if let Some(v) = body.get("local_api_key").and_then(|v| v.as_str()) {
            if !v.contains("••••") && !v.is_empty() {
                config.local_api_key = v.to_string();
            }
        }
        if let Some(v) = body.get("model").and_then(|v| v.as_str()) {
            config.model = v.to_string();
        }
        if let Some(v) = body.get("email_enabled").and_then(|v| v.as_bool()) {
            config.email_enabled = v;
        }
        if let Some(v) = body.get("email_to").and_then(|v| v.as_str()) {
            config.email_to = v.to_string();
        }
        if let Some(v) = body.get("smtp_host").and_then(|v| v.as_str()) {
            config.smtp_host = v.to_string();
        }
        if let Some(v) = body.get("smtp_port").and_then(|v| v.as_u64()) {
            config.smtp_port = v as u16;
        }
        if let Some(v) = body.get("smtp_from").and_then(|v| v.as_str()) {
            config.smtp_from = v.to_string();
        }
        if let Some(v) = body.get("smtp_user").and_then(|v| v.as_str()) {
            config.smtp_user = v.to_string();
        }
        if let Some(v) = body.get("smtp_pass").and_then(|v| v.as_str()) {
            if !v.contains("••••") && !v.is_empty() {
                config.smtp_pass = v.to_string();
            }
        }
        if let Some(v) = body.get("smtp_tls").and_then(|v| v.as_str()) {
            config.smtp_tls = v.to_string();
        }
        if let Some(v) = body.get("check_interval_minutes").and_then(|v| v.as_u64()) {
            config.check_interval_minutes = v as u32;
        }
        if let Some(v) = body.get("scan_schedule").and_then(|v| v.as_str()) {
            config.scan_schedule = v.to_string();
        }
        if let Some(arr) = body.get("accepted_risks").and_then(|v| v.as_array()) {
            config.accepted_risks = arr.iter()
                .filter_map(|v| v.as_str().map(|s| s.trim().to_string()))
                .filter(|s| !s.is_empty() && s.len() <= 200)
                .collect();
        }
        if let Some(v) = body.get("agent_max_tool_calls").and_then(|v| v.as_u64()) {
            // Range-clamp on save so the on-disk file always holds a
            // sane value — defence-in-depth alongside the use-time
            // clamp in `effective_agent_max_tool_calls`.
            config.agent_max_tool_calls = (v as u32).clamp(1, 100);
        }
        if let Some(v) = body.get("agent_tool_call_limit_enabled").and_then(|v| v.as_bool()) {
            config.agent_tool_call_limit_enabled = v;
        }

        // Validate provider and model compatibility
        if let Err(e) = config.validate() {
            return HttpResponse::BadRequest().json(serde_json::json!({"error": e}));
        }

        if let Err(e) = config.save() {
            return HttpResponse::InternalServerError().json(serde_json::json!({"error": e}));
        }

        // Serialize full config (with real keys) for cluster sync
        config_json = serde_json::to_value(&*config).unwrap_or_default();
    }

    // Broadcast to all online cluster nodes in the background
    let cluster_secret = state.cluster_secret.clone();
    let nodes = state.cluster.get_all_nodes();
    let client = API_HTTP_CLIENT.clone();
    for node in nodes.iter().filter(|n| !n.is_self && n.online) {
        let url = format!("http://{}:{}/api/ai/config/sync", crate::netaddr::bracket_host(&node.address), node.port);
        let secret = cluster_secret.clone();
        let cfg = config_json.clone();
        let c = client.clone();
        tokio::spawn(async move {
            let _ = c.post(&url)
                .header("X-WolfStack-Secret", secret)
                .json(&cfg)
                .timeout(std::time::Duration::from_secs(5))
                .send()
                .await;
        });
    }

    HttpResponse::Ok().json(serde_json::json!({"status": "saved"}))
}

/// POST /api/ai/config/sync — receive AI config from another cluster node
pub async fn ai_sync_config(
    req: HttpRequest, state: web::Data<AppState>,
    body: web::Json<crate::ai::AiConfig>,
) -> HttpResponse {
    if let Err(resp) = require_cluster_auth(&req, &state) { return resp; }

    let new_config = body.into_inner();
    if let Err(e) = new_config.save() {
        warn!("Failed to save synced AI config: {}", e);
        return HttpResponse::InternalServerError().json(serde_json::json!({"error": e}));
    }

    // Update in-memory config
    let mut config = state.ai_agent.config.lock().unwrap();
    *config = new_config;


    HttpResponse::Ok().json(serde_json::json!({"status": "synced"}))
}

/// POST /api/ai/test-email — send a test email to verify SMTP settings
pub async fn ai_test_email(
    req: HttpRequest, state: web::Data<AppState>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }

    let config = state.ai_agent.config.lock().unwrap().clone();

    if !config.email_enabled || config.email_to.is_empty() {
        return HttpResponse::BadRequest().json(serde_json::json!({
            "error": "Email alerts not enabled or no recipient configured"
        }));
    }

    let hostname = hostname::get()
        .map(|h| h.to_string_lossy().to_string())
        .unwrap_or_else(|_| "unknown".to_string());
    let version = env!("CARGO_PKG_VERSION");

    let subject = format!("[WolfStack] Test Email from {}", hostname);
    let body = format!(
        "✅ WolfStack Test Email\n\n\
         This is a test email from your WolfStack AI Agent.\n\n\
         Hostname: {}\n\
         Version: {}\n\
         Time: {}\n\n\
         If you received this, your email alert settings are working correctly.",
        hostname, version,
        chrono::Utc::now().format("%Y-%m-%d %H:%M:%S UTC")
    );

    match crate::ai::send_alert_email(&config, &subject, &body) {
        Ok(_) => HttpResponse::Ok().json(serde_json::json!({
            "status": "sent",
            "message": format!("Test email sent to {}", config.email_to)
        })),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({
            "error": format!("Failed to send: {}", e)
        })),
    }
}

/// POST /api/ai/test-connection — lightweight reachability probe for
/// the configured AI provider. Sends a tiny chat completion (no tools,
/// max_tokens=8, "ping") with a 15s outer timeout and 5s connect
/// timeout. Returns timing breakdown + structured error so the
/// "Test Connection" UI can show what actually failed.
///
/// Distinct from /api/ai/chat — that path loads the full system
/// prompt and 8 tool schemas (~13 KB request body), which is enough
/// to trip path-MTU black holes on misconfigured LANs. KO4BSR's
/// reproduction. The test endpoint sends ~150 bytes so the URL/auth
/// path is exercised without the body-size dependency.
pub async fn ai_test_connection(
    req: HttpRequest, state: web::Data<AppState>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }

    let config = state.ai_agent.config.lock().unwrap().clone();
    if !config.is_configured() {
        return HttpResponse::BadRequest().json(serde_json::json!({
            "ok": false,
            "stage": "config",
            "error": "AI not configured — set provider/key in Settings → AI Agent",
        }));
    }

    let provider = config.provider.clone();
    let url_for_log = match provider.as_str() {
        "local" => config.local_url.clone(),
        "openai" => "https://api.openai.com/v1".to_string(),
        "openrouter" => "https://openrouter.ai/api/v1".to_string(),
        "cloudflare" => crate::ai::cloudflare_base_url(&config.cloudflare_account_id),
        "gemini" => format!("https://generativelanguage.googleapis.com/.../{}:generateContent", config.model),
        // claude-cli shells out to the local `claude` binary — no HTTP, no key.
        "claude-cli" => "local `claude` CLI (Pro/Max login — no API key)".to_string(),
        _ => "https://api.anthropic.com/v1/messages".to_string(),
    };

    let started = std::time::Instant::now();
    // Reuse simple_chat — it picks the right provider call. The system
    // prompt and history we pass are intentionally minimal so the
    // request body stays small (~150 bytes for local, similar for
    // hosted providers).
    let result = tokio::time::timeout(
        std::time::Duration::from_secs(15),
        crate::ai::simple_chat(&config, "You are a connectivity test. Reply with the single word: OK", &[], "ping"),
    ).await;
    let elapsed_ms = started.elapsed().as_millis();

    match result {
        Ok(Ok(reply)) => HttpResponse::Ok().json(serde_json::json!({
            "ok": true,
            "provider": provider,
            "url": url_for_log,
            "model": config.model,
            "elapsed_ms": elapsed_ms,
            "reply": reply.chars().take(200).collect::<String>(),
        })),
        Ok(Err(e)) => HttpResponse::Ok().json(serde_json::json!({
            "ok": false,
            "stage": "request",
            "provider": provider,
            "url": url_for_log,
            "model": config.model,
            "elapsed_ms": elapsed_ms,
            "error": e,
        })),
        Err(_) => HttpResponse::Ok().json(serde_json::json!({
            "ok": false,
            "stage": "timeout",
            "provider": provider,
            "url": url_for_log,
            "model": config.model,
            "elapsed_ms": elapsed_ms,
            "error": format!(
                "Test request did not complete within 15 seconds. \
                 The host may be unreachable, blocked by a firewall, or behind a path-MTU black hole. \
                 Try `curl -v {}` from this machine to diagnose.",
                url_for_log
            ),
        })),
    }
}

/// GET /api/ai/suppress?p=<phrase>&t=<token> — one-click suppress
/// from an alert email. Session-free: the HMAC token is the auth.
/// Adds the phrase to accepted_risks and returns a minimal HTML page
/// confirming what was suppressed.
#[derive(Deserialize)]
pub struct AiSuppressQuery {
    pub p: String,
    pub t: String,
}

pub async fn ai_suppress_link(
    state: web::Data<AppState>,
    query: web::Query<AiSuppressQuery>,
) -> HttpResponse {
    let phrase = query.p.trim().to_string();
    if phrase.is_empty() || phrase.len() > 200 {
        return HttpResponse::BadRequest().body("Invalid phrase");
    }
    if !crate::ai::verify_suppress_token(&phrase, &query.t) {
        return HttpResponse::Forbidden().body(
            "Invalid or expired suppress token. \
             This link can only be used with a valid HMAC from an alert email sent by this node."
        );
    }

    // Add to accepted_risks if not already there.
    let added = {
        let mut config = state.ai_agent.config.lock().unwrap();
        if config.accepted_risks.iter().any(|r| r.eq_ignore_ascii_case(&phrase)) {
            false
        } else {
            config.accepted_risks.push(phrase.clone());
            if let Err(e) = config.save() {
                warn!("Failed to save accepted_risks: {}", e);
            }
            true
        }
    };

    // Minimal inline HTML — no frontend dependency. Explicitly does
    // NOT include operator session tokens or return to the dashboard
    // by default; a user who clicked a stale link from a shared inbox
    // should just see a confirmation, nothing privileged.
    let escaped: String = phrase.chars()
        .map(|c| match c {
            '<' => "&lt;".to_string(),
            '>' => "&gt;".to_string(),
            '&' => "&amp;".to_string(),
            '"' => "&quot;".to_string(),
            _ => c.to_string(),
        })
        .collect();
    let body = format!(
        "<!DOCTYPE html><html><head><meta charset=\"utf-8\"><title>Alert suppressed</title>\
         <style>body{{font-family:system-ui,sans-serif;max-width:640px;margin:4em auto;padding:1em;color:#222;}}\
         code{{background:#f2f2f2;padding:2px 6px;border-radius:4px;}}</style></head><body>\
         <h2>{}</h2>\
         <p>The AI agent will no longer flag this condition in future health checks on this node:</p>\
         <p><code>{}</code></p>\
         <p>You can review or remove suppressed items under <strong>AI settings → Accepted risks</strong> in the WolfStack dashboard.</p>\
         </body></html>",
        if added { "✓ Alert suppressed" } else { "Already suppressed" },
        escaped,
    );
    HttpResponse::Ok().content_type("text/html; charset=utf-8").body(body)
}

/// GET /api/ai/accepted-risks — list suppressed phrases
pub async fn ai_accepted_risks_get(
    req: HttpRequest, state: web::Data<AppState>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let risks = state.ai_agent.config.lock().unwrap().accepted_risks.clone();
    HttpResponse::Ok().json(serde_json::json!({ "accepted_risks": risks }))
}

/// POST /api/ai/accepted-risks — replace the list wholesale
#[derive(Deserialize)]
pub struct AiAcceptedRisksSave {
    pub accepted_risks: Vec<String>,
}

pub async fn ai_accepted_risks_save(
    req: HttpRequest, state: web::Data<AppState>,
    body: web::Json<AiAcceptedRisksSave>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let cleaned: Vec<String> = body.accepted_risks.iter()
        .map(|r| r.trim().to_string())
        .filter(|r| !r.is_empty() && r.len() <= 200)
        .collect();
    {
        let mut config = state.ai_agent.config.lock().unwrap();
        config.accepted_risks = cleaned.clone();
        if let Err(e) = config.save() {
            return HttpResponse::InternalServerError().json(serde_json::json!({ "error": e }));
        }
    }
    HttpResponse::Ok().json(serde_json::json!({ "accepted_risks": cleaned }))
}

/// POST /api/ai/accepted-risks/remove — remove one entry by value
#[derive(Deserialize)]
pub struct AiAcceptedRisksRemove {
    pub phrase: String,
}

pub async fn ai_accepted_risks_remove(
    req: HttpRequest, state: web::Data<AppState>,
    body: web::Json<AiAcceptedRisksRemove>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let phrase = body.phrase.trim();
    let removed;
    {
        let mut config = state.ai_agent.config.lock().unwrap();
        let before = config.accepted_risks.len();
        config.accepted_risks.retain(|r| !r.eq_ignore_ascii_case(phrase));
        removed = before - config.accepted_risks.len();
        if removed > 0 {
            if let Err(e) = config.save() {
                return HttpResponse::InternalServerError().json(serde_json::json!({ "error": e }));
            }
        }
    }
    HttpResponse::Ok().json(serde_json::json!({
        "removed": removed,
        "accepted_risks": state.ai_agent.config.lock().unwrap().accepted_risks.clone(),
    }))
}

/// POST /api/ai/chat — send a message to the AI agent
#[derive(Deserialize)]
pub struct AiChatRequest {
    pub message: String,
    /// The node ID the user is currently viewing (null/empty = datacenter level)
    #[serde(default)]
    pub node_id: Option<String>,
    /// The page/view the user is currently on (e.g. "dashboard", "containers", "vms", "networking")
    #[serde(default)]
    pub view: Option<String>,
    /// Friendly name of what the user is looking at (e.g. node hostname, container name)
    #[serde(default)]
    pub context_name: Option<String>,
}

pub async fn ai_chat(
    req: HttpRequest, state: web::Data<AppState>,
    body: web::Json<AiChatRequest>,
) -> HttpResponse {
    let username = match require_auth(&req, &state) {
        Ok(u) => u,
        Err(resp) => return resp,
    };

    // Build server context for the AI
    let server_context = {
        let hostname = hostname::get()
            .map(|h| h.to_string_lossy().to_string())
            .unwrap_or_else(|_| "unknown".to_string());

        // Get local container/VM lists once (reuse for counts and names)
        let local_docker_list = crate::containers::docker_list_all();
        let local_lxc_list = crate::containers::lxc_list_all();
        let local_vm_list = state.vms.lock().unwrap().list_vms();
        let docker_count = local_docker_list.len();
        let lxc_count = local_lxc_list.len();
        let vm_count = local_vm_list.len();
        let components = crate::installer::get_all_status();

        let local_docker: Vec<String> = local_docker_list.iter().map(|c| format!("{} [{}]", c.name, c.state)).collect();
        let local_lxc: Vec<String> = local_lxc_list.iter().map(|c| format!("{} [{}]", c.name, c.state)).collect();
        let local_vms: Vec<String> = local_vm_list.iter().map(|v| format!("{} [{}]", v.name, if v.running { "running" } else { "stopped" })).collect();

        let nodes = state.cluster.get_all_nodes();

        // All nodes (including Proxmox nodes that have WolfStack agents)
        let all_online: Vec<&crate::agent::Node> = nodes.iter().filter(|n| n.online).collect();
        // PVE nodes for separate cluster grouping display
        let pve_nodes: Vec<&crate::agent::Node> = nodes.iter().filter(|n| n.node_type == "proxmox").collect();

        let node_info = all_online.iter().map(|n| {
            let mut line = format!("  - {} ({}) [{}]", n.hostname, n.address,
                if n.online { "online" } else { "offline" });
            if n.docker_count > 0 { line.push_str(&format!(" — {} Docker", n.docker_count)); }
            if n.lxc_count > 0 { line.push_str(&format!(", {} LXC", n.lxc_count)); }
            if n.vm_count > 0 { line.push_str(&format!(", {} VMs", n.vm_count)); }
            // For the local node, include actual names
            if n.is_self {
                if !local_docker.is_empty() { line.push_str(&format!("\n      Docker: {}", local_docker.join(", "))); }
                if !local_lxc.is_empty() { line.push_str(&format!("\n      LXC: {}", local_lxc.join(", "))); }
                if !local_vms.is_empty() { line.push_str(&format!("\n      VMs: {}", local_vms.join(", "))); }
            }
            line
        }).collect::<Vec<_>>().join("\n");

        // Group PVE nodes by cluster
        let mut pve_clusters: std::collections::HashMap<String, Vec<&crate::agent::Node>> = std::collections::HashMap::new();
        for n in &pve_nodes {
            let key = n.pve_cluster_name.clone()
                .or_else(|| n.cluster_name.clone())
                .unwrap_or_else(|| n.address.clone());
            pve_clusters.entry(key).or_default().push(n);
        }

        let pve_info = if pve_clusters.is_empty() {
            "None".to_string()
        } else {
            pve_clusters.iter().map(|(cluster_name, cnodes)| {
                let node_details = cnodes.iter().map(|n| {
                    let metrics_str = if let Some(ref m) = n.metrics {
                        let mem_used_gb = m.memory_used_bytes as f64 / (1024.0 * 1024.0 * 1024.0);
                        let mem_total_gb = m.memory_total_bytes as f64 / (1024.0 * 1024.0 * 1024.0);
                        let root_disk = m.disks.iter().find(|d| d.mount_point == "/").or_else(|| m.disks.first());
                        let disk_info = root_disk.map(|d| {
                            let used_gb = d.used_bytes as f64 / (1024.0 * 1024.0 * 1024.0);
                            let total_gb = d.total_bytes as f64 / (1024.0 * 1024.0 * 1024.0);
                            format!(", disk {:.1}/{:.1}GB", used_gb, total_gb)
                        }).unwrap_or_default();
                        format!(" — CPU {:.0}%, RAM {:.1}/{:.1}GB{}",
                            m.cpu_usage_percent, mem_used_gb, mem_total_gb, disk_info)
                    } else {
                        String::new()
                    };
                    format!("    - {} (pve_node: {}, {}) [{}] — {} VMs, {} CTs{}",
                        n.hostname, n.pve_node_name.as_deref().unwrap_or("?"),
                        n.address,
                        if n.online { "online" } else { "offline" },
                        n.vm_count, n.lxc_count, metrics_str)
                }).collect::<Vec<_>>().join("\n");
                format!("  Cluster '{}' ({} nodes):\n{}", cluster_name, cnodes.len(), node_details)
            }).collect::<Vec<_>>().join("\n")
        };

        // Build user navigation context
        let user_context = {
            let mut ctx = String::new();
            if let Some(ref nid) = body.node_id {
                if !nid.is_empty() {
                    let target_node = nodes.iter().find(|n| n.id == *nid);
                    if let Some(tn) = target_node {
                        ctx.push_str(&format!("\n\nUSER IS CURRENTLY VIEWING: Node '{}' ({})", tn.hostname, tn.address));
                        if tn.node_type == "proxmox" {
                            ctx.push_str(" [Proxmox VE node]");
                        }
                    } else {
                        ctx.push_str(&format!("\n\nUSER IS CURRENTLY VIEWING: Node ID '{}'", nid));
                    }
                } else {
                    ctx.push_str("\n\nUSER IS CURRENTLY VIEWING: Datacenter overview (all nodes)");
                }
            } else {
                ctx.push_str("\n\nUSER IS CURRENTLY VIEWING: Datacenter overview (all nodes)");
            }
            if let Some(ref view) = body.view {
                if !view.is_empty() {
                    ctx.push_str(&format!(", Page: {}", view));
                }
            }
            if let Some(ref name) = body.context_name {
                if !name.is_empty() {
                    ctx.push_str(&format!(", Context: {}", name));
                }
            }
            // Enumerate containers/VMs on the viewed node (reuse already-fetched local data)
            if body.node_id.as_ref().map(|s| !s.is_empty()).unwrap_or(false) {
                let is_self_node = nodes.iter().any(|n| n.is_self && Some(&n.id) == body.node_id.as_ref());
                if is_self_node {
                    if !local_docker.is_empty() {
                        ctx.push_str("\n\nDocker containers on this node:");
                        for name in &local_docker { ctx.push_str(&format!("\n  - {}", name)); }
                    }
                    if !local_lxc.is_empty() {
                        ctx.push_str("\n\nLXC containers on this node:");
                        for name in &local_lxc { ctx.push_str(&format!("\n  - {}", name)); }
                    }
                    if !local_vms.is_empty() {
                        ctx.push_str("\n\nVMs on this node:");
                        for name in &local_vms { ctx.push_str(&format!("\n  - {}", name)); }
                    }
                } else {
                    ctx.push_str("\n\n(Container/VM list for remote nodes is provided by the frontend target picker)");
                }
            }

            ctx.push_str("\n\nWhen the user says 'this server', 'this node', 'here', etc. they mean the node/view shown above.");
            ctx.push_str("\nThe user may be asking about a specific container, VM, or the host itself. If it's ambiguous, ask which one they mean.");
            ctx.push_str("\nWhen proposing [ACTION] fixes, set target=\"local\" for commands on the host node. The user will choose the actual target (host, container, or VM) before approving.");
            ctx
        };

        format!(
            "Hostname: {}\nLocal Docker containers: {}\nLocal LXC containers: {}\nLocal VMs: {}\n\
             Components: {}\n\nAll Nodes ({}):\n{}\n\nProxmox Clusters:\n{}{}",
            hostname, docker_count, lxc_count, vm_count,
            components.iter().map(|c| format!("{:?}: {}", c.component, if c.running { "running" } else { "stopped" })).collect::<Vec<_>>().join(", "),
            all_online.len(), node_info,
            pve_info,
            user_context,
        )
    };

    // Build cluster node list for remote command execution.
    // Include ALL online nodes (including Proxmox nodes that have WolfStack agents).
    // URLs come from build_node_urls so the AI agent inherits the same
    // HTTPS-first chain federation uses; v23.12 dropped the implicit
    // http://addr:port+1 attempt that this code used pre-migration.
    let cluster_nodes: Vec<(String, String, Vec<String>)> = {
        let nodes = state.cluster.get_all_nodes();
        nodes.iter()
            .filter(|n| !n.is_self && n.online)
            .map(|n| {
                // The AI agent appends "/api/ai/exec" etc to the base URL,
                // so we strip the path component: build_node_urls with an
                // empty path returns scheme://host:port URLs.
                let urls = build_node_urls(&n.address, n.port, "");
                (n.id.clone(), n.hostname.clone(), urls)
            })
            .collect()
    };

    // The agent's chat() call is the slow path: on a local model (LM Studio,
    // Ollama, llama.cpp) it sends the full tools schema + cluster context and
    // can generate up to 4096 tokens over several round-trips — *minutes* in
    // the wild. Holding one HTTP request open that long is fragile: a reverse
    // proxy that buffers the response (Cloudflare, and any nginx/Caddy/Traefik
    // not explicitly told to stream) sits on every byte until the handler
    // finishes, then either delivers it all at once or — as a tester hit — resets
    // the connection with "Error in input stream". An earlier SSE-heartbeat
    // attempt (v25.1.22) failed for exactly this reason: a buffering proxy
    // swallows the heartbeats, so they never reach the browser (observed TTFB
    // of 5.5 min while the model generated).
    //
    // Robust fix that needs NO cooperation from the proxy: don't hold a long
    // request at all. POST starts the work in a background task and returns a
    // job id immediately (sub-second — nothing buffers a tiny response). The
    // browser then polls GET /api/ai/chat/result with sub-second requests until
    // the job is done. Short requests sail through any proxy untouched.
    prune_ai_chat_jobs();

    let job_id = format!("aichat-{}", uuid::Uuid::new_v4().simple());
    {
        let mut jobs = AI_CHAT_JOBS.lock().unwrap();
        jobs.insert(job_id.clone(), AiChatJob {
            created_at: chrono::Utc::now().timestamp(),
            owner: username.clone(),
            status: AiChatJobStatus::Running,
            response: None,
            actions: None,
            error: None,
        });
    }

    let agent = state.ai_agent.clone();
    let cluster_secret = state.cluster_secret.clone();
    let message = body.message.clone();
    let job_id_task = job_id.clone();
    tokio::spawn(async move {
        let result = agent.chat(&message, &server_context, &cluster_nodes, &cluster_secret).await;
        let mut jobs = AI_CHAT_JOBS.lock().unwrap();
        // The job may have been pruned (>10 min) or evicted; only update if it's
        // still present. Never holds the lock across an await — chat() already
        // finished above.
        if let Some(job) = jobs.get_mut(&job_id_task) {
            match result {
                Ok((response, actions)) => {
                    let actions_json: Vec<serde_json::Value> = actions.iter().map(|a| {
                        serde_json::json!({
                            "id": a.id,
                            "title": a.title,
                            "command": a.command,
                            "risk": a.risk,
                            "explanation": a.explanation,
                            "target": a.node_target,
                        })
                    }).collect();
                    job.response = Some(response);
                    job.actions = Some(actions_json);
                    job.status = AiChatJobStatus::Done;
                }
                Err(e) => {
                    job.error = Some(e);
                    job.status = AiChatJobStatus::Error;
                }
            }
        }
    });

    HttpResponse::Ok().json(serde_json::json!({ "job_id": job_id }))
}

/// In-memory store for async AI chat jobs. The chat agentic loop can run for
/// minutes on a slow local model, so POST /api/ai/chat kicks the work onto a
/// background task and the browser polls GET /api/ai/chat/result for the
/// outcome — see `ai_chat` for why a single long request is unreliable behind a
/// buffering proxy. Ephemeral runtime state (never serialised), so a static map
/// is the right home; entries are pruned after 20 minutes (see
/// `prune_ai_chat_jobs` for why that outlasts the worst-case run).
#[derive(Clone, Copy)]
enum AiChatJobStatus { Running, Done, Error }

struct AiChatJob {
    created_at: i64,
    /// The authenticated identity that created the job (the `require_auth`
    /// username, or "cluster-node" for proxied inter-node requests). The result
    /// poll checks this so one operator can't read another's chat by guessing /
    /// lifting a job id from logs — OWASP A01. UUID v4 ids already make ids
    /// unguessable; this is defence in depth.
    owner: String,
    status: AiChatJobStatus,
    response: Option<String>,
    actions: Option<Vec<serde_json::Value>>,
    error: Option<String>,
}

static AI_CHAT_JOBS: std::sync::LazyLock<std::sync::Mutex<std::collections::HashMap<String, AiChatJob>>> =
    std::sync::LazyLock::new(|| std::sync::Mutex::new(std::collections::HashMap::new()));

/// Drop chat jobs older than 20 minutes so the map can't grow unbounded. The
/// retention window must outlast the worst-case task lifetime — the agentic
/// loop runs up to 3 rounds (src/ai/mod.rs chat()), each capped at the 300s
/// per-request timeout = 900s — plus the frontend's 16-minute poll budget, so a
/// genuinely slow run still has its result waiting when the browser collects
/// it. 1200s clears that with margin.
fn prune_ai_chat_jobs() {
    let cutoff = chrono::Utc::now().timestamp() - 1200;
    let mut jobs = AI_CHAT_JOBS.lock().unwrap();
    jobs.retain(|_, j| j.created_at >= cutoff);
}

/// GET /api/ai/chat/result?id=<job_id> — poll for an async chat result.
/// Returns `{status:"running"}` while the agent works, `{status:"done",
/// response, actions}` on success, `{status:"error", error}` on failure, or
/// `{status:"unknown"}` if the job id isn't found (expired/never existed).
pub async fn ai_chat_result(
    req: HttpRequest, state: web::Data<AppState>,
    query: web::Query<std::collections::HashMap<String, String>>,
) -> HttpResponse {
    let username = match require_auth(&req, &state) {
        Ok(u) => u,
        Err(resp) => return resp,
    };

    let job_id = match query.get("id") {
        Some(id) => id.clone(),
        None => return HttpResponse::BadRequest().json(serde_json::json!({ "error": "Missing id parameter" })),
    };

    let jobs = AI_CHAT_JOBS.lock().unwrap();
    // Scope to the creator: a job belonging to someone else is reported exactly
    // like a non-existent one ("unknown"), never distinguished — so a lifted id
    // leaks neither the response nor the job's existence.
    match jobs.get(&job_id).filter(|job| job.owner == username) {
        Some(job) => match job.status {
            AiChatJobStatus::Running => HttpResponse::Ok().json(serde_json::json!({ "status": "running" })),
            AiChatJobStatus::Done => HttpResponse::Ok().json(serde_json::json!({
                "status": "done",
                "response": job.response.clone().unwrap_or_default(),
                "actions": job.actions.clone().unwrap_or_default(),
            })),
            AiChatJobStatus::Error => HttpResponse::Ok().json(serde_json::json!({
                "status": "error",
                "error": job.error.clone().unwrap_or_else(|| "AI request failed".to_string()),
            })),
        },
        None => HttpResponse::Ok().json(serde_json::json!({ "status": "unknown" })),
    }
}

/// POST /api/ai/action — approve or reject a proposed action.
/// Approve only marks the action as "approved" — it does NOT execute it.
/// The terminal (console.html) fetches the command via GET /api/ai/action/command
/// and sends it to the PTY shell, so the user sees it run live.
#[derive(Deserialize)]
pub struct AiActionRequest {
    pub action_id: String,
    #[serde(default = "default_true")]
    pub approved: bool,
}

fn default_true() -> bool { true }

pub async fn ai_action(
    req: HttpRequest, state: web::Data<AppState>,
    body: web::Json<AiActionRequest>,
) -> HttpResponse {
    let username = match require_auth(&req, &state) {
        Ok(u) => u,
        Err(resp) => return resp,
    };

    if !body.approved {
        match state.ai_agent.reject_action(&body.action_id, &username) {
            Ok(()) => return HttpResponse::Ok().json(serde_json::json!({ "status": "rejected" })),
            Err(e) => return HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
        }
    }

    // Mark as approved (terminal will fetch and execute the command)
    {
        let mut pa = state.ai_agent.pending_actions.lock().unwrap();
        let now = chrono::Utc::now().timestamp();
        if let Some(a) = pa.iter_mut().find(|a| a.id == body.action_id) {
            if a.status != "pending" {
                return HttpResponse::BadRequest().json(serde_json::json!({
                    "error": format!("Action already {}", a.status)
                }));
            }
            if now - a.created_at > 600 {
                a.status = "expired".to_string();
                return HttpResponse::BadRequest().json(serde_json::json!({ "error": "Action expired" }));
            }
            a.status = "approved".to_string();
            a.approved_by = username.clone();
            crate::ai::log_action_audit(a, "approved", &username, "");
            return HttpResponse::Ok().json(serde_json::json!({
                "status": "approved",
                "command": a.command,
            }));
        }
    }

    HttpResponse::NotFound().json(serde_json::json!({ "error": "Action not found" }))
}

/// GET /api/ai/action/command?id=xxx — retrieve the command for an approved action (one-time, for terminal auto-exec)
pub async fn ai_action_command(
    req: HttpRequest, state: web::Data<AppState>,
    query: web::Query<std::collections::HashMap<String, String>>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }

    let action_id = match query.get("id") {
        Some(id) => id.clone(),
        None => return HttpResponse::BadRequest().json(serde_json::json!({"error": "Missing id parameter"})),
    };

    let pa = state.ai_agent.pending_actions.lock().unwrap();
    // Only return command for approved actions (approved by the POST /api/ai/action call)
    match pa.iter().find(|a| a.id == action_id && a.status == "approved") {
        Some(a) => HttpResponse::Ok().json(serde_json::json!({
            "command": a.command,
            "title": a.title,
        })),
        None => HttpResponse::NotFound().json(serde_json::json!({
            "error": "Action not found, not approved, or expired"
        })),
    }
}

/// POST /api/ai/action/exec — execute an approved action command on a remote node (cluster proxy)
pub async fn ai_action_exec(
    req: HttpRequest, state: web::Data<AppState>,
    body: web::Json<AiExecRequest>,
) -> HttpResponse {
    // Only allow inter-node auth (X-WolfStack-Secret) — not browser sessions.
    // Centralised three-way check (in-memory, on-disk, optional default).
    // Pre-fix this endpoint accepted in-memory + default only, missing the
    // on-disk path that covers the rotation transition window AND missing
    // the Stage 5 env-flag gate on default acceptance.
    let secret_header = req.headers().get("X-WolfStack-Secret")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    if !crate::auth::validate_inter_node_secret(secret_header, &state.cluster_secret) {
        return HttpResponse::Forbidden().json(serde_json::json!({"error": "Cluster auth required"}));
    }

    match crate::ai::execute_action_command(&body.command) {
        Ok(output) => HttpResponse::Ok().json(serde_json::json!({ "output": output })),
        Err(e) => HttpResponse::Ok().json(serde_json::json!({ "error": e })),
    }
}

/// POST /api/ai/exec — execute a safe read-only command (used by cluster proxy)
#[derive(Deserialize)]
pub struct AiExecRequest {
    pub command: String,
}

pub async fn ai_exec(
    req: HttpRequest, state: web::Data<AppState>,
    body: web::Json<AiExecRequest>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }

    match crate::ai::execute_safe_command(&body.command) {
        Ok(output) => HttpResponse::Ok().json(serde_json::json!({
            "output": output,
            "exit_code": 0,
        })),
        Err(e) => HttpResponse::Ok().json(serde_json::json!({
            "error": e,
        })),
    }
}

/// GET /api/ai/status — agent status and last health check
/// GET /api/system-check — runs the dependency audit on this node
/// and returns a structured report for the Settings UI.
pub async fn system_check_run(
    req: HttpRequest, state: web::Data<AppState>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let ai_enabled = state.ai_agent.config.lock().unwrap().is_configured();
    // Run both audits off the async executor — they shell out to lsmod,
    // systemctl, docker info, ss, journalctl, pgrep etc. and we don't
    // want actix's async runtime parked on them. Run them in parallel
    // so the user-visible latency matches the slower of the two, not
    // the sum.
    let deps_fut = web::block(crate::systemcheck::run_checks);
    let sec_fut  = web::block(crate::security::run_security_checks);
    let (deps_res, sec_res) = tokio::join!(deps_fut, sec_fut);
    let mut checks = match deps_res {
        Ok(v) => v,
        Err(e) => return HttpResponse::InternalServerError()
            .json(serde_json::json!({ "error": format!("System check failed: {}", e) })),
    };
    // Cluster-scoped checks (cross-node WolfNet IP conflicts) need
    // AppState for the cached remote topologies. Runs synchronously
    // here — cheap because it just reads in-memory topology snapshots.
    let mut cluster_checks = crate::security::run_cluster_checks(&state);
    checks.append(&mut cluster_checks);

    match sec_res {
        Ok(mut v) => checks.append(&mut v),
        Err(e) => {
            // Security scan error doesn't fail the whole endpoint —
            // surface it as a single Warning entry so the user sees
            // why the Security category looks thin. Any other outcome
            // would hide a real issue.
            checks.push(crate::systemcheck::DependencyCheck {
                name: "Security scan errored".into(),
                category: "Security".into(),
                status: crate::systemcheck::DepStatus::Warning,
                version: None,
                detail: format!("Security scan task failed: {}. Non-fatal — dependency checks above are still accurate.", e),
                install_hint: None,
                ai_helpful: false,
                install_package: None,
            });
        }
    }
    HttpResponse::Ok().json(serde_json::json!({
        "checks": checks,
        "ai_enabled": ai_enabled,
        "hostname": hostname::get().ok().and_then(|h| h.into_string().ok()),
    }))
}

/// GET /api/security/secret-audit — lightweight read-only audit of
/// committed-default secrets on this node. Used by:
///   • the dashboard banner (asks once per page load, decides colour)
///   • Settings → Security (renders the full finding list + remediation)
///   • Stage 4 telemetry — the count is folded into the heartbeat
///
/// Returns the same `secret_audit::Finding` shape the scanner uses;
/// the structured JSON lets the frontend present per-finding migration
/// buttons without re-parsing scanner text.
pub async fn secret_audit_get(
    req: HttpRequest, state: web::Data<AppState>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let findings = crate::secret_audit::audit();
    let high_or_above = findings.iter()
        .filter(|f| !matches!(f.severity, crate::secret_audit::Severity::Info))
        .count();
    HttpResponse::Ok().json(serde_json::json!({
        "findings": findings,
        "finding_count": high_or_above,
        "using_default_cluster_secret": crate::secret_audit::is_using_default_cluster_secret(),
    }))
}

/// POST /api/system-check/ask-ai — given a specific failing dependency,
/// ask the AI agent for tailored remediation advice. Body: `{ name, detail, install_hint }`.
#[derive(serde::Deserialize)]
pub struct SystemCheckAskAi {
    pub name: String,
    pub detail: String,
    pub install_hint: Option<String>,
}
pub async fn system_check_ask_ai(
    req: HttpRequest, state: web::Data<AppState>,
    body: web::Json<SystemCheckAskAi>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    if !state.ai_agent.config.lock().unwrap().is_configured() {
        return HttpResponse::BadRequest().json(serde_json::json!({
            "error": "AI agent is not configured — enable it in Settings → AI Agent first"
        }));
    }
    // Include a few lines of host context so the AI gives distro-
    // specific advice. detect_distro() returns an enum with no Display
    // impl so format with {:?}.
    let distro = format!("{:?}", crate::installer::detect_distro());
    let os_release = std::fs::read_to_string("/etc/os-release")
        .unwrap_or_default()
        .lines()
        .filter(|l| l.starts_with("PRETTY_NAME=") || l.starts_with("ID="))
        .collect::<Vec<_>>()
        .join(" | ");
    let prompt = format!(
        "WolfStack system check found a problem with `{}`.\n\
         Detail: {}\n\
         Suggested fix already shown to admin: {}\n\
         Host: {} ({})\n\
         Architecture: {}\n\n\
         Give concrete remediation steps the admin can run *right now*. \
         If the dependency simply isn't supported on this OS/arch, say so clearly \
         and suggest the closest workaround. Keep it short and distro-aware.",
        body.name,
        body.detail,
        body.install_hint.clone().unwrap_or_else(|| "(none)".into()),
        os_release,
        distro,
        std::env::consts::ARCH,
    );
    match state.ai_agent.analyze_issue(&prompt).await {
        Some(advice) => HttpResponse::Ok().json(serde_json::json!({ "advice": advice })),
        None => HttpResponse::InternalServerError().json(serde_json::json!({
            "error": "AI agent did not respond — check provider API key and model in Settings"
        })),
    }
}

pub async fn ai_status(
    req: HttpRequest, state: web::Data<AppState>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let config = state.ai_agent.config.lock().unwrap();
    let last_check = state.ai_agent.last_health_check.lock().unwrap().clone();
    let alert_count = state.ai_agent.alerts.lock().unwrap().len();
    let history_count = state.ai_agent.chat_history.lock().unwrap().len();
    let pending_actions: Vec<serde_json::Value> = {
        let pa = state.ai_agent.pending_actions.lock().unwrap();
        let now = chrono::Utc::now().timestamp();
        pa.iter()
            .filter(|a| a.status == "pending" && (now - a.created_at) < 600)
            .map(|a| serde_json::json!({
                "id": a.id, "title": a.title, "command": a.command,
                "risk": a.risk, "explanation": a.explanation,
                "target": a.node_target, "created_at": a.created_at,
            }))
            .collect()
    };

    HttpResponse::Ok().json(serde_json::json!({
        "configured": config.is_configured(),
        "provider": config.provider,
        "model": config.model,
        "last_health_check": last_check,
        "alert_count": alert_count,
        "chat_message_count": history_count,
        "knowledge_base_size": state.ai_agent.knowledge_base.len(),
        "pending_actions": pending_actions,
    }))
}

/// GET /api/ai/alerts — historical alerts
pub async fn ai_alerts(
    req: HttpRequest, state: web::Data<AppState>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let alerts = state.ai_agent.alerts.lock().unwrap().clone();
    HttpResponse::Ok().json(alerts)
}

/// GET /api/ai/models?provider=claude|gemini — list available models
pub async fn ai_models(
    req: HttpRequest, state: web::Data<AppState>,
    query: web::Query<std::collections::HashMap<String, String>>,
    body: web::Bytes,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let config = state.ai_agent.config.lock().unwrap().clone();
    // Optional POST body: lets the UI pass the selected provider plus a
    // typed-but-not-yet-saved API key so the model dropdown can populate BEFORE
    // the first Save. Without this it's a chicken-and-egg — saving requires a
    // model already chosen, but the model list needs the saved key (the operator
    // could only escape via "Custom…"). The key travels in the body, not the
    // query string (which lands in access logs) nor a custom header (which the
    // node proxy strips when this is fetched against a remote node).
    let body_json: serde_json::Value = if body.is_empty() {
        serde_json::Value::Null
    } else {
        serde_json::from_slice(&body).unwrap_or(serde_json::Value::Null)
    };
    // Reject a masked placeholder (••••…, as returned by GET /api/ai/config) so a
    // mask never reaches the provider as a real key — fall back to the saved key.
    let unsaved_key = body_json.get("api_key").and_then(|v| v.as_str())
        .map(|s| s.trim())
        .filter(|s| !s.is_empty() && !s.contains('\u{2022}'));
    let provider = query.get("provider").map(|s| s.as_str())
        .or_else(|| body_json.get("provider").and_then(|v| v.as_str()))
        .unwrap_or(&config.provider)
        .to_string();

    // Cloudflare Workers AI exposes ~100 models across multiple modalities
    // (chat / embeddings / vision / image / TTS). The `/v1/models` listing
    // is enormous and includes models that aren't chat-completion-compatible,
    // so we return a short curated list of well-known chat models and let
    // the operator type any other model name they want — Workers AI also
    // adds new models faster than we can keep a list up to date.
    if provider == "cloudflare" {
        return HttpResponse::Ok().json(serde_json::json!({
            "models": [
                "@cf/meta/llama-3.1-8b-instruct",
                "@cf/meta/llama-3.1-70b-instruct",
                "@cf/meta/llama-3.2-3b-instruct",
                "@cf/mistralai/mistral-small-3.1-24b-instruct",
                "@cf/qwen/qwen1.5-14b-chat-awq",
                "@cf/google/gemma-7b-it",
            ],
            "note": "Cloudflare Workers AI offers many more models — pick 'Custom…' to type a model ID (e.g. @cf/meta/llama-3.3-70b-instruct-fp8-fast). See https://developers.cloudflare.com/workers-ai/models/"
        }));
    }

    // Local AI: fetch models from the local server's /v1/models endpoint
    if provider == "local" {
        if config.local_url.is_empty() {
            return HttpResponse::Ok().json(serde_json::json!({ "models": ["llama3", "mistral", "codellama", "phi3", "gemma2", "qwen2"], "note": "Enter your local AI URL and save to auto-detect models" }));
        }
        let base = config.local_url.trim_end_matches('/');
        let url = if base.ends_with("/v1") { format!("{}/models", base) } else { format!("{}/v1/models", base) };
        let client = &*API_HTTP_CLIENT;
        let mut req_builder = client.get(&url).timeout(std::time::Duration::from_secs(5));
        if !config.local_api_key.is_empty() {
            req_builder = req_builder.header("Authorization", format!("Bearer {}", config.local_api_key));
        }
        match req_builder.send().await {
            Ok(resp) if resp.status().is_success() => {
                if let Ok(data) = resp.json::<serde_json::Value>().await {
                    let models: Vec<String> = data["data"].as_array()
                        .or_else(|| data["models"].as_array())
                        .map(|arr| arr.iter().filter_map(|m| m["id"].as_str().or_else(|| m["name"].as_str()).or_else(|| m.as_str()).map(|s| s.to_string())).collect())
                        .unwrap_or_default();
                    if !models.is_empty() {
                        return HttpResponse::Ok().json(serde_json::json!({ "models": models }));
                    }
                }
                HttpResponse::Ok().json(serde_json::json!({ "models": ["llama3", "mistral", "codellama"], "note": "Could not parse model list — showing defaults" }))
            }
            Ok(resp) => {
                let status = resp.status();
                let _ = resp.bytes().await;
                HttpResponse::Ok().json(serde_json::json!({ "models": ["llama3", "mistral"], "error": format!("Server returned {}", status) }))
            }
            Err(e) => HttpResponse::Ok().json(serde_json::json!({ "models": ["llama3", "mistral"], "error": format!("Cannot reach {}: {}", url, e) })),
        }
    } else if provider == "claude-cli" {
        // Claude Code CLI has no API key (it uses the local subscription login)
        // — return its curated static model list directly.
        match state.ai_agent.list_models(&provider, "").await {
            Ok(models) => HttpResponse::Ok().json(serde_json::json!({ "models": models })),
            Err(e) => HttpResponse::Ok().json(serde_json::json!({ "models": [], "error": e })),
        }
    } else {
        let saved_key = match provider.as_str() {
            "gemini" => &config.gemini_api_key,
            "openrouter" => &config.openrouter_api_key,
            "openai" => &config.openai_api_key,
            _ => &config.claude_api_key,
        };
        // Prefer a key the operator just typed (POST body) over the saved one so
        // the dropdown loads before the config is persisted.
        let api_key = unsaved_key.unwrap_or(saved_key.as_str());
        if api_key.is_empty() {
            return HttpResponse::Ok().json(serde_json::json!({ "models": [], "error": "No API key configured for this provider" }));
        }
        match state.ai_agent.list_models(&provider, api_key).await {
            Ok(models) => HttpResponse::Ok().json(serde_json::json!({ "models": models })),
            Err(e) => HttpResponse::Ok().json(serde_json::json!({ "models": [], "error": e })),
        }
    }
}

// ─── Networking API ───

/// GET /api/networking/interfaces — list all network interfaces
pub async fn net_list_interfaces(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    HttpResponse::Ok().json(networking::list_interfaces())
}

/// GET /api/networking/dns — get DNS configuration
pub async fn net_get_dns(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    HttpResponse::Ok().json(networking::get_dns())
}

/// GET /api/networking/bridges — list bridges (classified LAN/NAT/empty)
/// plus candidate physical NICs that could be enslaved into a new LAN
/// bridge. Drives the "Create LAN bridge" UI.
pub async fn net_list_bridges(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let bridges = web::block(crate::networking::lan_bridge::classify_bridges).await;
    let nics = web::block(crate::networking::lan_bridge::candidate_nics).await;
    match (bridges, nics) {
        (Ok(bridges), Ok(nics)) => HttpResponse::Ok().json(serde_json::json!({
            "bridges": bridges,
            "nics": nics,
        })),
        _ => HttpResponse::InternalServerError()
            .json(serde_json::json!({ "error": "failed to enumerate bridges/NICs" })),
    }
}

#[derive(Deserialize)]
pub struct LanBridgeCreateRequest {
    pub bridge_name: String,
    pub nic: String,
    #[serde(default)]
    pub accept_risk: bool,
}

/// POST /api/networking/lan-bridge — create a LAN bridge enslaving a
/// physical NIC. The blocking `ip`/`nmcli` work runs on the actix
/// blocking pool. When the chosen NIC is the management NIC, the
/// response carries a `pending_confirm` token that must be POSTed back
/// (see `net_lan_bridge_confirm`) within `rollback_seconds` or the
/// change auto-reverts.
pub async fn net_lan_bridge_create(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<LanBridgeCreateRequest>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let body = body.into_inner();
    let params = crate::networking::lan_bridge::CreateLanBridgeParams {
        bridge_name: body.bridge_name,
        nic: body.nic,
        accept_risk: body.accept_risk,
    };
    match web::block(move || crate::networking::lan_bridge::create_lan_bridge(&params)).await {
        Ok(Ok(outcome)) => HttpResponse::Ok().json(serde_json::json!({
            "message": outcome.message,
            "pending_confirm": outcome.pending_confirm,
            "rollback_seconds": outcome.rollback_seconds,
        })),
        Ok(Err(e)) => HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
        Err(e) => HttpResponse::InternalServerError()
            .json(serde_json::json!({ "error": format!("lan-bridge task: {}", e) })),
    }
}

