// ─── WireGuard Bridge API ───

/// GET /api/networking/wireguard — list all bridges
pub async fn net_wireguard_list(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let bridges = state.wireguard_bridges.read().unwrap();
    let installed = networking::wireguard_installed();
    let list: Vec<serde_json::Value> = bridges.values().map(|b| {
        serde_json::json!({
            "cluster": b.cluster,
            "enabled": b.enabled,
            "listen_port": b.listen_port,
            "public_key": b.public_key,
            "bridge_subnet": b.bridge_subnet(),
            "server_ip": b.server_ip,
            "wolfnet_subnet": b.wolfnet_subnet,
            "interface": b.interface_name(),
            "client_count": b.clients.len(),
        })
    }).collect();
    HttpResponse::Ok().json(serde_json::json!({
        "installed": installed,
        "bridges": list,
    }))
}

/// GET /api/networking/wireguard/{cluster} — get bridge details + clients
pub async fn net_wireguard_get(req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let cluster = path.into_inner();
    let bridges = state.wireguard_bridges.read().unwrap();
    match bridges.get(&cluster) {
        Some(bridge) => {
            let clients: Vec<serde_json::Value> = bridge.clients.iter().map(|c| {
                serde_json::json!({
                    "id": c.id,
                    "name": c.name,
                    "public_key": c.public_key,
                    "assigned_ip": c.assigned_ip,
                    "created_at": c.created_at,
                    "enabled": c.enabled,
                })
            }).collect();
            HttpResponse::Ok().json(serde_json::json!({
                "cluster": bridge.cluster,
                "enabled": bridge.enabled,
                "listen_port": bridge.listen_port,
                "public_key": bridge.public_key,
                "bridge_subnet": bridge.bridge_subnet(),
                "server_ip": bridge.server_ip,
                "wolfnet_subnet": bridge.wolfnet_subnet,
                "interface": bridge.interface_name(),
                "clients": clients,
            }))
        }
        None => HttpResponse::NotFound().json(serde_json::json!({"error": "No bridge for this cluster"})),
    }
}

#[derive(Deserialize)]
pub struct WgInitRequest {
    #[serde(default = "default_wg_port")]
    listen_port: u16,
}
fn default_wg_port() -> u16 { 51820 }

/// POST /api/networking/wireguard/{cluster}/init — initialize bridge
pub async fn net_wireguard_init(req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>, body: web::Json<WgInitRequest>) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let cluster = path.into_inner();
    match networking::init_wireguard_bridge(&cluster, body.listen_port) {
        Ok(bridge) => {
            // Reload the live map from disk (mirrors toggle/delete) so the UI
            // can never diverge from persisted state — the divergence that hid
            // klasSponsor's half-created bridge from the WireGuard UI.
            *state.wireguard_bridges.write().unwrap() = networking::load_wireguard_bridges();
            HttpResponse::Ok().json(serde_json::json!({
                "status": "ok",
                "bridge_subnet": bridge.bridge_subnet(),
                "listen_port": bridge.listen_port,
                "public_key": bridge.public_key,
            }))
        }
        Err(e) => HttpResponse::BadRequest().json(serde_json::json!({"error": e})),
    }
}

#[derive(Deserialize)]
pub struct WgToggleRequest {
    enabled: bool,
}

/// POST /api/networking/wireguard/{cluster}/toggle — enable/disable bridge
pub async fn net_wireguard_toggle(req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>, body: web::Json<WgToggleRequest>) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let cluster = path.into_inner();
    match networking::toggle_wireguard_bridge(&cluster, body.enabled) {
        Ok(msg) => {
            // Reload state
            let fresh = networking::load_wireguard_bridges();
            *state.wireguard_bridges.write().unwrap() = fresh;
            HttpResponse::Ok().json(serde_json::json!({"status": msg}))
        }
        Err(e) => HttpResponse::BadRequest().json(serde_json::json!({"error": e})),
    }
}

/// DELETE /api/networking/wireguard/{cluster} — delete bridge entirely
pub async fn net_wireguard_delete(req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let cluster = path.into_inner();
    match networking::delete_wireguard_bridge(&cluster) {
        Ok(msg) => {
            state.wireguard_bridges.write().unwrap().remove(&cluster);
            HttpResponse::Ok().json(serde_json::json!({"status": msg}))
        }
        Err(e) => HttpResponse::BadRequest().json(serde_json::json!({"error": e})),
    }
}

#[derive(Deserialize)]
pub struct WgAddClientRequest {
    name: String,
}

/// POST /api/networking/wireguard/{cluster}/clients — add client
pub async fn net_wireguard_add_client(req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>, body: web::Json<WgAddClientRequest>) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let cluster = path.into_inner();
    match networking::add_wireguard_client(&cluster, &body.name) {
        Ok((client, conf)) => {
            // Reload state
            let fresh = networking::load_wireguard_bridges();
            *state.wireguard_bridges.write().unwrap() = fresh;
            HttpResponse::Ok().json(serde_json::json!({
                "client": {
                    "id": client.id,
                    "name": client.name,
                    "assigned_ip": client.assigned_ip,
                    "created_at": client.created_at,
                },
                "config": conf,
            }))
        }
        Err(e) => HttpResponse::BadRequest().json(serde_json::json!({"error": e})),
    }
}

/// DELETE /api/networking/wireguard/{cluster}/clients/{id} — remove client
pub async fn net_wireguard_remove_client(req: HttpRequest, state: web::Data<AppState>, path: web::Path<(String, String)>) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let (cluster, client_id) = path.into_inner();
    match networking::remove_wireguard_client(&cluster, &client_id) {
        Ok(msg) => {
            let fresh = networking::load_wireguard_bridges();
            *state.wireguard_bridges.write().unwrap() = fresh;
            HttpResponse::Ok().json(serde_json::json!({"status": msg}))
        }
        Err(e) => HttpResponse::BadRequest().json(serde_json::json!({"error": e})),
    }
}

/// GET /api/networking/wireguard/{cluster}/clients/{id}/config — download client config
pub async fn net_wireguard_client_config(req: HttpRequest, state: web::Data<AppState>, path: web::Path<(String, String)>) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let (cluster, client_id) = path.into_inner();
    match networking::get_client_config(&cluster, &client_id) {
        Ok(conf) => HttpResponse::Ok()
            .content_type("text/plain")
            .insert_header(("Content-Disposition", format!("attachment; filename=\"wg-{}-{}.conf\"", cluster, client_id)))
            .body(conf),
        Err(e) => HttpResponse::NotFound().json(serde_json::json!({"error": e})),
    }
}

// ─── VLAN / vSwitch / Public-IP attachment API ─────────────────────
//
// Backed by `crate::networking::vlan`. Lets the operator add/remove
// 802.1Q VLAN attachments (Hetzner vSwitch, OVH vRack, Equinix Metal,
// generic 802.1Q) and routed extra public IPs without hand-editing
// /etc/network/interfaces.

/// GET /api/networking/vlan — current store + detected network manager.
pub async fn vlan_list(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let store = crate::networking::vlan::VlanStore::load();
    let manager = crate::networking::vlan::detect_net_manager();
    HttpResponse::Ok().json(serde_json::json!({
        "vlans": store.vlans,
        "public_ips": store.public_ips,
        "net_manager": manager,
        "net_manager_label": manager.label(),
        "auto_persist_supported": manager.auto_persist_supported(),
    }))
}

/// POST /api/networking/vlan/attachments — create or update a VLAN
/// attachment. Body is the full `VlanAttachment` (id may be empty for
/// create — server generates one).
///
/// Preflight gate: by default, refuses to save when `preflight` reports
/// any `critical` findings. The frontend calls `/api/networking/vlan/preflight`
/// first, shows the operator the findings, and re-submits with
/// `?ack_critical=true` after they confirm. This is the safety net that
/// stops a typo'd parent NIC or duplicate bridge from silently breaking
/// the operator's network.
#[derive(Deserialize, Default)]
pub struct VlanUpsertQuery {
    #[serde(default)]
    pub ack_critical: bool,
}

pub async fn vlan_upsert(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<crate::networking::vlan::VlanAttachment>,
    query: web::Query<VlanUpsertQuery>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let proposed = body.into_inner();

    // Preflight before we mutate state. Re-run server-side even though
    // the frontend likely already showed the operator the same findings —
    // the host could have changed between preflight and submit.
    let store_for_check = crate::networking::vlan::VlanStore::load();
    let manager = crate::networking::vlan::detect_net_manager();
    let findings = crate::networking::vlan::preflight(&store_for_check, manager, Some(&proposed));
    let critical: Vec<_> = findings.iter()
        .filter(|f| matches!(f.severity, crate::networking::vlan::PreflightSeverity::Critical))
        .cloned()
        .collect();
    if !critical.is_empty() && !query.ack_critical {
        return HttpResponse::Conflict().json(serde_json::json!({
            "error": "preflight reported critical findings; pass ?ack_critical=true to apply anyway",
            "preflight": findings,
        }));
    }

    let mut store = store_for_check;
    let id = match store.upsert_vlan(proposed) {
        Ok(id) => id,
        Err(e) => return HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
    };
    if let Err(e) = store.save() {
        return HttpResponse::InternalServerError().json(serde_json::json!({ "error": e }));
    }
    // Apply immediately so the operator sees the live result. Failures
    // here are surfaced but don't fail the save — the persisted state
    // is still valid and the UI can show what went wrong.
    let report = match crate::networking::vlan::apply(&store) {
        Ok(r) => r,
        Err(e) => return HttpResponse::InternalServerError().json(serde_json::json!({
            "error": format!("saved but apply failed: {}", e),
            "id": id,
            "preflight": findings,
        })),
    };
    HttpResponse::Ok().json(serde_json::json!({
        "id": id,
        "apply": report,
        "preflight": findings,
    }))
}

/// DELETE /api/networking/vlan/attachments/{id} — remove and tear down.
pub async fn vlan_remove(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let id = path.into_inner();
    let mut store = crate::networking::vlan::VlanStore::load();
    let target = store.get_vlan(&id).cloned();
    if !store.remove_vlan(&id) {
        return HttpResponse::NotFound().json(serde_json::json!({
            "error": format!("vlan attachment '{}' not found", id),
        }));
    }
    if let Err(e) = store.save() {
        return HttpResponse::InternalServerError().json(serde_json::json!({ "error": e }));
    }
    // Tear down the kernel state for the removed VLAN before
    // re-applying the rest, so we don't leave orphan devices.
    if let Some(t) = target {
        crate::networking::vlan::teardown_vlan_kernel_state(&t.parent_iface, t.vlan_id, &t.bridge_name);
    }
    let _ = crate::networking::vlan::apply(&store);
    HttpResponse::Ok().json(serde_json::json!({ "removed": true }))
}

/// POST /api/networking/vlan/public-ips — create or update a routed
/// public IP attachment.
pub async fn public_ip_upsert(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<crate::networking::vlan::PublicIpAttachment>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let mut store = crate::networking::vlan::VlanStore::load();
    let id = match store.upsert_public_ip(body.into_inner()) {
        Ok(id) => id,
        Err(e) => return HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
    };
    if let Err(e) = store.save() {
        return HttpResponse::InternalServerError().json(serde_json::json!({ "error": e }));
    }
    let report = match crate::networking::vlan::apply(&store) {
        Ok(r) => r,
        Err(e) => return HttpResponse::InternalServerError().json(serde_json::json!({
            "error": format!("saved but apply failed: {}", e),
            "id": id,
        })),
    };
    HttpResponse::Ok().json(serde_json::json!({ "id": id, "apply": report }))
}

/// DELETE /api/networking/vlan/public-ips/{id} — remove and tear down
/// iptables/lo state for a routed public IP.
pub async fn public_ip_remove(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let id = path.into_inner();
    let mut store = crate::networking::vlan::VlanStore::load();
    let target = store.get_public_ip(&id).cloned();
    if !store.remove_public_ip(&id) {
        return HttpResponse::NotFound().json(serde_json::json!({
            "error": format!("public ip attachment '{}' not found", id),
        }));
    }
    if let Err(e) = store.save() {
        return HttpResponse::InternalServerError().json(serde_json::json!({ "error": e }));
    }
    if let Some(t) = target {
        crate::networking::vlan::teardown_public_ip_kernel_state(&t.ip, &t.container_internal_ip, &t.egress_iface);
    }
    let _ = crate::networking::vlan::apply(&store);
    HttpResponse::Ok().json(serde_json::json!({ "removed": true }))
}

/// POST /api/networking/vlan/apply — re-apply the entire store.
/// Useful as an "I edited the JSON by hand, please reconcile" button
/// or after a fresh boot if persistence wasn't perfect.
pub async fn vlan_apply(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let store = crate::networking::vlan::VlanStore::load();
    match crate::networking::vlan::apply(&store) {
        Ok(report) => HttpResponse::Ok().json(report),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": e })),
    }
}

/// GET /api/networking/vlan/preview — dry-run rendering of the current
/// store. Lets the UI show the operator the config snippet that would
/// be written before they hit save. Now also runs preflight against
/// the live host so the operator sees disruption warnings up-front.
pub async fn vlan_preview(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let store = crate::networking::vlan::VlanStore::load();
    let snippet = crate::networking::vlan::render_ifupdown(&store);
    let manager = crate::networking::vlan::detect_net_manager();
    let preflight = crate::networking::vlan::preflight(&store, manager, None);
    HttpResponse::Ok().json(serde_json::json!({
        "snippet": snippet,
        "manager": manager,
        "preflight": preflight,
    }))
}

/// POST /api/networking/vlan/parse-config — parse a pasted
/// `/etc/network/interfaces` from another server and return any VLAN
/// definitions found. Used by the "import from another server" flow:
/// operator copies a working config from machine A and uses the parsed
/// values as a template for machine B.
#[derive(Deserialize)]
pub struct ParseConfigRequest {
    /// For now, only "ifupdown" is supported. Future: netplan, networkd.
    #[serde(default)]
    pub format: String,
    pub content: String,
}

pub async fn vlan_parse_config(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<ParseConfigRequest>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let body = body.into_inner();
    // Default to ifupdown if format is empty/unknown — that's the only
    // parser we have today and the user's pasting Debian-style config.
    let parsed = if body.format.is_empty() || body.format == "ifupdown" {
        crate::networking::vlan::parse_ifupdown_text(&body.content)
    } else {
        return HttpResponse::BadRequest().json(serde_json::json!({
            "error": format!("unsupported config format '{}'; only 'ifupdown' is supported in this version", body.format),
        }));
    };
    HttpResponse::Ok().json(serde_json::json!({ "parsed": parsed }))
}

/// GET /api/networking/vlan/discover — read kernel state and report
/// any VLAN topologies already configured on this host. Lets the
/// operator import existing config rather than re-creating it (or, in
/// the case of incompatible topologies like vlan-aware bridges, gives
/// them a clear "don't add this through WolfStack, you'd conflict"
/// warning).
// ────────────────────────────────────────────────────────────────────
// Emergency security actions
// ────────────────────────────────────────────────────────────────────

/// POST /api/security/rotate-root-local — rotate THIS node's root
/// password and return the new password to the caller. Designed to be
/// invoked either:
///   - directly by a logged-in operator (via the UI on this node)
///   - by another WolfStack node acting as a fleet-rotation coordinator
///     (via X-WolfStack-Secret auth)
///
/// The password is generated locally with the system CSPRNG. It is
/// also appended to /root/.wolfstack-emergency-passwords.txt (mode
/// 0600) as a belt-and-braces backup in case the UI display fails.
/// Existing SSH sessions for root are killed so any active attacker
/// session drops at the same moment.
pub async fn security_rotate_root_local(
    req: HttpRequest,
    state: web::Data<AppState>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let result = tokio::task::spawn_blocking(crate::security::rotate_local_root).await;
    match result {
        Ok(Ok(pw)) => HttpResponse::Ok().json(serde_json::json!({
            "ok": true,
            "password": pw,
            "hostname": hostname::get()
                .map(|h| h.to_string_lossy().to_string())
                .unwrap_or_default(),
        })),
        Ok(Err(e)) => HttpResponse::InternalServerError().json(serde_json::json!({
            "ok": false,
            "error": e,
        })),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({
            "ok": false,
            "error": format!("rotation task panicked: {}", e),
        })),
    }
}

#[derive(Deserialize)]
pub struct FleetRotateRequest {
    /// Operator typed confirmation phrase — must equal "ROTATE ALL PASSWORDS".
    /// Defense against accidental clicks; the UI requires this be typed
    /// before enabling the submit button.
    pub confirmation: String,
    /// If true, also rotate the coordinator node's own password. Defaults
    /// to true. Set false if the operator wants to rotate peers first
    /// (e.g. they're SSH'd into the coordinator and want to keep that
    /// session alive a bit longer).
    #[serde(default = "default_true_include_self")]
    pub include_self: bool,
}

fn default_true_include_self() -> bool { true }

#[derive(Serialize)]
pub struct FleetRotateNodeResult {
    pub node_id: String,
    pub hostname: String,
    pub address: String,
    pub node_type: String,
    pub status: String,        // "ok" | "failed" | "skipped"
    pub new_password: Option<String>,
    pub error: Option<String>,
}

/// POST /api/security/rotate-fleet — coordinator endpoint. Fans the
/// rotation out to every WolfStack-managed node in the cluster
/// (including this one if include_self=true), collects results, and
/// returns the per-node passwords ONCE. The operator MUST save them
/// immediately — they're not stored anywhere else in WolfStack's state.
///
/// Proxmox-only nodes (where WolfStack isn't installed) are surfaced
/// as "skipped" with a hint that the operator must rotate via the
/// Proxmox UI or SSH.
pub async fn security_rotate_fleet(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<FleetRotateRequest>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let body = body.into_inner();
    if body.confirmation.trim() != "ROTATE ALL PASSWORDS" {
        return HttpResponse::BadRequest().json(serde_json::json!({
            "error": "confirmation phrase must equal 'ROTATE ALL PASSWORDS' exactly",
        }));
    }

    // Snapshot the cluster state so we don't hold the lock across async work.
    let (self_id, nodes) = {
        let n = state.cluster.nodes.read().unwrap();
        (state.cluster.self_id.clone(), n.values().cloned().collect::<Vec<_>>())
    };

    let secret = state.cluster_secret.clone();
    let mut futures = Vec::new();

    for node in nodes {
        let secret_c = secret.clone();
        let self_id_c = self_id.clone();
        let include_self = body.include_self;
        futures.push(async move {
            let is_self = node.id == self_id_c;
            // Proxmox-only nodes can't be remotely rotated by us —
            // surface as skipped with a clear instruction.
            if node.node_type != "wolfstack" {
                return FleetRotateNodeResult {
                    node_id: node.id,
                    hostname: node.hostname,
                    address: node.address,
                    node_type: node.node_type,
                    status: "skipped".into(),
                    new_password: None,
                    error: Some("Proxmox-only node — WolfStack agent not installed. Rotate manually via Proxmox UI or SSH.".into()),
                };
            }
            if is_self && !include_self {
                return FleetRotateNodeResult {
                    node_id: node.id,
                    hostname: node.hostname,
                    address: node.address,
                    node_type: node.node_type,
                    status: "skipped".into(),
                    new_password: None,
                    error: Some("Skipped (include_self=false). Rotate this node manually when ready.".into()),
                };
            }
            // For self, run rotation in-process — avoids the loopback HTTP
            // call and the risk that the coordinator's own SSH session
            // (if any) gets killed before the rotation completes.
            if is_self {
                match tokio::task::spawn_blocking(crate::security::rotate_local_root).await {
                    Ok(Ok(pw)) => FleetRotateNodeResult {
                        node_id: node.id, hostname: node.hostname, address: node.address,
                        node_type: node.node_type, status: "ok".into(),
                        new_password: Some(pw), error: None,
                    },
                    Ok(Err(e)) => FleetRotateNodeResult {
                        node_id: node.id, hostname: node.hostname, address: node.address,
                        node_type: node.node_type, status: "failed".into(),
                        new_password: None, error: Some(e),
                    },
                    Err(e) => FleetRotateNodeResult {
                        node_id: node.id, hostname: node.hostname, address: node.address,
                        node_type: node.node_type, status: "failed".into(),
                        new_password: None,
                        error: Some(format!("panic: {}", e)),
                    },
                }
            } else {
                // Remote peer — call its /api/security/rotate-root-local
                // with the cluster secret using the canonical HTTPS-first
                // chain.
                let urls = build_node_urls(&node.address, node.port, "/api/security/rotate-root-local");
                let client = reqwest::Client::builder()
                    .danger_accept_invalid_certs(true)
                    .timeout(std::time::Duration::from_secs(30))
                    .build();
                let client = match client {
                    Ok(c) => c,
                    Err(e) => return FleetRotateNodeResult {
                        node_id: node.id, hostname: node.hostname, address: node.address,
                        node_type: node.node_type, status: "failed".into(),
                        new_password: None,
                        error: Some(format!("client build: {}", e)),
                    },
                };
                let mut last_err = String::new();
                for url in &urls {
                    let resp = client.post(url)
                        .header("X-WolfStack-Secret", &secret_c)
                        .send().await;
                    match resp {
                        Ok(r) if r.status().is_success() => {
                            if let Ok(j) = r.json::<serde_json::Value>().await {
                                let pw = j.get("password").and_then(|v| v.as_str()).map(|s| s.to_string());
                                return FleetRotateNodeResult {
                                    node_id: node.id, hostname: node.hostname, address: node.address,
                                    node_type: node.node_type, status: "ok".into(),
                                    new_password: pw, error: None,
                                };
                            }
                            last_err = "remote returned 200 but no parseable JSON".into();
                        }
                        Ok(r) => { last_err = format!("HTTP {}", r.status()); }
                        Err(e) => { last_err = format!("transport: {}", e); }
                    }
                }
                FleetRotateNodeResult {
                    node_id: node.id, hostname: node.hostname, address: node.address,
                    node_type: node.node_type, status: "failed".into(),
                    new_password: None,
                    error: Some(format!("all transports failed; last: {}", last_err)),
                }
            }
        });
    }

    let results = futures::future::join_all(futures).await;
    let ok = results.iter().filter(|r| r.status == "ok").count();
    let failed = results.iter().filter(|r| r.status == "failed").count();
    let skipped = results.iter().filter(|r| r.status == "skipped").count();

    HttpResponse::Ok().json(serde_json::json!({
        "summary": format!("{} rotated, {} failed, {} skipped", ok, failed, skipped),
        "results": results,
        "important": "These passwords are NOT stored anywhere in WolfStack. Save them to your password manager immediately. Each node also has a backup at /root/.wolfstack-emergency-passwords.txt (mode 0600).",
    }))
}

// ════════════════════════════════════════════════════════════════════
// Fleet-wide aggregation endpoints — power the Fleet Security page.
// Each endpoint fans out to every WolfStack peer in the cluster,
// collects responses in parallel, and returns a structured per-node
// view that the UI can render as a unified table.
// ════════════════════════════════════════════════════════════════════

#[derive(Serialize)]
pub struct FleetNodeResult<T: Serialize> {
    pub node_id: String,
    pub hostname: String,
    pub address: String,
    pub status: String,        // "ok" | "failed" | "skipped"
    pub data: Option<T>,
    pub error: Option<String>,
}

/// Fan out an authenticated GET to every WolfStack peer (including
/// self) and collect each one's JSON response. Self is handled
/// in-process via the supplied `local` closure to avoid the loopback
/// round-trip.
async fn fleet_fanout_get<T, Local>(
    state: &web::Data<AppState>,
    path: &str,
    local: Local,
) -> Vec<FleetNodeResult<T>>
where
    T: serde::de::DeserializeOwned + Serialize + Send + 'static,
    Local: FnOnce() -> T,
{
    let (self_id, peers) = {
        let n = state.cluster.nodes.read().unwrap();
        let self_id = state.cluster.self_id.clone();
        let peers: Vec<crate::agent::Node> = n.values().cloned().collect();
        (self_id, peers)
    };
    let secret = state.cluster_secret.clone();
    let local_result = std::sync::Mutex::new(Some(local()));
    let mut tasks = Vec::new();
    for node in peers {
        let is_self = node.id == self_id;
        let secret_c = secret.clone();
        let path = path.to_string();
        let local_ref = if is_self {
            let mut g = local_result.lock().unwrap();
            g.take()
        } else { None };
        tasks.push(async move {
            if let Some(data) = local_ref {
                return FleetNodeResult {
                    node_id: node.id, hostname: node.hostname, address: node.address,
                    status: "ok".into(), data: Some(data), error: None,
                };
            }
            if node.node_type != "wolfstack" {
                return FleetNodeResult {
                    node_id: node.id, hostname: node.hostname, address: node.address,
                    status: "skipped".into(), data: None,
                    error: Some("non-WolfStack node".into()),
                };
            }
            let urls = build_node_urls(&node.address, node.port, &path);
            let client = match reqwest::Client::builder()
                .danger_accept_invalid_certs(true)
                .timeout(std::time::Duration::from_secs(8))
                .build() {
                Ok(c) => c,
                Err(e) => return FleetNodeResult {
                    node_id: node.id, hostname: node.hostname, address: node.address,
                    status: "failed".into(), data: None,
                    error: Some(format!("client build: {}", e)),
                },
            };
            // Capture WHY each attempt failed. We collect EVERY url's
            // error rather than overwriting — otherwise the operator
            // only sees the last attempt's failure and the actual root
            // cause on the primary URL (HTTPS) stays hidden.
            let mut errors: Vec<String> = Vec::new();
            for url in &urls {
                let resp = client.get(url).header("X-WolfStack-Secret", &secret_c).send().await;
                match resp {
                    Ok(r) if r.status().is_success() => {
                        match r.json::<T>().await {
                            Ok(v) => return FleetNodeResult {
                                node_id: node.id, hostname: node.hostname, address: node.address,
                                status: "ok".into(), data: Some(v), error: None,
                            },
                            Err(e) => {
                                errors.push(format!("{} -> 200 OK but JSON parse failed: {}", url, e));
                            }
                        }
                    }
                    Ok(r) => {
                        let status = r.status();
                        let body = r.text().await.unwrap_or_default();
                        let preview = body.chars().take(200).collect::<String>();
                        errors.push(format!("{} -> HTTP {}: {}", url, status, preview));
                    }
                    Err(e) => {
                        errors.push(format!("{} -> transport: {}", url, e));
                    }
                }
            }
            FleetNodeResult {
                node_id: node.id, hostname: node.hostname, address: node.address,
                status: "failed".into(), data: None,
                error: Some(errors.join(" | ")),
            }
        });
    }
    futures::future::join_all(tasks).await
}

/// GET /api/fleet/security/lockouts — aggregated blocked-IP view
/// across every WolfStack node in this cluster AND every federated
/// cluster registered here. UI uses this to power the "Fleet blocked
/// IPs" + "Last N blocked" panels on the Fleet Security page. Each
/// federation is fetched in parallel using its stored api_key as a
/// Bearer token; failures are surfaced per-federation so the operator
/// can see which one is unreachable without blocking the whole view.
pub async fn fleet_security_lockouts(
    req: HttpRequest,
    state: web::Data<AppState>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let limiter = state.login_limiter.clone();
    let local = move || {
        serde_json::json!({
            "lockouts": limiter.current_lockouts().into_iter().map(|(ip, secs, user)| {
                serde_json::json!({ "ip": ip, "remaining_seconds": secs, "last_username": user })
            }).collect::<Vec<_>>(),
            "audit": limiter.audit_log(),
            "config": limiter.config(),
        })
    };
    // Cluster fanout: every WolfStack peer in this cluster.
    let cluster_results = fleet_fanout_get::<serde_json::Value, _>(
        &state, "/api/security/auth-lockouts", local,
    ).await;
    // Federation fanout: every registered federation, in parallel.
    let federation_results = fetch_federation_lockouts(&state).await;
    HttpResponse::Ok().json(serde_json::json!({
        "nodes": cluster_results,
        "federations": federation_results,
    }))
}

/// Per-federation lockout snapshot used by `fleet_security_lockouts`.
#[derive(Serialize)]
struct FederationLockoutResult {
    /// Federation identifier (matches the `id` in FederationStore).
    federation_id: String,
    /// Operator-friendly name shown in the UI.
    name: String,
    /// Federation's base URL (informational).
    base_url: String,
    /// "ok" | "failed" — top-level transport status.
    status: String,
    /// Same payload shape as a single cluster node's response:
    /// `{ lockouts: [...], audit: [...], config: {...} }`. None when
    /// status != "ok".
    #[serde(skip_serializing_if = "Option::is_none")]
    data: Option<serde_json::Value>,
    #[serde(skip_serializing_if = "Option::is_none")]
    error: Option<String>,
}

async fn fetch_federation_lockouts(state: &web::Data<AppState>) -> Vec<FederationLockoutResult> {
    let federations: Vec<crate::federation::FederatedCluster> = match state.federations.read() {
        Ok(g) => g.clusters.clone(),
        Err(_) => return Vec::new(),
    };
    if federations.is_empty() { return Vec::new(); }

    let mut tasks = Vec::new();
    for fed in federations {
        tasks.push(async move {
            let client = match reqwest::Client::builder()
                .danger_accept_invalid_certs(fed.insecure_tls)
                .timeout(std::time::Duration::from_secs(8))
                .build()
            {
                Ok(c) => c,
                Err(e) => return FederationLockoutResult {
                    federation_id: fed.id.clone(),
                    name: fed.name.clone(),
                    base_url: fed.base_url.clone(),
                    status: "failed".into(),
                    data: None,
                    error: Some(format!("client build: {}", e)),
                },
            };
            let url = format!("{}/api/security/auth-lockouts",
                fed.base_url.trim_end_matches('/'));
            let resp = client.get(&url)
                .header("Authorization", format!("Bearer {}", fed.api_key))
                .send().await;
            match resp {
                Ok(r) if r.status().is_success() => match r.json::<serde_json::Value>().await {
                    Ok(v) => FederationLockoutResult {
                        federation_id: fed.id.clone(),
                        name: fed.name.clone(),
                        base_url: fed.base_url.clone(),
                        status: "ok".into(),
                        data: Some(v),
                        error: None,
                    },
                    Err(e) => FederationLockoutResult {
                        federation_id: fed.id.clone(),
                        name: fed.name.clone(),
                        base_url: fed.base_url.clone(),
                        status: "failed".into(),
                        data: None,
                        error: Some(format!("200 OK but JSON parse failed: {}", e)),
                    },
                },
                Ok(r) => {
                    let status_code = r.status();
                    let body = r.text().await.unwrap_or_default();
                    FederationLockoutResult {
                        federation_id: fed.id.clone(),
                        name: fed.name.clone(),
                        base_url: fed.base_url.clone(),
                        status: "failed".into(),
                        data: None,
                        error: Some(format!("HTTP {}: {}", status_code,
                            body.chars().take(200).collect::<String>())),
                    }
                }
                Err(e) => FederationLockoutResult {
                    federation_id: fed.id.clone(),
                    name: fed.name.clone(),
                    base_url: fed.base_url.clone(),
                    status: "failed".into(),
                    data: None,
                    error: Some(format!("transport: {}", e)),
                },
            }
        });
    }
    futures::future::join_all(tasks).await
}

/// GET /api/fleet/security/listening-ports — what's listening on
/// 0.0.0.0 across every node. Surfaces internet-exposed services so
/// the operator can see the attack surface at a glance.
pub async fn fleet_security_listening_ports(
    req: HttpRequest,
    state: web::Data<AppState>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let local = move || collect_listening_ports();
    let results = fleet_fanout_get::<serde_json::Value, _>(
        &state, "/api/security/listening-ports-local", local,
    ).await;
    HttpResponse::Ok().json(serde_json::json!({ "nodes": results }))
}

/// GET /api/security/listening-ports-local — node-local listener
/// snapshot. Called by the coordinator via fleet-fanout. Auth: either
/// session or cluster secret.
pub async fn security_listening_ports_local(
    req: HttpRequest,
    state: web::Data<AppState>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    HttpResponse::Ok().json(collect_listening_ports())
}

/// Parse `ss -tlnp` output into a structured per-port view. Filters to
/// listeners on `0.0.0.0` and `::` (publicly-exposed), groups by port,
/// and notes the owning process. Returns an empty list if `ss` isn't
/// available.
fn collect_listening_ports() -> serde_json::Value {
    let out = std::process::Command::new("ss")
        .args(["-tlnp4", "-tlnp6"])
        .output();
    let stdout = match out {
        Ok(o) if o.status.success() => String::from_utf8_lossy(&o.stdout).to_string(),
        _ => return serde_json::json!({ "ports": [], "error": "ss unavailable" }),
    };
    let mut ports: Vec<serde_json::Value> = Vec::new();
    for line in stdout.lines() {
        if !line.starts_with("LISTEN") { continue; }
        let cols: Vec<&str> = line.split_whitespace().collect();
        if cols.len() < 5 { continue; }
        let local_addr = cols[3];
        // Only public listeners — 0.0.0.0:* or [::]:*
        let public = local_addr.starts_with("0.0.0.0:")
            || local_addr.starts_with("*:")
            || local_addr.starts_with("[::]:");
        if !public { continue; }
        let port = local_addr.rsplit(':').next().unwrap_or("?");
        // The process column wraps; collect everything after column 4
        // and parse the "users:((..." segment.
        let proc_col = cols[5..].join(" ");
        let process = proc_col
            .find("\"")
            .and_then(|s| proc_col[s + 1..].find("\"").map(|e| &proc_col[s + 1..s + 1 + e]))
            .unwrap_or("?")
            .to_string();
        ports.push(serde_json::json!({
            "port": port,
            "local_addr": local_addr,
            "process": process,
        }));
    }
    serde_json::json!({ "ports": ports })
}

/// POST /api/fleet/security/push-lockout-policy — write the same
/// lockout config to every WolfStack node. Operator sets the policy
/// once in the UI, we propagate it to all 14.
pub async fn fleet_security_push_lockout_policy(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<crate::auth::LoginLockoutConfig>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let cfg = body.into_inner();

    // Apply locally first.
    if let Err(e) = state.login_limiter.set_config(cfg.clone()) {
        return HttpResponse::InternalServerError().json(serde_json::json!({ "error": e }));
    }

    // Fan out to peers.
    let (self_id, peers) = {
        let n = state.cluster.nodes.read().unwrap();
        let self_id = state.cluster.self_id.clone();
        let peers: Vec<crate::agent::Node> = n.values()
            .filter(|p| p.id != self_id && p.node_type == "wolfstack")
            .cloned()
            .collect();
        (self_id, peers)
    };
    let _ = self_id;
    let secret = state.cluster_secret.clone();
    let client = reqwest::Client::builder()
        .danger_accept_invalid_certs(true)
        .timeout(std::time::Duration::from_secs(8))
        .build()
        .ok();
    let mut node_results: Vec<serde_json::Value> = Vec::new();
    if let Some(client) = client {
        for node in peers {
            let urls = build_node_urls(&node.address, node.port, "/api/security/auth-config");
            let mut ok = false;
            let mut err = String::new();
            for url in &urls {
                let r = client.post(url)
                    .header("X-WolfStack-Secret", &secret)
                    .json(&cfg)
                    .send().await;
                match r {
                    Ok(resp) if resp.status().is_success() => { ok = true; break; }
                    Ok(resp) => { err = format!("HTTP {}", resp.status()); }
                    Err(e) => { err = format!("transport: {}", e); }
                }
            }
            node_results.push(serde_json::json!({
                "node_id": node.id,
                "hostname": node.hostname,
                "address": node.address,
                "ok": ok,
                "error": if ok { String::new() } else { err },
            }));
        }
    }
    HttpResponse::Ok().json(serde_json::json!({
        "ok": true,
        "self_applied": true,
        "peers": node_results,
    }))
}

/// POST /api/fleet/security/force-logout-all — invalidate every active
/// session on every WolfStack node. Use this when you suspect session
/// cookie theft. Operator must re-login everywhere after.
pub async fn fleet_security_force_logout_all(
    req: HttpRequest,
    state: web::Data<AppState>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    // Local destroy: blow away every session in the SessionManager.
    state.sessions.destroy_all();
    // Fan out.
    let (self_id, peers) = {
        let n = state.cluster.nodes.read().unwrap();
        let self_id = state.cluster.self_id.clone();
        let peers: Vec<crate::agent::Node> = n.values()
            .filter(|p| p.id != self_id && p.node_type == "wolfstack")
            .cloned()
            .collect();
        (self_id, peers)
    };
    let _ = self_id;
    let secret = state.cluster_secret.clone();
    let client = reqwest::Client::builder()
        .danger_accept_invalid_certs(true)
        .timeout(std::time::Duration::from_secs(5))
        .build()
        .ok();
    let mut succeeded = 1usize; // self
    let mut failed = 0usize;
    if let Some(client) = client {
        for node in peers {
            let urls = build_node_urls(&node.address, node.port, "/api/security/sessions-destroy-all");
            let mut ok = false;
            for url in &urls {
                let r = client.post(url)
                    .header("X-WolfStack-Secret", &secret)
                    .send().await;
                if matches!(r, Ok(ref resp) if resp.status().is_success()) {
                    ok = true; break;
                }
            }
            if ok { succeeded += 1; } else { failed += 1; }
        }
    }
    HttpResponse::Ok().json(serde_json::json!({
        "ok": true,
        "summary": format!("Destroyed all sessions on {} node(s); {} failed", succeeded, failed),
    }))
}

// ════════════════════════════════════════════════════════════════════
// Fleet-wide cluster-secret rotation
// ════════════════════════════════════════════════════════════════════
//
// The cluster secret is the inter-node auth token. If it leaks (via
// the same path that leaked the root password) every WolfStack-to-
// WolfStack call from anywhere on the internet can impersonate a
// peer. This endpoint generates a new secret, distributes it to every
// peer using the OLD secret (last-time use), each peer writes the new
// value to disk, and returns success. The new secret takes effect
// after the next WolfStack restart on each node — until then the old
// is still active.
//
// Operator must restart WolfStack on every node to fully cut over.
// We surface that explicitly in the response so they don't think it's
// already live.

#[derive(Deserialize)]
pub struct RotateClusterSecretReceiveRequest {
    pub new_secret: String,
}

/// POST /api/security/cluster-secret/receive — peer-callable. Saves
/// the new secret to /etc/wolfstack/cluster-secret. Authenticated via
/// X-WolfStack-Secret using the CURRENT (old) secret — that's the
/// last legitimate use of the old secret before it's superseded.
///
/// Stage 5 fix: pre-Stage-5 this endpoint accepted ONLY the hardcoded
/// default secret, which meant the matching coordinator
/// (`fleet_security_rotate_cluster_secret`) only worked on installs
/// that had never rotated. Now uses the shared three-way validator so
/// the legacy rotation flow works on already-rotated installs too. The
/// helper honours the Stage 5 env flag — operators who set
/// WOLFSTACK_REJECT_DEFAULT_SECRET=1 still get the tighter check here.
pub async fn security_cluster_secret_receive(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<RotateClusterSecretReceiveRequest>,
) -> HttpResponse {
    let presented = req.headers().get("X-WolfStack-Secret")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    if !crate::auth::validate_inter_node_secret(presented, &state.cluster_secret) {
        return HttpResponse::Unauthorized().json(serde_json::json!({
            "error": "invalid cluster secret",
        }));
    }
    let new = body.into_inner().new_secret;
    // Sanity-check format: must start with wsk_ and be reasonable length.
    if !new.starts_with("wsk_") || new.len() < 16 || new.len() > 256 {
        return HttpResponse::BadRequest().json(serde_json::json!({
            "error": "new secret must start with 'wsk_' and be 16-256 chars",
        }));
    }
    // ORDERING: capture OLD on-disk secret before the save so we can
    // re-key this node's own at-rest stores from old→new.
    let old_secret = crate::auth::load_cluster_secret();
    if let Err(e) = crate::auth::save_cluster_secret(&new) {
        return HttpResponse::InternalServerError().json(serde_json::json!({
            "error": e,
        }));
    }
    // Re-key local at-rest secrets (no-op if unchanged). The secret is
    // the at-rest encryption key — without this the node's local SQL /
    // OIDC / integration / DNS / cloud / XO credentials would be
    // undecryptable after its restart.
    let reencrypt = {
        let old = old_secret.clone();
        let new2 = new.clone();
        web::block(move || crate::secret_rotation::reencrypt_all_at_rest(&old, &new2))
            .await.ok()
    };
    // W2 fix: use the actual configured path in the response — pre-fix
    // hardcoded "/etc/wolfstack/cluster-secret" misled operators on
    // installs with paths.json overrides.
    let active_path = crate::paths::get().cluster_secret;
    HttpResponse::Ok().json(serde_json::json!({
        "ok": true,
        "applied_at_restart": true,
        "at_rest_reencrypt": reencrypt,
        "note": format!("Secret written to {}. Restart WolfStack to activate.", active_path),
    }))
}

/// POST /api/fleet/security/rotate-cluster-secret — coordinator
/// endpoint. Generates a new secret, fans out to every peer, returns
/// per-peer status + the new secret value (so the operator can save
/// it — though it's also persisted on every node).
pub async fn fleet_security_rotate_cluster_secret(
    req: HttpRequest,
    state: web::Data<AppState>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    // ORDERING: capture OLD on-disk secret before generating + saving the
    // new one, so we can re-key local at-rest stores from old→new.
    let old_secret = crate::auth::load_cluster_secret();
    let new_secret = crate::auth::generate_cluster_secret();

    // Apply locally first.
    if let Err(e) = crate::auth::save_cluster_secret(&new_secret) {
        return HttpResponse::InternalServerError().json(serde_json::json!({
            "error": format!("local save failed: {}", e),
        }));
    }
    // Re-key local at-rest secrets (no-op if old == new).
    let reencrypt = {
        let old = old_secret.clone();
        let new = new_secret.clone();
        web::block(move || crate::secret_rotation::reencrypt_all_at_rest(&old, &new))
            .await.ok()
    };

    // Fan out to every WolfStack peer using the CURRENT (old) secret.
    // If the old secret has already been compromised AND used to
    // change the secret elsewhere, this fanout would fail — operator
    // would see partial success and need to rotate manually.
    let (self_id, peers) = {
        let n = state.cluster.nodes.read().unwrap();
        let self_id = state.cluster.self_id.clone();
        let peers: Vec<crate::agent::Node> = n.values()
            .filter(|p| p.id != self_id && p.node_type == "wolfstack")
            .cloned()
            .collect();
        (self_id, peers)
    };
    let _ = self_id;
    // Auth the fanout with the IN-MEMORY current secret (the value
    // peers were started with). Pre-fix this used
    // `default_cluster_secret()` which only worked on the first
    // rotation of a never-rotated install — every subsequent rotation
    // failed all peer pushes because they no longer accepted the
    // hardcoded default. `state.cluster_secret` is the value loaded
    // at startup, which IS what each peer currently accepts.
    let old_secret = state.cluster_secret.clone();
    let client = match reqwest::Client::builder()
        .danger_accept_invalid_certs(true)
        .timeout(std::time::Duration::from_secs(8))
        .build()
    {
        Ok(c) => c,
        Err(e) => return HttpResponse::InternalServerError().json(serde_json::json!({
            "error": format!("client build: {}", e),
        })),
    };
    let mut peer_results: Vec<serde_json::Value> = Vec::new();
    for node in peers {
        let urls = build_node_urls(&node.address, node.port, "/api/security/cluster-secret/receive");
        let body = serde_json::json!({ "new_secret": new_secret });
        let mut ok = false;
        let mut err = String::new();
        for url in &urls {
            let r = client.post(url)
                .header("X-WolfStack-Secret", &old_secret)
                .json(&body)
                .send().await;
            match r {
                Ok(resp) if resp.status().is_success() => { ok = true; break; }
                Ok(resp) => { err = format!("HTTP {}", resp.status()); }
                Err(e) => { err = format!("transport: {}", e); }
            }
        }
        peer_results.push(serde_json::json!({
            "node_id": node.id,
            "hostname": node.hostname,
            "address": node.address,
            "ok": ok,
            "error": if ok { String::new() } else { err },
        }));
    }
    let success_count = peer_results.iter().filter(|r| r["ok"].as_bool() == Some(true)).count();
    let fail_count = peer_results.len() - success_count;
    HttpResponse::Ok().json(serde_json::json!({
        "ok": fail_count == 0,
        "new_secret": new_secret,
        "self_applied": true,
        "at_rest_reencrypt": reencrypt,
        "peers": peer_results,
        "summary": format!(
            "Local + {}/{} peer(s) saved the new secret. {} failed. \
             RESTART WOLFSTACK ON EVERY NODE to activate the new secret. \
             Until restart, the OLD secret is still in use.",
            success_count, peer_results.len(), fail_count,
        ),
        "important": "Save the new secret value from this response if you want to keep a copy outside the fleet. WolfStack also persists it to /etc/wolfstack/cluster-secret on every node.",
    }))
}

// ════════════════════════════════════════════════════════════════════
// SSH hardening — fleet-wide push of safe sshd config
// ════════════════════════════════════════════════════════════════════
//
// Writes /etc/ssh/sshd_config.d/00-wolfstack-hardening.conf with the
// settings the operator chose (PasswordAuthentication, PermitRootLogin,
// PubkeyAuthentication). Verifies via `sshd -t` BEFORE reloading; if
// the config is invalid we restore the backup and refuse the change
// rather than risk a broken sshd that locks the operator out.
//
// **CRITICAL SAFETY GUARD**: We refuse to push a config that would
// make the operator unable to log back in. Specifically: if the host
// has NO authorized_keys for any user with a usable shell, we refuse
// to set PasswordAuthentication=no — that would lock everyone out
// permanently. Operator must either add a key first or override the
// safety with `force=true`.

#[derive(Deserialize, Serialize, Clone)]
pub struct SshHardeningConfig {
    /// Set to "no", "yes", or "prohibit-password". Default: prohibit-password.
    #[serde(default = "default_permit_root")]
    pub permit_root_login: String,
    /// "yes" or "no". Default: no.
    #[serde(default = "default_password_auth")]
    pub password_authentication: String,
    /// "yes" or "no". Default: yes (force key-only).
    #[serde(default = "default_pubkey_auth")]
    pub pubkey_authentication: String,
    /// Bypass the "would lock you out" safety check. Use ONLY when you
    /// know what you're doing.
    #[serde(default)]
    pub force: bool,
}

fn default_permit_root() -> String { "prohibit-password".into() }
fn default_password_auth() -> String { "no".into() }
fn default_pubkey_auth() -> String { "yes".into() }

const SSH_HARDENING_PATH: &str = "/etc/ssh/sshd_config.d/00-wolfstack-hardening.conf";

/// POST /api/security/ssh-hardening-local — apply hardening to THIS
/// node. Validates with `sshd -t`, refuses if the change would lock
/// the operator out (no authorized_keys + disabling password auth).
pub async fn security_ssh_hardening_local(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<SshHardeningConfig>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let cfg = body.into_inner();

    // Safety: refuse to disable password auth if there are no SSH keys
    // for any user with a real shell. This is the lock-out guard.
    if cfg.password_authentication == "no" && !cfg.force && !any_authorized_keys_present() {
        return HttpResponse::Conflict().json(serde_json::json!({
            "ok": false,
            "error": "REFUSED: disabling password authentication when no authorized_keys files exist would permanently lock you out. Add an SSH key first OR pass force=true.",
        }));
    }

    let snippet = format!(
        "# Auto-generated by WolfStack — fleet SSH hardening.\n\
         # Edit via Settings → Security → SSH hardening, NOT here.\n\
         PermitRootLogin {}\n\
         PasswordAuthentication {}\n\
         PubkeyAuthentication {}\n\
         ChallengeResponseAuthentication no\n\
         KbdInteractiveAuthentication no\n\
         UsePAM yes\n\
         MaxAuthTries 3\n",
        sanitize_yes_no_or_prohibit(&cfg.permit_root_login, "prohibit-password"),
        sanitize_yes_no(&cfg.password_authentication, "no"),
        sanitize_yes_no(&cfg.pubkey_authentication, "yes"),
    );

    // Backup any existing snippet for rollback.
    let backup = std::fs::read_to_string(SSH_HARDENING_PATH).ok();

    if let Err(e) = std::fs::write(SSH_HARDENING_PATH, &snippet) {
        return HttpResponse::InternalServerError().json(serde_json::json!({
            "ok": false,
            "error": format!("write {}: {}", SSH_HARDENING_PATH, e),
        }));
    }

    // Validate. If `sshd -t` rejects the merged config, restore the
    // backup (or delete the file) and report the error.
    let validate = std::process::Command::new("sshd").arg("-t").output();
    let valid = matches!(validate.as_ref(), Ok(o) if o.status.success());
    if !valid {
        let stderr = validate
            .map(|o| String::from_utf8_lossy(&o.stderr).trim().to_string())
            .unwrap_or_else(|e| format!("sshd spawn: {}", e));
        match backup {
            Some(b) => { let _ = std::fs::write(SSH_HARDENING_PATH, b); }
            None => { let _ = std::fs::remove_file(SSH_HARDENING_PATH); }
        }
        return HttpResponse::InternalServerError().json(serde_json::json!({
            "ok": false,
            "error": format!("sshd -t rejected the new config; rolled back. Error: {}", stderr),
        }));
    }

    // Reload sshd. SIGHUP keeps existing sessions alive, picks up the
    // new config for new connections.
    let reload = std::process::Command::new("systemctl")
        .args(["reload", "ssh"])
        .output();
    let reload_ok = matches!(reload.as_ref(), Ok(o) if o.status.success());
    if !reload_ok {
        // Try the other unit name (Debian uses `ssh`, RHEL uses `sshd`).
        let _ = std::process::Command::new("systemctl")
            .args(["reload", "sshd"])
            .output();
    }
    HttpResponse::Ok().json(serde_json::json!({
        "ok": true,
        "applied": cfg,
        "config_path": SSH_HARDENING_PATH,
    }))
}

fn sanitize_yes_no(v: &str, fallback: &str) -> String {
    match v.trim().to_lowercase().as_str() {
        "yes" => "yes".into(),
        "no" => "no".into(),
        _ => fallback.into(),
    }
}

fn sanitize_yes_no_or_prohibit(v: &str, fallback: &str) -> String {
    match v.trim().to_lowercase().as_str() {
        "yes" => "yes".into(),
        "no" => "no".into(),
        "prohibit-password" | "without-password" => "prohibit-password".into(),
        _ => fallback.into(),
    }
}

/// True iff at least one user with a real shell has a non-empty
/// authorized_keys file. Used by the SSH-hardening lock-out guard.
fn any_authorized_keys_present() -> bool {
    use std::io::BufRead;
    let passwd = match std::fs::File::open("/etc/passwd") {
        Ok(f) => f,
        Err(_) => return true, // can't tell — fail open (don't refuse)
    };
    for line in std::io::BufReader::new(passwd).lines().flatten() {
        let parts: Vec<&str> = line.split(':').collect();
        if parts.len() < 7 { continue; }
        let user = parts[0];
        let home = parts[5];
        let shell = parts[6];
        if !shell.ends_with("sh") { continue; } // skip nologin / false
        let _ = user;
        let path = format!("{}/.ssh/authorized_keys", home);
        if let Ok(meta) = std::fs::metadata(&path) {
            if meta.len() > 0 { return true; }
        }
    }
    // Check /root specifically (might not be in /etc/passwd loop above).
    if let Ok(meta) = std::fs::metadata("/root/.ssh/authorized_keys") {
        if meta.len() > 0 { return true; }
    }
    false
}

/// POST /api/fleet/security/ssh-hardening — push the same SSH
/// hardening config to every WolfStack peer. Each peer applies +
/// validates locally; the response is per-peer success/failure.
pub async fn fleet_security_ssh_hardening(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<SshHardeningConfig>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let cfg = body.into_inner();

    // Apply locally first — if our own config is rejected, abort
    // before touching peers. We invoke security_ssh_hardening_local's
    // logic directly via a synthesised request would be ugly; instead
    // we duplicate the small core: write file + sshd -t.
    // Simplest: serialise the config and POST to ourselves on loopback.
    // Cleaner: extract a helper. Going with the helper.
    if let Err(e) = apply_ssh_hardening_local_inline(&cfg) {
        return HttpResponse::InternalServerError().json(serde_json::json!({
            "ok": false,
            "error": format!("local: {}", e),
        }));
    }

    let (self_id, peers) = {
        let n = state.cluster.nodes.read().unwrap();
        let self_id = state.cluster.self_id.clone();
        let peers: Vec<crate::agent::Node> = n.values()
            .filter(|p| p.id != self_id && p.node_type == "wolfstack")
            .cloned()
            .collect();
        (self_id, peers)
    };
    let _ = self_id;
    let secret = state.cluster_secret.clone();
    let client = match reqwest::Client::builder()
        .danger_accept_invalid_certs(true)
        .timeout(std::time::Duration::from_secs(15))
        .build()
    {
        Ok(c) => c,
        Err(e) => return HttpResponse::InternalServerError().json(serde_json::json!({
            "error": format!("client build: {}", e),
        })),
    };

    let mut peer_results: Vec<serde_json::Value> = Vec::new();
    for node in peers {
        let urls = build_node_urls(&node.address, node.port, "/api/security/ssh-hardening-local");
        let mut ok = false;
        let mut err = String::new();
        for url in &urls {
            let r = client.post(url)
                .header("X-WolfStack-Secret", &secret)
                .json(&cfg)
                .send().await;
            match r {
                Ok(resp) if resp.status().is_success() => { ok = true; break; }
                Ok(resp) => {
                    let status = resp.status();
                    let body = resp.text().await.unwrap_or_default();
                    err = format!("HTTP {}: {}", status, body);
                }
                Err(e) => { err = format!("transport: {}", e); }
            }
        }
        peer_results.push(serde_json::json!({
            "node_id": node.id,
            "hostname": node.hostname,
            "address": node.address,
            "ok": ok,
            "error": if ok { String::new() } else { err },
        }));
    }
    HttpResponse::Ok().json(serde_json::json!({
        "ok": true,
        "self_applied": true,
        "peers": peer_results,
        "applied_config": cfg,
    }))
}

/// Inline copy of the core SSH-hardening logic (write file + sshd -t
/// + reload). Used by both the local endpoint and the fleet endpoint
/// to apply locally without an HTTP round-trip to ourselves.
fn apply_ssh_hardening_local_inline(cfg: &SshHardeningConfig) -> Result<(), String> {
    if cfg.password_authentication == "no" && !cfg.force && !any_authorized_keys_present() {
        return Err("REFUSED: disabling password auth with no SSH keys present would lock you out (pass force=true to override)".into());
    }
    let snippet = format!(
        "# Auto-generated by WolfStack — fleet SSH hardening.\n\
         # Edit via Settings → Security → SSH hardening, NOT here.\n\
         PermitRootLogin {}\n\
         PasswordAuthentication {}\n\
         PubkeyAuthentication {}\n\
         ChallengeResponseAuthentication no\n\
         KbdInteractiveAuthentication no\n\
         UsePAM yes\n\
         MaxAuthTries 3\n",
        sanitize_yes_no_or_prohibit(&cfg.permit_root_login, "prohibit-password"),
        sanitize_yes_no(&cfg.password_authentication, "no"),
        sanitize_yes_no(&cfg.pubkey_authentication, "yes"),
    );
    let backup = std::fs::read_to_string(SSH_HARDENING_PATH).ok();
    std::fs::write(SSH_HARDENING_PATH, &snippet)
        .map_err(|e| format!("write {}: {}", SSH_HARDENING_PATH, e))?;
    let validate = std::process::Command::new("sshd").arg("-t").output();
    if !matches!(validate.as_ref(), Ok(o) if o.status.success()) {
        let stderr = validate
            .map(|o| String::from_utf8_lossy(&o.stderr).trim().to_string())
            .unwrap_or_else(|e| format!("sshd spawn: {}", e));
        match backup {
            Some(b) => { let _ = std::fs::write(SSH_HARDENING_PATH, b); }
            None => { let _ = std::fs::remove_file(SSH_HARDENING_PATH); }
        }
        return Err(format!("sshd -t rejected config (rolled back): {}", stderr));
    }
    let _ = std::process::Command::new("systemctl").args(["reload", "ssh"]).output();
    let _ = std::process::Command::new("systemctl").args(["reload", "sshd"]).output();
    Ok(())
}

