/// POST /api/files/lxc/write — write file inside LXC container
pub async fn files_lxc_write(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<serde_json::Value>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let container = match body.get("container").and_then(|v| v.as_str()) {
        Some(c) => c.to_string(),
        None => return HttpResponse::BadRequest().json(serde_json::json!({ "error": "Missing 'container'" })),
    };
    let path = match body.get("path").and_then(|v| v.as_str()) {
        Some(p) => p.to_string(),
        None => return HttpResponse::BadRequest().json(serde_json::json!({ "error": "Missing 'path'" })),
    };
    let content = match body.get("content").and_then(|v| v.as_str()) {
        Some(c) => c,
        None => return HttpResponse::BadRequest().json(serde_json::json!({ "error": "Missing 'content'" })),
    };
    // Write via lxc-attach using tee
    let mut child = match std::process::Command::new("lxc-attach")
        .args(["-n", &container, "--", "tee", &path])
        .stdin(std::process::Stdio::piped())
        .stdout(std::process::Stdio::null())
        .stderr(std::process::Stdio::piped())
        .spawn()
    {
        Ok(c) => c,
        Err(e) => return HttpResponse::InternalServerError().json(serde_json::json!({ "error": format!("{}", e) })),
    };
    if let Some(mut stdin) = child.stdin.take() {
        use std::io::Write;
        let _ = stdin.write_all(content.as_bytes());
    }
    match child.wait() {
        Ok(status) if status.success() => HttpResponse::Ok().json(serde_json::json!({ "message": "File saved", "path": path })),
        Ok(_) => HttpResponse::BadRequest().json(serde_json::json!({ "error": "lxc-attach write failed" })),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": format!("{}", e) })),
    }
}

/// POST /api/agent/storage/apply — receive and apply a mount config from another node (cluster-auth)
pub async fn agent_storage_apply(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<storage::StorageMount>,
) -> HttpResponse {
    if let Err(e) = require_cluster_auth(&req, &state) { return e; }
    let mut mount = body.into_inner();
    // A global NFS mount whose source points at loopback would, replicated
    // verbatim, make every PEER mount itself — which runs no NFS server, so
    // it errors on every node but the originator (wabil cluster-NFS,
    // 2026-06-16). Rewrite a loopback source host to the sending node's
    // address (the connection source IP — the same req.peer_addr technique
    // the router replication uses) so peers reach the originator's real
    // server. Only loopback hosts are touched, and a loopback source can
    // never work on a peer anyway, so a correctly-addressed mount is never
    // changed.
    if matches!(mount.mount_type, storage::MountType::Nfs) {
        if let Some(sender) = req.peer_addr().map(|a| a.ip()) {
            mount.source = rewrite_loopback_nfs_source(&mount.source, sender);
        }
    }
    // Idempotent upsert (NOT create_mount): a re-synced global mount that
    // already exists on this peer must UPDATE + re-attempt the mount, not
    // fail with "Mount point already in use" before ever creating the dir or
    // mounting (wabil 2026-06-16).
    match storage::apply_replicated_mount(mount) {
        Ok(m) => HttpResponse::Ok().json(serde_json::json!({
            "message": "Mount applied",
            "mount": m
        })),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": e })),
    }
}

/// Rewrite an NFS source's host to `sender` when it points at loopback
/// (`127.0.0.0/8`, `::1`, or `localhost`). NFS sources are `host:/export`;
/// splitting on the first `:/` parses bracketed IPv6 (`[::1]:/p`) and IPv4
/// (`1.2.3.4:/p`) alike. Non-loopback sources are returned unchanged.
fn rewrite_loopback_nfs_source(source: &str, sender: std::net::IpAddr) -> String {
    let (host, path) = match source.trim().split_once(":/") {
        Some((h, p)) => (h, p),
        None => return source.to_string(),
    };
    let hclean = host.trim().trim_start_matches('[').trim_end_matches(']');
    let is_loopback = hclean.eq_ignore_ascii_case("localhost")
        || hclean.parse::<std::net::IpAddr>().map(|ip| ip.is_loopback()).unwrap_or(false);
    if !is_loopback {
        return source.to_string();
    }
    let new_host = match sender {
        std::net::IpAddr::V6(_) => format!("[{}]", sender),
        std::net::IpAddr::V4(_) => sender.to_string(),
    };
    format!("{}:/{}", new_host, path)
}

/// Helper: push a mount config to all remote cluster nodes
async fn sync_mount_to_cluster(
    state: &web::Data<AppState>,
    mount: &storage::StorageMount,
) -> Result<Vec<serde_json::Value>, String> {
    let nodes = state.cluster.get_all_nodes();
    let mut results = Vec::new();

    for node in &nodes {
        // Only WolfStack peers run the storage agent; skip self and
        // Proxmox-only members (they'd just 404).
        if node.is_self || node.node_type != "wolfstack" { continue; }

        // Canonical HTTPS-first URL chain. The old code posted a hardcoded
        // `http://<addr>:<port>` — but peers serve HTTPS on that port (the
        // plaintext second listener was removed), so the request died on the
        // TLS handshake INSTANTLY on every modern peer. The apply was never
        // reached: no mount, no dir, and no entry in the peer's Storage
        // Manager (wabil 2026-06-16). build_node_urls leads with HTTPS, and
        // API_HTTP_CLIENT already accepts the peers' self-signed certs.
        let urls = build_node_urls(&node.address, node.port, "/api/agent/storage/apply");
        let mut applied = false;
        let mut last_status = serde_json::Value::from("error");
        let mut last_response = String::from("no attempts");
        for url in &urls {
            match API_HTTP_CLIENT.post(url)
                .header("X-WolfStack-Secret", &state.cluster_secret)
                .json(mount)
                .timeout(std::time::Duration::from_secs(20)) // apply mounts synchronously
                .send()
                .await
            {
                Ok(resp) => {
                    let status = resp.status();
                    let body = resp.text().await.unwrap_or_default();
                    if status.is_success() {
                        results.push(serde_json::json!({
                            "node": node.hostname, "status": status.as_u16(), "response": body
                        }));
                        applied = true;
                        break;
                    }
                    last_status = serde_json::Value::from(status.as_u16());
                    last_response = format!("{} -> {}", url, body.chars().take(300).collect::<String>());
                }
                Err(e) => {
                    last_status = serde_json::Value::from("error");
                    last_response = format!("{} -> transport: {}", url, e);
                }
            }
        }
        if !applied {
            results.push(serde_json::json!({
                "node": node.hostname, "status": last_status, "response": last_response
            }));
        }
    }

    Ok(results)
}

/// POST /api/upgrade — run the WolfStack upgrade script in the background
// ─── Config Export / Import ───

/// Build the full config-export bundle. Shared by the HTTP export, the daily
/// auto-backup task, and the manual "back up now" action so all three produce
/// identical bundles. PVE API credentials are stripped from the node records
/// (the bundle is a downloadable / on-disk artifact, not the live 0600 config).
pub fn build_config_bundle() -> serde_json::Value {
    let mut bundle = serde_json::Map::new();

    // Helper: read a JSON file and insert into bundle
    fn read_json_file(path: &str) -> Option<serde_json::Value> {
        std::fs::read_to_string(path).ok()
            .and_then(|s| serde_json::from_str(&s).ok())
    }

    // Nodes (cluster links). Strip PVE API credentials before export:
    // nodes.json is stored mode 0600 precisely because each record can embed a
    // peer's pve_token / pve_fingerprint, and an export bundle is a file an
    // operator may hand to support or store off-box. Topology + cluster names
    // restore fine without them; PVE tokens are re-entered after a restore.
    if let Some(mut v) = read_json_file("/etc/wolfstack/nodes.json") {
        if let Some(arr) = v.as_array_mut() {
            for node in arr.iter_mut() {
                if let Some(obj) = node.as_object_mut() {
                    obj.remove("pve_token");
                    obj.remove("pve_fingerprint");
                }
            }
        }
        bundle.insert("nodes".into(), v);
    }
    // AI config
    if let Some(v) = read_json_file("/etc/wolfstack/ai-config.json") {
        bundle.insert("ai_config".into(), v);
    }
    // Storage config
    if let Some(v) = read_json_file("/etc/wolfstack/storage.json") {
        bundle.insert("storage_config".into(), v);
    }
    // Backup config (schedules only — strip entries to keep it small)
    if let Some(v) = read_json_file("/etc/wolfstack/backups.json") {
        if let Some(obj) = v.as_object() {
            let mut cleaned = serde_json::Map::new();
            if let Some(schedules) = obj.get("schedules") {
                cleaned.insert("schedules".into(), schedules.clone());
            }
            bundle.insert("backup_config".into(), serde_json::Value::Object(cleaned));
        }
    }
    // IP mappings
    if let Some(v) = read_json_file(&crate::paths::get().ip_mappings) {
        bundle.insert("ip_mappings".into(), v);
    }
    // PBS config
    if let Some(v) = read_json_file("/etc/wolfstack/pbs/config.json") {
        bundle.insert("pbs_config".into(), v);
    }

    // Metadata
    let hostname = hostname::get()
        .map(|h| h.to_string_lossy().to_string())
        .unwrap_or_else(|_| "unknown".into());
    bundle.insert("exported_from".into(), serde_json::Value::String(hostname));
    bundle.insert("exported_at".into(), serde_json::Value::String(
        chrono::Utc::now().to_rfc3339()
    ));
    bundle.insert("version".into(), serde_json::Value::String(
        env!("CARGO_PKG_VERSION").to_string()
    ));

    serde_json::Value::Object(bundle)
}

/// Export all WolfStack configuration as a downloadable JSON file
pub async fn config_export(
    req: HttpRequest, state: web::Data<AppState>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    HttpResponse::Ok()
        .insert_header(("Content-Type", "application/json"))
        .insert_header(("Content-Disposition", "attachment; filename=\"wolfstack-config.json\""))
        .json(build_config_bundle())
}

/// Import WolfStack configuration from a JSON bundle
pub async fn config_import(
    req: HttpRequest, state: web::Data<AppState>, body: web::Json<serde_json::Value>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }

    let bundle = body.into_inner();
    let obj = match bundle.as_object() {
        Some(o) => o,
        None => return HttpResponse::BadRequest().json(serde_json::json!({
            "error": "Invalid config bundle — expected JSON object"
        })),
    };

    let (imported, errors) = apply_config_bundle(obj, &state);
    HttpResponse::Ok().json(config_import_summary(imported, errors))
}

/// Apply a parsed config bundle to THIS node: merge cluster nodes, overwrite
/// the simple config files, and merge backup schedules. Shared by the HTTP
/// upload-import (`config_import`) and the restore-from-saved-backup endpoint
/// (`config_backup_restore`). Returns (imported_labels, error_labels) so each
/// caller can build its own response. Non-destructive: nodes merge, schedules
/// merge by id; only the simple settings files are overwritten wholesale.
fn apply_config_bundle(
    obj: &serde_json::Map<String, serde_json::Value>,
    state: &web::Data<AppState>,
) -> (Vec<String>, Vec<String>) {
    let mut imported = Vec::new();
    let mut errors = Vec::new();

    // Ensure config dir exists
    let _ = std::fs::create_dir_all("/etc/wolfstack");

    // Import nodes — merge with existing, skip self
    if let Some(nodes_val) = obj.get("nodes") {
        match import_nodes(nodes_val, state) {
            Ok(count) => imported.push(format!("{} nodes", count)),
            Err(e) => errors.push(format!("nodes: {}", e)),
        }
    }

    // Simple file imports
    let file_imports = [
        ("ai_config", "/etc/wolfstack/ai-config.json", "AI config"),
        ("storage_config", "/etc/wolfstack/storage.json", "storage config"),
        ("ip_mappings", "/etc/wolfstack/ip-mappings.json", "IP mappings"),
    ];

    for (key, path, label) in &file_imports {
        if let Some(val) = obj.get(*key) {
            match write_json_file(path, val) {
                Ok(_) => imported.push(label.to_string()),
                Err(e) => errors.push(format!("{}: {}", label, e)),
            }
        }
    }

    // Reload AI config into the running agent so changes take effect immediately
    if obj.contains_key("ai_config") {
        let reloaded = crate::ai::AiConfig::load();
        let mut cfg = state.ai_agent.config.lock().unwrap();
        *cfg = reloaded;
    }

    // Backup config (schedules only)
    if let Some(val) = obj.get("backup_config") {
        // Merge schedules into existing config, keeping existing entries
        let mut config = backup::load_config();
        if let Some(schedules) = val.get("schedules").and_then(|v| v.as_array()) {
            if let Ok(imported_schedules) = serde_json::from_value::<Vec<backup::BackupSchedule>>(
                serde_json::Value::Array(schedules.clone())
            ) {
                let existing_ids: std::collections::HashSet<String> =
                    config.schedules.iter().map(|s| s.id.clone()).collect();
                let mut added = 0;
                for schedule in imported_schedules {
                    if !existing_ids.contains(&schedule.id) {
                        config.schedules.push(schedule);
                        added += 1;
                    }
                }
                if let Err(e) = backup::save_config(&config) {
                    errors.push(format!("backup schedules: {}", e));
                } else {
                    imported.push(format!("{} backup schedules", added));
                }
            }
        }
    }

    // PBS config
    if let Some(val) = obj.get("pbs_config") {
        let _ = std::fs::create_dir_all("/etc/wolfstack/pbs");
        match write_json_file("/etc/wolfstack/pbs/config.json", val) {
            Ok(_) => imported.push("PBS config".into()),
            Err(e) => errors.push(format!("PBS config: {}", e)),
        }
    }

    (imported, errors)
}

/// Build the JSON response body for an import/restore from its result labels.
fn config_import_summary(imported: Vec<String>, errors: Vec<String>) -> serde_json::Value {
    let summary = if errors.is_empty() {
        format!("Successfully imported: {}", imported.join(", "))
    } else {
        format!("Imported: {}. Errors: {}", imported.join(", "), errors.join(", "))
    };
    serde_json::json!({
        "message": summary,
        "imported": imported,
        "errors": errors,
    })
}

/// Write a serde_json::Value to a file as pretty JSON
fn write_json_file(path: &str, val: &serde_json::Value) -> Result<(), String> {
    if let Some(parent) = std::path::Path::new(path).parent() {
        std::fs::create_dir_all(parent)
            .map_err(|e| format!("Failed to create dir: {}", e))?;
    }
    let json = serde_json::to_string_pretty(val)
        .map_err(|e| format!("Failed to serialize: {}", e))?;
    std::fs::write(path, json)
        .map_err(|e| format!("Failed to write {}: {}", path, e))
}

/// Import nodes into the cluster, merging with existing. Returns count of added nodes.
fn import_nodes(nodes_val: &serde_json::Value, state: &web::Data<AppState>) -> Result<usize, String> {
    // nodes.json — and therefore the exported bundle's "nodes" — is a JSON
    // ARRAY of Node (see ClusterState::save_nodes, which serializes
    // `Vec<&Node>`). The old importer parsed it as a map, so EVERY config
    // restore failed on nodes with "invalid type: sequence, expected a map".
    // Accept the array form (the real format); also tolerate a legacy
    // object/map form so a hand-edited bundle still imports.
    let import_nodes: Vec<crate::agent::Node> = match nodes_val {
        serde_json::Value::Array(_) => serde_json::from_value(nodes_val.clone())
            .map_err(|e| format!("Invalid nodes format: {}", e))?,
        serde_json::Value::Object(_) => {
            serde_json::from_value::<std::collections::HashMap<String, crate::agent::Node>>(nodes_val.clone())
                .map_err(|e| format!("Invalid nodes format: {}", e))?
                .into_values()
                .collect()
        }
        _ => return Err("expected an array of nodes".to_string()),
    };

    let self_id = state.cluster.self_id.clone();
    let mut added = 0;

    {
        let mut nodes = state.cluster.nodes.write()
            .map_err(|_| "Failed to acquire lock".to_string())?;
        for mut node in import_nodes {
            // Never import ourselves — match BOTH the local key id and the
            // global self_id the record carries (the exporting node lists us as
            // a peer keyed by our ws-{uuid}).
            if node.id == self_id || node.self_id.as_deref() == Some(self_id.as_str()) {
                continue;
            }
            // Dedup against what we already hold: by local id, by stable global
            // self_id (when present), or by reachable address+port+type. Mirrors
            // the convergence dedup so a restore can't create duplicate records.
            let dup = nodes.values().any(|n| {
                n.id == node.id
                    || (node.self_id.is_some() && n.self_id == node.self_id)
                    // Include pve_node_name in the address key — a multi-node
                    // Proxmox cluster shares one API endpoint address+port but
                    // has a distinct pve_node_name per node. Omitting it (as the
                    // first cut did) would collapse pve2/pve3 into pve1 and
                    // silently drop them. Mirrors add_server_full's dedup.
                    || (n.address == node.address && n.port == node.port
                        && n.node_type == node.node_type
                        && n.pve_node_name == node.pve_node_name)
            });
            if dup {
                continue;
            }
            node.is_self = false;
            node.online = false; // re-confirmed on next poll
            nodes.insert(node.id.clone(), node);
            added += 1;
        }
    }

    // Persist
    state.cluster.save_nodes();

    Ok(added)
}

// ─── Automatic config backups ───
//
// WolfStack snapshots its whole configuration (cluster nodes + AI / storage /
// PBS / IP-mapping settings + backup schedules) to disk once a day, plus on
// demand, so a wiped or garbled config can always be restored from
// Settings → Config Backup. This is exactly the hole the v24.29.x incident
// fell into: the membership list was lost and there was no on-box snapshot to
// roll back to. Bundles are written 0600 (they can embed storage / PBS creds)
// in a 0700 directory; PVE creds are stripped by build_config_bundle.

/// Directory holding on-box config snapshots.
fn config_backup_dir() -> &'static str { "/etc/wolfstack/config-backups" }

/// How many snapshots to keep — older ones are pruned after each new write.
const CONFIG_BACKUP_KEEP: usize = 14;

/// Validate a backup filename (a URL path segment) and resolve it INSIDE the
/// backup dir. Rejects every path-traversal shape (slashes, `..`, leading dot,
/// non-allowlisted chars) so a crafted name can't read/delete arbitrary files.
fn safe_backup_path(name: &str) -> Result<std::path::PathBuf, String> {
    if name.is_empty()
        || name.len() > 128
        || name.contains('/')
        || name.contains('\\')
        || name.contains("..")
        || name.starts_with('.')
        || !name.ends_with(".json")
        || !name.chars().all(|c| c.is_ascii_alphanumeric() || c == '-' || c == '_' || c == '.')
    {
        return Err("invalid backup name".into());
    }
    Ok(std::path::Path::new(config_backup_dir()).join(name))
}

/// List saved config backups newest-first: (filename, size_bytes, mtime_secs).
fn list_config_backups() -> Vec<(String, u64, u64)> {
    let mut out: Vec<(String, u64, u64)> = Vec::new();
    if let Ok(rd) = std::fs::read_dir(config_backup_dir()) {
        for entry in rd.flatten() {
            let name = entry.file_name().to_string_lossy().to_string();
            if !(name.starts_with("wolfstack-config-") && name.ends_with(".json")) {
                continue;
            }
            if let Ok(meta) = entry.metadata() {
                let mtime = meta.modified().ok()
                    .and_then(|t| t.duration_since(std::time::UNIX_EPOCH).ok())
                    .map(|d| d.as_secs())
                    .unwrap_or(0);
                out.push((name, meta.len(), mtime));
            }
        }
    }
    // Newest first. The timestamped name also sorts chronologically, so it's a
    // stable tiebreaker when two files share an mtime second.
    out.sort_by(|a, b| b.2.cmp(&a.2).then_with(|| b.0.cmp(&a.0)));
    out
}

/// Delete all but the newest `keep` snapshots.
fn prune_config_backups(keep: usize) {
    for (name, _, _) in list_config_backups().into_iter().skip(keep) {
        if let Ok(p) = safe_backup_path(&name) {
            let _ = std::fs::remove_file(p);
        }
    }
}

/// Write the current config bundle to a timestamped snapshot, then prune to
/// `CONFIG_BACKUP_KEEP`. Returns the filename written. Sync (file I/O) — call
/// via `web::block` / `spawn_blocking` off the async runtime.
pub fn write_config_backup_now() -> Result<String, String> {
    let dir = config_backup_dir();
    std::fs::create_dir_all(dir).map_err(|e| format!("create dir: {}", e))?;
    // Lock the directory down — snapshots can embed storage / PBS credentials.
    #[cfg(unix)]
    {
        use std::os::unix::fs::PermissionsExt;
        let _ = std::fs::set_permissions(dir, std::fs::Permissions::from_mode(0o700));
    }
    let stamp = chrono::Utc::now().format("%Y%m%d-%H%M%S").to_string();
    let name = format!("wolfstack-config-{}.json", stamp);
    let path = std::path::Path::new(dir).join(&name);
    let json = serde_json::to_string_pretty(&build_config_bundle())
        .map_err(|e| format!("serialize: {}", e))?;
    // 0600 — same sensitivity as the live config files it snapshots.
    crate::paths::write_secure(&path.to_string_lossy(), json)
        .map_err(|e| format!("write: {}", e))?;
    prune_config_backups(CONFIG_BACKUP_KEEP);
    Ok(name)
}

/// Write a daily snapshot if none exists for today (UTC). Returns the name
/// written, or `None` if today's snapshot is already present. Driven by the
/// hourly task in main.rs — the per-day guard makes it at-most-once-per-day
/// and restart-safe.
pub fn maybe_write_daily_config_backup() -> Result<Option<String>, String> {
    let today = chrono::Utc::now().format("%Y%m%d").to_string();
    let prefix = format!("wolfstack-config-{}-", today);
    if list_config_backups().iter().any(|(n, _, _)| n.starts_with(&prefix)) {
        return Ok(None);
    }
    write_config_backup_now().map(Some)
}

/// GET /api/config/backups — list saved config snapshots
pub async fn config_backups_list(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let listed = web::block(list_config_backups).await.unwrap_or_default();
    let backups: Vec<serde_json::Value> = listed.into_iter()
        .map(|(name, size, modified)| serde_json::json!({
            "name": name, "size": size, "modified": modified,
        }))
        .collect();
    HttpResponse::Ok().json(serde_json::json!({ "backups": backups }))
}

/// POST /api/config/backups — create a snapshot now
pub async fn config_backup_create(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    match web::block(write_config_backup_now).await {
        Ok(Ok(name)) => HttpResponse::Ok().json(serde_json::json!({
            "message": format!("Backup created: {}", name), "name": name,
        })),
        Ok(Err(e)) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": e })),
        Err(_) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": "backup task failed" })),
    }
}

/// GET /api/config/backups/{name} — download a saved snapshot
pub async fn config_backup_download(
    req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let name = path.into_inner();
    let p = match safe_backup_path(&name) {
        Ok(p) => p,
        Err(e) => return HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
    };
    match web::block(move || std::fs::read(&p)).await {
        Ok(Ok(bytes)) => HttpResponse::Ok()
            .insert_header(("Content-Type", "application/json"))
            // name is allowlisted to [A-Za-z0-9._-] above, so it's safe in the header.
            .insert_header(("Content-Disposition", format!("attachment; filename=\"{}\"", name)))
            .body(bytes),
        _ => HttpResponse::NotFound().json(serde_json::json!({ "error": "backup not found" })),
    }
}

/// DELETE /api/config/backups/{name} — delete a saved snapshot
pub async fn config_backup_delete(
    req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let name = path.into_inner();
    let p = match safe_backup_path(&name) {
        Ok(p) => p,
        Err(e) => return HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
    };
    match web::block(move || std::fs::remove_file(&p)).await {
        Ok(Ok(())) => HttpResponse::Ok().json(serde_json::json!({ "message": format!("Deleted {}", name) })),
        _ => HttpResponse::NotFound().json(serde_json::json!({ "error": "backup not found" })),
    }
}

/// POST /api/config/backups/{name}/restore — restore a saved snapshot onto this node
pub async fn config_backup_restore(
    req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }
    let name = path.into_inner();
    let p = match safe_backup_path(&name) {
        Ok(p) => p,
        Err(e) => return HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
    };
    let data = match web::block(move || std::fs::read_to_string(&p)).await {
        Ok(Ok(d)) => d,
        _ => return HttpResponse::NotFound().json(serde_json::json!({ "error": "backup not found" })),
    };
    let bundle: serde_json::Value = match serde_json::from_str(&data) {
        Ok(v) => v,
        Err(e) => return HttpResponse::BadRequest().json(serde_json::json!({
            "error": format!("backup is not valid JSON: {}", e)
        })),
    };
    let obj = match bundle.as_object() {
        Some(o) => o,
        None => return HttpResponse::BadRequest().json(serde_json::json!({
            "error": "backup is not a config bundle object"
        })),
    };
    let (imported, errors) = apply_config_bundle(obj, &state);
    HttpResponse::Ok().json(config_import_summary(imported, errors))
}

/// Path the web-triggered upgrade streams its stdout+stderr to. The
/// previous run is overwritten (the most recent failure is what an
/// operator wants to inspect; older runs aren't useful). Permissions are
/// 0644 so an operator can `cat` it without sudo. NEVER under /var/lib —
/// `/var/lib/wolfstack` is on the OnAccessExcludePath list and we want
/// this log scannable by clamav.
const UPGRADE_LOG_PATH: &str = "/var/log/wolfstack-upgrade.log";
const UPGRADE_LOG_MAX_RETURN_BYTES: usize = 256 * 1024;

/// POST /api/upgrade — run the WolfStack upgrade script in the background
/// Optional query param: ?channel=beta (defaults to master)
pub async fn system_upgrade(
    req: HttpRequest, state: web::Data<AppState>,
    query: web::Query<std::collections::HashMap<String, String>>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }

    let channel = query.get("channel").map(|s| s.as_str()).unwrap_or("master");
    let (branch, flag) = if channel == "beta" { ("beta", " --beta") } else { ("master", "") };

    // WolfStack itself runs as root (needs /etc/shadow for auth — see
    // CLAUDE.md), so the `sudo` that used to live here was redundant
    // AND broke on minimal Proxmox installs which don't ship sudo by
    // default (customer report 2026-05-25: NyvenZA's Proxmox box logs
    // in as root and has no sudo binary, so `curl | sudo bash` errored
    // with "sudo: command not found"). Pipe straight to bash — we're
    // already root.
    let cmd = format!(
        "curl -sSL https://raw.githubusercontent.com/wolfsoftwaresystemsltd/WolfStack/{}/setup.sh | bash -s --{}",
        branch, flag
    );

    // Truncate + write a header line so the operator sees what kicked
    // off this upgrade run even before setup.sh starts producing output.
    // Then re-open in append mode and hand the file to the child as
    // stdout+stderr. Previous-run output is discarded on every new
    // upgrade — the most recent failure is what matters; older runs are
    // noise.
    use std::io::Write;
    {
        let mut hdr = match std::fs::OpenOptions::new()
            .create(true).write(true).truncate(true)
            .open(UPGRADE_LOG_PATH)
        {
            Ok(f) => f,
            Err(e) => {
                error!("Failed to create upgrade log {}: {}", UPGRADE_LOG_PATH, e);
                return HttpResponse::InternalServerError().json(serde_json::json!({
                    "error": format!("Failed to create {}: {}", UPGRADE_LOG_PATH, e)
                }));
            }
        };
        let _ = writeln!(
            hdr,
            "=== WolfStack upgrade started {} (channel={}, branch={}) ===\n$ {}\n",
            chrono::Utc::now().to_rfc3339(), channel, branch, cmd,
        );
        // 0644 so the operator can `cat` without sudo; the log doesn't
        // contain secrets — only setup.sh output and apt progress.
        #[cfg(unix)]
        {
            use std::os::unix::fs::PermissionsExt;
            let _ = hdr.set_permissions(std::fs::Permissions::from_mode(0o644));
        }
    }
    let log_for_stdout = match std::fs::OpenOptions::new()
        .append(true).open(UPGRADE_LOG_PATH)
    {
        Ok(f) => f,
        Err(e) => {
            error!("Failed to reopen upgrade log {} for append: {}", UPGRADE_LOG_PATH, e);
            return HttpResponse::InternalServerError().json(serde_json::json!({
                "error": format!("Failed to open {} for streaming: {}", UPGRADE_LOG_PATH, e)
            }));
        }
    };
    let log_for_stderr = match log_for_stdout.try_clone() {
        Ok(f) => f,
        Err(e) => {
            error!("Failed to dup upgrade log fd: {}", e);
            return HttpResponse::InternalServerError().json(serde_json::json!({
                "error": format!("Failed to dup log fd: {}", e)
            }));
        }
    };

    // Spawn the upgrade script as a detached background process with
    // stdout+stderr captured to UPGRADE_LOG_PATH. The child inherits the
    // file descriptors, so output continues to land even after this
    // handler returns and the WolfStack binary restarts mid-upgrade
    // (setup.sh runs as a child of init, file descriptors survive).
    match std::process::Command::new("bash")
        .args(["-c", &cmd])
        .stdin(std::process::Stdio::null())
        .stdout(std::process::Stdio::from(log_for_stdout))
        .stderr(std::process::Stdio::from(log_for_stderr))
        .spawn()
    {
        Ok(_) => HttpResponse::Ok().json(serde_json::json!({
            "message": format!("Upgrade started ({} channel) — WolfStack will restart automatically when complete.", branch),
            "log_path": UPGRADE_LOG_PATH,
            "log_url": "/api/upgrade/log",
        })),
        Err(e) => {
            error!("Failed to start upgrade: {}", e);
            // Surface the spawn failure to the log file too so even
            // a /api/upgrade/log poll sees it.
            if let Ok(mut f) = std::fs::OpenOptions::new().append(true).open(UPGRADE_LOG_PATH) {
                let _ = writeln!(f, "=== ERROR: failed to spawn upgrade: {} ===", e);
            }
            HttpResponse::InternalServerError().json(serde_json::json!({
                "error": format!("Failed to start upgrade: {}", e),
                "log_path": UPGRADE_LOG_PATH,
            }))
        }
    }
}

/// GET /api/upgrade/log — return the tail of the upgrade log so the
/// operator can see what setup.sh / apt produced without ssh'ing in.
/// Returns the LAST `UPGRADE_LOG_MAX_RETURN_BYTES` bytes — big enough
/// for a full setup.sh run, small enough that the UI doesn't choke.
/// Optional query param `?tail=N` (bytes) overrides, capped at 4 MB.
pub async fn system_upgrade_log(
    req: HttpRequest, state: web::Data<AppState>,
    query: web::Query<std::collections::HashMap<String, String>>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }

    let tail_bytes: usize = query.get("tail")
        .and_then(|s| s.parse::<usize>().ok())
        .map(|n| n.min(4 * 1024 * 1024))
        .unwrap_or(UPGRADE_LOG_MAX_RETURN_BYTES);

    let path = std::path::Path::new(UPGRADE_LOG_PATH);
    if !path.exists() {
        return HttpResponse::Ok().json(serde_json::json!({
            "exists": false,
            "path": UPGRADE_LOG_PATH,
            "message": "No upgrade has been run via the web interface on this node yet.",
            "content": "",
            "size_bytes": 0,
            "truncated": false,
        }));
    }

    let size_bytes = std::fs::metadata(path).map(|m| m.len() as usize).unwrap_or(0);
    let content = match std::fs::read(path) {
        Ok(bytes) => {
            let start = bytes.len().saturating_sub(tail_bytes);
            // UTF-8 boundary safety: if we landed mid-codepoint, walk
            // forward to the next start byte (top bits 0x.. or 0b10..
            // are continuation bytes — skip them).
            let mut safe_start = start;
            while safe_start < bytes.len() && (bytes[safe_start] & 0xC0) == 0x80 {
                safe_start += 1;
            }
            String::from_utf8_lossy(&bytes[safe_start..]).to_string()
        }
        Err(e) => {
            return HttpResponse::InternalServerError().json(serde_json::json!({
                "error": format!("Failed to read {}: {}", UPGRADE_LOG_PATH, e)
            }));
        }
    };

    let mtime_rfc3339 = std::fs::metadata(path).ok()
        .and_then(|m| m.modified().ok())
        .map(|t| chrono::DateTime::<chrono::Utc>::from(t).to_rfc3339());

    HttpResponse::Ok().json(serde_json::json!({
        "exists": true,
        "path": UPGRADE_LOG_PATH,
        "content": content,
        "size_bytes": size_bytes,
        "truncated": size_bytes > content.len(),
        "modified_at": mtime_rfc3339,
    }))
}

// ─── WolfFlow Workflow Automation API ───

/// GET /api/wolfflow/workflows — list workflows
pub async fn wolfflow_list(req: HttpRequest, state: web::Data<AppState>, query: web::Query<std::collections::HashMap<String, String>>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let cluster = query.get("cluster").map(|s| s.as_str());
    HttpResponse::Ok().json(state.wolfflow.list_workflows(cluster))
}

/// POST /api/wolfflow/workflows — create workflow
pub async fn wolfflow_create(req: HttpRequest, state: web::Data<AppState>, body: web::Json<serde_json::Value>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    match serde_json::from_value::<crate::wolfflow::Workflow>(body.into_inner()) {
        Ok(mut wf) => {
            if wf.id.is_empty() { wf.id = format!("wf-{:x}", std::time::SystemTime::now().duration_since(std::time::UNIX_EPOCH).unwrap().as_millis()); }
            if wf.created_at.is_empty() { wf.created_at = chrono::Utc::now().to_rfc3339(); }
            wf.updated_at = chrono::Utc::now().to_rfc3339();
            let created = state.wolfflow.create_workflow(wf);
            HttpResponse::Ok().json(created)
        }
        Err(e) => HttpResponse::BadRequest().json(serde_json::json!({ "error": format!("Invalid workflow: {}", e) })),
    }
}

/// GET /api/wolfflow/workflows/{id}
pub async fn wolfflow_get(req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    match state.wolfflow.get_workflow(&path.into_inner()) {
        Some(wf) => HttpResponse::Ok().json(wf),
        None => HttpResponse::NotFound().json(serde_json::json!({ "error": "Workflow not found" })),
    }
}

/// PUT /api/wolfflow/workflows/{id}
pub async fn wolfflow_update(req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>, body: web::Json<serde_json::Value>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    match serde_json::from_value::<crate::wolfflow::Workflow>(body.into_inner()) {
        Ok(mut wf) => {
            wf.updated_at = chrono::Utc::now().to_rfc3339();
            match state.wolfflow.update_workflow(&path.into_inner(), wf) {
                Some(updated) => HttpResponse::Ok().json(updated),
                None => HttpResponse::NotFound().json(serde_json::json!({ "error": "Workflow not found" })),
            }
        }
        Err(e) => HttpResponse::BadRequest().json(serde_json::json!({ "error": format!("Invalid workflow: {}", e) })),
    }
}

/// DELETE /api/wolfflow/workflows/{id}
pub async fn wolfflow_delete(req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    match state.wolfflow.delete_workflow(&path.into_inner()) {
        Some(_) => HttpResponse::Ok().json(serde_json::json!({ "ok": true })),
        None => HttpResponse::NotFound().json(serde_json::json!({ "error": "Workflow not found" })),
    }
}

/// POST /api/wolfflow/workflows/{id}/run — manually trigger a workflow
pub async fn wolfflow_trigger(req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let id = path.into_inner();
    let workflow = match state.wolfflow.get_workflow(&id) {
        Some(wf) => wf,
        None => return HttpResponse::NotFound().json(serde_json::json!({ "error": "Workflow not found" })),
    };
    let wf_state = state.wolfflow.clone();
    let cluster = state.cluster.clone();
    let secret = state.cluster_secret.clone();
    let ai_config = state.ai_agent.config.lock().unwrap().clone();
    tokio::spawn(async move {
        crate::wolfflow::execute_workflow(&wf_state, &cluster, &secret, &workflow, "manual", Some(ai_config)).await;
    });
    HttpResponse::Ok().json(serde_json::json!({ "ok": true, "message": "Workflow triggered" }))
}

/// GET /api/wolfflow/runs — list execution history
pub async fn wolfflow_runs_list(req: HttpRequest, state: web::Data<AppState>, query: web::Query<std::collections::HashMap<String, String>>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let wf_id = query.get("workflow_id").map(|s| s.as_str());
    let limit = query.get("limit").and_then(|s| s.parse().ok()).unwrap_or(50);
    let mut runs = state.wolfflow.list_runs(wf_id);
    runs.reverse(); // newest first
    runs.truncate(limit);
    HttpResponse::Ok().json(runs)
}

/// GET /api/wolfflow/runs/{id}
pub async fn wolfflow_run_detail(req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let id = path.into_inner();
    let runs = state.wolfflow.list_runs(None);
    match runs.into_iter().find(|r| r.id == id) {
        Some(run) => HttpResponse::Ok().json(run),
        None => HttpResponse::NotFound().json(serde_json::json!({ "error": "Run not found" })),
    }
}

/// GET /api/wolfflow/toolbox — list available actions
pub async fn wolfflow_toolbox(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    HttpResponse::Ok().json(crate::wolfflow::toolbox_actions())
}

/// GET /api/wolfflow/infrastructure — returns the full infrastructure tree for target selection
/// Clusters → Nodes → Docker containers, LXC containers, VMs
pub async fn wolfflow_infrastructure(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }

    let nodes = state.cluster.get_all_nodes();
    let cluster_secret = state.cluster_secret.clone();
    let http_client = &*API_HTTP_CLIENT;

    let mut clusters: std::collections::HashMap<String, Vec<serde_json::Value>> = std::collections::HashMap::new();

    for node in &nodes {
        // Skip legacy Proxmox-API-only entries — they're surfaced via the deprecation banner.
        if node.node_type == "proxmox" { continue; }

        let cluster_name = node.cluster_name.clone()
            .unwrap_or_else(|| "Default".to_string());

        let mut node_data = serde_json::json!({
            "id": node.id,
            "hostname": node.hostname,
            "address": node.address,
            "port": node.port,
            "online": node.online,
            "node_type": node.node_type,
            "is_self": node.is_self,
            "docker": [],
            "lxc": [],
            "vms": [],
        });

        // Fetch containers for online nodes
        if node.online && node.node_type == "wolfstack" {
            let urls = build_node_urls(&node.address, node.port, "/api/containers/docker");
            for url in &urls {
                if let Ok(resp) = http_client.get(url)
                    .timeout(std::time::Duration::from_secs(5))
                    .header("X-WolfStack-Secret", &cluster_secret)
                    .send().await
                {
                    if let Ok(containers) = resp.json::<Vec<serde_json::Value>>().await {
                        node_data["docker"] = serde_json::json!(containers.iter().map(|c| {
                            serde_json::json!({
                                "name": c.get("name").and_then(|v| v.as_str()).unwrap_or("?"),
                                "state": c.get("state").and_then(|v| v.as_str()).unwrap_or("?"),
                            })
                        }).collect::<Vec<_>>());
                        break;
                    }
                }
            }
            let urls = build_node_urls(&node.address, node.port, "/api/containers/lxc");
            for url in &urls {
                if let Ok(resp) = http_client.get(url)
                    .timeout(std::time::Duration::from_secs(5))
                    .header("X-WolfStack-Secret", &cluster_secret)
                    .send().await
                {
                    if let Ok(containers) = resp.json::<Vec<serde_json::Value>>().await {
                        node_data["lxc"] = serde_json::json!(containers.iter().map(|c| {
                            serde_json::json!({
                                "name": c.get("name").and_then(|v| v.as_str()).unwrap_or("?"),
                                "state": c.get("state").and_then(|v| v.as_str()).unwrap_or("?"),
                            })
                        }).collect::<Vec<_>>());
                        break;
                    }
                }
            }
            let urls = build_node_urls(&node.address, node.port, "/api/vms");
            for url in &urls {
                if let Ok(resp) = http_client.get(url)
                    .timeout(std::time::Duration::from_secs(5))
                    .header("X-WolfStack-Secret", &cluster_secret)
                    .send().await
                {
                    if let Ok(vms) = resp.json::<Vec<serde_json::Value>>().await {
                        node_data["vms"] = serde_json::json!(vms.iter().map(|v| {
                            serde_json::json!({
                                "name": v.get("name").and_then(|v| v.as_str()).unwrap_or("?"),
                                "state": if v.get("running").and_then(|v| v.as_bool()).unwrap_or(false) { "running" } else { "stopped" },
                            })
                        }).collect::<Vec<_>>());
                        break;
                    }
                }
            }
        } else if node.online && node.node_type == "proxmox" {
            // PVE nodes — fetch guests
            // PVE guests fetched via the local /pve/resources endpoint below
            let pve_url = format!("/api/nodes/{}/pve/resources", node.id);
            if let Ok(resp) = http_client.get(&format!("https://{}:{}{}", "127.0.0.1", 8553, pve_url))
                .timeout(std::time::Duration::from_secs(5))
                .header("X-WolfStack-Secret", &cluster_secret)
                .send().await
            {
                if let Ok(guests) = resp.json::<Vec<serde_json::Value>>().await {
                    let lxc: Vec<_> = guests.iter()
                        .filter(|g| g.get("guest_type").and_then(|v| v.as_str()) == Some("lxc"))
                        .map(|g| serde_json::json!({
                            "name": g.get("name").and_then(|v| v.as_str()).unwrap_or("?"),
                            "state": g.get("status").and_then(|v| v.as_str()).unwrap_or("?"),
                        }))
                        .collect();
                    let vms: Vec<_> = guests.iter()
                        .filter(|g| g.get("guest_type").and_then(|v| v.as_str()) == Some("qemu"))
                        .map(|g| serde_json::json!({
                            "name": g.get("name").and_then(|v| v.as_str()).unwrap_or("?"),
                            "state": g.get("status").and_then(|v| v.as_str()).unwrap_or("?"),
                        }))
                        .collect();
                    node_data["lxc"] = serde_json::json!(lxc);
                    node_data["vms"] = serde_json::json!(vms);
                }
            }
        }

        clusters.entry(cluster_name).or_default().push(node_data);
    }

    HttpResponse::Ok().json(clusters)
}

/// POST /api/wolfflow/exec — execute a single action (used by remote execution)
pub async fn wolfflow_exec(req: HttpRequest, state: web::Data<AppState>, body: web::Json<serde_json::Value>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    match serde_json::from_value::<crate::wolfflow::ActionType>(body.into_inner()) {
        Ok(action) => {
            match crate::wolfflow::execute_action_local(&action).await {
                Ok(output) => HttpResponse::Ok().json(serde_json::json!({ "ok": true, "output": output })),
                Err(err) => HttpResponse::Ok().json(serde_json::json!({ "ok": false, "output": err })),
            }
        }
        Err(e) => HttpResponse::BadRequest().json(serde_json::json!({ "error": format!("Invalid action: {}", e) })),
    }
}

/// POST /api/wolfflow/container-exec — execute an action inside a specific container (cluster proxy)
pub async fn wolfflow_container_exec(req: HttpRequest, state: web::Data<AppState>, body: web::Json<serde_json::Value>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let data = body.into_inner();
    let action_val = data.get("action").cloned().unwrap_or(serde_json::Value::Null);
    let ct_val = data.get("container").cloned().unwrap_or(serde_json::Value::Null);

    let action: crate::wolfflow::ActionType = match serde_json::from_value(action_val) {
        Ok(a) => a,
        Err(e) => return HttpResponse::BadRequest().json(serde_json::json!({ "error": format!("Invalid action: {}", e) })),
    };
    let ct: crate::wolfflow::ContainerTarget = match serde_json::from_value(ct_val) {
        Ok(c) => c,
        Err(e) => return HttpResponse::BadRequest().json(serde_json::json!({ "error": format!("Invalid container target: {}", e) })),
    };

    match crate::wolfflow::execute_action_in_container(&action, &ct).await {
        Ok(output) => HttpResponse::Ok().json(serde_json::json!({ "ok": true, "output": output.text })),
        Err(err) => HttpResponse::Ok().json(serde_json::json!({ "ok": false, "error": err })),
    }
}

/// POST /api/wolfflow/all-containers-exec — execute an action inside all containers on this node (cluster proxy)
pub async fn wolfflow_all_containers_exec(req: HttpRequest, state: web::Data<AppState>, body: web::Json<serde_json::Value>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    match serde_json::from_value::<crate::wolfflow::ActionType>(body.into_inner()) {
        Ok(action) => {
            match crate::wolfflow::execute_in_all_local_containers(&action).await {
                Ok(output) => HttpResponse::Ok().json(serde_json::json!({ "ok": true, "output": output.text })),
                Err(err) => HttpResponse::Ok().json(serde_json::json!({ "ok": false, "error": err })),
            }
        }
        Err(e) => HttpResponse::BadRequest().json(serde_json::json!({ "error": format!("Invalid action: {}", e) })),
    }
}

// ─── User Preferences API ───

fn user_prefs_path(username: &str) -> Option<String> {
    // Sanitize username — no dots (prevents ../ traversal), no slashes
    let safe: String = username.chars()
        .map(|c| if c.is_alphanumeric() || c == '-' || c == '_' { c } else { '_' })
        .collect();
    if safe.is_empty() || safe == "cluster-node" { return None; }
    let path = format!("{}/user-prefs/{}.json", crate::paths::get().config_dir, safe);
    // Verify the path is under the expected directory
    let expected_dir = format!("{}/user-prefs/", crate::paths::get().config_dir);
    if !path.starts_with(&expected_dir) { return None; }
    Some(path)
}

/// GET /api/user/preferences — load the current user's preferences
pub async fn user_prefs_get(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    let username = match require_auth(&req, &state) {
        Ok(u) => u,
        Err(resp) => return resp,
    };

    let path = match user_prefs_path(&username) {
        Some(p) => p,
        None => return HttpResponse::Forbidden().json(serde_json::json!({ "error": "Not a user account" })),
    };
    match std::fs::read_to_string(&path) {
        Ok(data) => {
            match serde_json::from_str::<serde_json::Value>(&data) {
                Ok(prefs) => HttpResponse::Ok().json(prefs),
                Err(_) => HttpResponse::Ok().json(serde_json::json!({})),
            }
        }
        Err(_) => HttpResponse::Ok().json(serde_json::json!({})),
    }
}

/// POST /api/user/preferences — save the current user's preferences (full replace)
pub async fn user_prefs_save(req: HttpRequest, state: web::Data<AppState>, body: web::Json<serde_json::Value>) -> HttpResponse {
    let username = match require_auth(&req, &state) {
        Ok(u) => u,
        Err(resp) => return resp,
    };

    let path = match user_prefs_path(&username) {
        Some(p) => p,
        None => return HttpResponse::Forbidden().json(serde_json::json!({ "error": "Not a user account" })),
    };
    let dir = std::path::Path::new(&path).parent().unwrap_or(std::path::Path::new("/tmp"));
    if let Err(e) = std::fs::create_dir_all(dir) {
        return HttpResponse::InternalServerError().json(serde_json::json!({ "error": format!("Failed to create dir: {}", e) }));
    }

    // Limit size to prevent abuse (64 KB should be plenty for preferences)
    let json = serde_json::to_string_pretty(&body.into_inner()).unwrap_or_default();
    if json.len() > 65536 {
        return HttpResponse::BadRequest().json(serde_json::json!({ "error": "Preferences too large (max 64 KB)" }));
    }

    match std::fs::write(&path, &json) {
        Ok(_) => HttpResponse::Ok().json(serde_json::json!({ "ok": true })),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": format!("Failed to save: {}", e) })),
    }
}

/// PATCH /api/user/preferences — merge specific keys into existing preferences
pub async fn user_prefs_patch(req: HttpRequest, state: web::Data<AppState>, body: web::Json<serde_json::Value>) -> HttpResponse {
    let username = match require_auth(&req, &state) {
        Ok(u) => u,
        Err(resp) => return resp,
    };

    let path = match user_prefs_path(&username) {
        Some(p) => p,
        None => return HttpResponse::Forbidden().json(serde_json::json!({ "error": "Not a user account" })),
    };
    let dir = std::path::Path::new(&path).parent().unwrap_or(std::path::Path::new("/tmp"));
    let _ = std::fs::create_dir_all(dir);

    // Load existing
    let mut prefs: serde_json::Map<String, serde_json::Value> = std::fs::read_to_string(&path)
        .ok()
        .and_then(|d| serde_json::from_str(&d).ok())
        .unwrap_or_default();

    // Merge incoming keys
    if let Some(obj) = body.as_object() {
        for (k, v) in obj {
            if v.is_null() {
                prefs.remove(k);
            } else {
                prefs.insert(k.clone(), v.clone());
            }
        }
    }

    let json = serde_json::to_string_pretty(&prefs).unwrap_or_default();
    if json.len() > 65536 {
        return HttpResponse::BadRequest().json(serde_json::json!({ "error": "Preferences too large" }));
    }

    match std::fs::write(&path, &json) {
        Ok(_) => HttpResponse::Ok().json(serde_json::json!({ "ok": true })),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": format!("Failed to save: {}", e) })),
    }
}

/// GET /api/ping — lightweight liveness probe for the frontend connection
/// monitor. Auth-required so the client can distinguish three states: 200 =
/// reachable + session valid, 401 = reachable but session gone (→ login),
/// network error = server unreachable (→ "connection lost" banner). Does no
/// work beyond the auth check so it's cheap to poll every few seconds.
pub async fn ping(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    HttpResponse::Ok().json(serde_json::json!({ "ok": true }))
}

// ─── Per-user interface lock (idle lock + PIN) ───
//
// A soft, client-enforced screen lock: after `idle_minutes` of inactivity
// the dashboard covers itself and asks for a PIN. This is a "stop a random
// passer-by getting into an unattended session" deterrent, NOT a hard
// access control — a technical user with devtools can bypass a client-side
// overlay. The PIN itself, though, is treated as a credential: it's stored
// only as a salted SHA-256 hash in a per-user file that the prefs GET never
// returns, and it's verified server-side with a small delay on failure to
// slow guessing. The watchful eye of the lock — like Durin's Gate, it opens
// only to the one who knows the word.

/// Per-user lock profile path. Separate from `user_prefs_path` so the PIN
/// hash is never served by the preferences GET. Same sanitisation +
/// traversal guard as the prefs path.
fn user_lock_path(username: &str) -> Option<String> {
    let safe: String = username.chars()
        .map(|c| if c.is_alphanumeric() || c == '-' || c == '_' { c } else { '_' })
        .collect();
    if safe.is_empty() || safe == "cluster-node" { return None; }
    let path = format!("{}/user-prefs/{}.lock.json", crate::paths::get().config_dir, safe);
    let expected_dir = format!("{}/user-prefs/", crate::paths::get().config_dir);
    if !path.starts_with(&expected_dir) { return None; }
    Some(path)
}

#[derive(serde::Serialize, serde::Deserialize, Default)]
struct UserLockProfile {
    #[serde(default)]
    enabled: bool,
    #[serde(default)]
    idle_minutes: u32,
    #[serde(default)]
    pin_salt: String,
    #[serde(default)]
    pin_hash: String,
}

fn load_user_lock(path: &str) -> UserLockProfile {
    std::fs::read_to_string(path).ok()
        .and_then(|d| serde_json::from_str(&d).ok())
        .unwrap_or_default()
}

/// Salted SHA-256 of the PIN. Salt is per-PIN-set, so the same PIN on two
/// accounts (or reset on the same account) yields a different hash.
fn hash_user_pin(salt: &str, pin: &str) -> String {
    use sha2::Digest;
    let digest = sha2::Sha256::digest(format!("{}:{}", salt, pin).as_bytes());
    digest.iter().map(|b| format!("{:02x}", b)).collect()
}

fn random_lock_salt() -> String {
    use rand::RngCore;
    let mut bytes = [0u8; 16];
    rand::thread_rng().fill_bytes(&mut bytes);
    bytes.iter().map(|b| format!("{:02x}", b)).collect()
}

/// Constant-time comparison so a failed verify doesn't leak how many
/// leading hex chars matched via timing.
fn ct_eq(a: &[u8], b: &[u8]) -> bool {
    if a.len() != b.len() { return false; }
    let mut diff = 0u8;
    for (x, y) in a.iter().zip(b.iter()) { diff |= x ^ y; }
    diff == 0
}

/// GET /api/user/lock — the current user's idle-lock settings. Never
/// returns the salt or hash; `pin_set` is the only PIN signal.
pub async fn user_lock_get(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    let username = match require_auth(&req, &state) {
        Ok(u) => u,
        Err(resp) => return resp,
    };
    let path = match user_lock_path(&username) {
        Some(p) => p,
        None => return HttpResponse::Forbidden().json(serde_json::json!({ "error": "Not a user account" })),
    };
    let lock = load_user_lock(&path);
    HttpResponse::Ok().json(serde_json::json!({
        "username": username,
        "enabled": lock.enabled,
        "idle_minutes": if lock.idle_minutes == 0 { 10 } else { lock.idle_minutes },
        "pin_set": !lock.pin_hash.is_empty(),
    }))
}

#[derive(serde::Deserialize)]
pub struct UserLockUpdate {
    enabled: Option<bool>,
    idle_minutes: Option<u32>,
    /// `Some(non-empty)` sets a new PIN; `Some("")` clears it; `None` leaves
    /// the existing PIN untouched.
    pin: Option<String>,
}

/// POST /api/user/lock — update idle-lock settings and/or the PIN.
pub async fn user_lock_save(req: HttpRequest, state: web::Data<AppState>, body: web::Json<UserLockUpdate>) -> HttpResponse {
    let username = match require_auth(&req, &state) {
        Ok(u) => u,
        Err(resp) => return resp,
    };
    let path = match user_lock_path(&username) {
        Some(p) => p,
        None => return HttpResponse::Forbidden().json(serde_json::json!({ "error": "Not a user account" })),
    };
    if let Some(dir) = std::path::Path::new(&path).parent() {
        let _ = std::fs::create_dir_all(dir);
    }

    let mut lock = load_user_lock(&path);
    let update = body.into_inner();

    if let Some(en) = update.enabled { lock.enabled = en; }
    if let Some(m) = update.idle_minutes { lock.idle_minutes = m.clamp(1, 240); }
    match update.pin.as_deref() {
        Some(p) if !p.is_empty() => {
            if p.len() < 4 || p.len() > 12 || !p.chars().all(|c| c.is_ascii_digit()) {
                return HttpResponse::BadRequest().json(serde_json::json!({ "error": "PIN must be 4–12 digits" }));
            }
            let salt = random_lock_salt();
            lock.pin_hash = hash_user_pin(&salt, p);
            lock.pin_salt = salt;
        }
        Some(_) => {
            // Explicit empty string = clear the PIN. Without a PIN there's
            // nothing to unlock with, so the lock must also turn off.
            lock.pin_hash.clear();
            lock.pin_salt.clear();
            lock.enabled = false;
        }
        None => {}
    }
    // Can't arm a lock with no PIN to unlock it.
    if lock.enabled && lock.pin_hash.is_empty() {
        return HttpResponse::BadRequest().json(serde_json::json!({ "error": "Set a PIN before enabling the lock" }));
    }
    if lock.idle_minutes == 0 { lock.idle_minutes = 10; }

    let json = serde_json::to_string_pretty(&lock).unwrap_or_default();
    match std::fs::write(&path, &json) {
        Ok(_) => HttpResponse::Ok().json(serde_json::json!({
            "ok": true,
            "enabled": lock.enabled,
            "idle_minutes": lock.idle_minutes,
            "pin_set": !lock.pin_hash.is_empty(),
        })),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": format!("Failed to save: {}", e) })),
    }
}

/// POST /api/user/lock/verify — check a PIN to lift the lock. Returns
/// `{ ok: bool }`. A 300 ms delay on failure rate-limits brute force.
pub async fn user_lock_verify(req: HttpRequest, state: web::Data<AppState>, body: web::Json<serde_json::Value>) -> HttpResponse {
    let username = match require_auth(&req, &state) {
        Ok(u) => u,
        Err(resp) => return resp,
    };
    let path = match user_lock_path(&username) {
        Some(p) => p,
        None => return HttpResponse::Forbidden().json(serde_json::json!({ "error": "Not a user account" })),
    };
    let lock = load_user_lock(&path);
    // No PIN configured → nothing to verify against, treat as unlocked.
    if lock.pin_hash.is_empty() {
        return HttpResponse::Ok().json(serde_json::json!({ "ok": true }));
    }
    let pin = body.get("pin").and_then(|v| v.as_str()).unwrap_or("");
    let candidate = hash_user_pin(&lock.pin_salt, pin);
    let ok = ct_eq(candidate.as_bytes(), lock.pin_hash.as_bytes());
    if !ok {
        // Async sleep — never block the runtime thread (see CLAUDE.md).
        tokio::time::sleep(std::time::Duration::from_millis(300)).await;
    }
    HttpResponse::Ok().json(serde_json::json!({ "ok": ok }))
}

