/// Parse human-readable size strings (e.g. "1.2G", "450M", "32K") to MB
fn parse_size_to_mb(s: &str) -> f64 {
    let s = s.trim();
    if s.is_empty() { return 0.0; }
    let (num_str, suffix) = if s.ends_with(|c: char| c.is_alphabetic()) {
        let idx = s.len() - 1;
        (&s[..idx], &s[idx..])
    } else {
        (s, "")
    };
    let num: f64 = num_str.parse().unwrap_or(0.0);
    match suffix.to_uppercase().as_str() {
        "T" => num * 1024.0 * 1024.0,
        "G" => num * 1024.0,
        "M" => num,
        "K" => num / 1024.0,
        "B" => num / (1024.0 * 1024.0),
        _ => num, // assume MB
    }
}

#[derive(Serialize, Clone)]
pub struct Issue {
    pub severity: String,   // "critical", "warning", "info"
    pub category: String,   // "cpu", "memory", "disk", "swap", "load", "service", "container"
    pub title: String,
    pub detail: String,
}

/// A one-click recovery the operator can run from the issues page for a
/// fixable issue. `kind` selects the server-side recipe; `target` is the
/// concrete thing it acts on (a systemd unit, or a fixed token like
/// "journal"); `label` is the button text. Computed per-issue at scan
/// time by [`repair_for`] rather than stored on every `Issue`, so the
/// ~18 existing issue producers stay untouched.
#[derive(Serialize, Clone)]
pub struct IssueRepair {
    pub kind: String,    // "service" | "clamav" | "chkrootkit" | "certbot" | "journal" | "apt" | "dnf"
    pub target: String,  // unit name, or a fixed token for disk-cleanup kinds
    pub label: String,   // button text: "Repair" | "Clean"
}

/// Classify a failed systemd unit into the repair recipe that actually
/// recovers it. Service-specific where it matters, generic otherwise.
fn repair_kind_for_unit(unit: &str) -> &'static str {
    let u = unit.to_ascii_lowercase();
    if u.contains("clamav") || u.contains("freshclam") {
        "clamav"
    } else if u.contains("chkrootkit") {
        "chkrootkit"
    } else if u.contains("certbot") || u.contains("letsencrypt") {
        "certbot"
    } else {
        "service"
    }
}

/// Given an issue, return the repair the operator can run for it — or
/// None when there's no safe one-click action (CPU/RAM/load/swap, k8s
/// pods, and /tmp are deliberately excluded: /tmp may stage malware, so
/// it's never auto-cleaned). Service units are parsed from the issue's
/// `detail` ("systemd unit X is in failed state") and re-validated by
/// `valid_unit_name`; the disk-cleanup kinds key off the `title` prefix
/// (they carry no unit). Both couplings fail closed — if a producer string
/// in `collect_issues` is reworded, the button simply doesn't appear
/// rather than misfiring.
pub fn repair_for(issue: &Issue) -> Option<IssueRepair> {
    match issue.category.as_str() {
        "service" => {
            let unit = issue.detail
                .strip_prefix("systemd unit ")
                .and_then(|s| s.strip_suffix(" is in failed state"))
                .map(|s| s.trim())
                .filter(|s| valid_unit_name(s))?;
            Some(IssueRepair {
                kind: repair_kind_for_unit(unit).to_string(),
                target: unit.to_string(),
                label: "Repair".into(),
            })
        }
        "disk" => {
            // Only the three caches we know how to clean safely.
            let (kind, target) = if issue.title.starts_with("Journal logs using") {
                ("journal", "journal")
            } else if issue.title.starts_with("APT cache") {
                ("apt", "apt")
            } else if issue.title.starts_with("DNF cache") {
                ("dnf", "dnf")
            } else {
                return None; // /tmp, low-disk warnings: no blind one-click
            };
            Some(IssueRepair { kind: kind.into(), target: target.into(), label: "Clean".into() })
        }
        _ => None,
    }
}

/// Collect system issues (reusable — called by HTTP handler and background scheduler)
pub fn collect_issues(metrics: &crate::monitoring::SystemMetrics) -> Vec<Issue> {
    let mut issues: Vec<Issue> = Vec::new();
    let mem_pct = metrics.memory_percent;

    // ── CPU check ──
    if metrics.cpu_usage_percent > 90.0 {
        issues.push(Issue {
            severity: "critical".into(),
            category: "cpu".into(),
            title: "CPU usage critically high".into(),
            detail: format!("CPU at {:.1}% — system may be unresponsive", metrics.cpu_usage_percent),
        });
    } else if metrics.cpu_usage_percent > 75.0 {
        issues.push(Issue {
            severity: "warning".into(),
            category: "cpu".into(),
            title: "CPU usage elevated".into(),
            detail: format!("CPU at {:.1}% — monitor for sustained load", metrics.cpu_usage_percent),
        });
    }

    // ── Memory check ──
    if mem_pct > 90.0 {
        issues.push(Issue {
            severity: "critical".into(),
            category: "memory".into(),
            title: "Memory usage critically high".into(),
            detail: format!("Memory at {:.1}% — OOM risk", mem_pct),
        });
    } else if mem_pct > 80.0 {
        issues.push(Issue {
            severity: "warning".into(),
            category: "memory".into(),
            title: "Memory usage elevated".into(),
            detail: format!("Memory at {:.1}%", mem_pct),
        });
    }

    // ── Disk checks (free space, not just %) ──
    for disk in &metrics.disks {
        // Skip /boot/ and /etc/pve mounts unless >99% — managed by the OS/Proxmox
        if (disk.mount_point.starts_with("/boot") || disk.mount_point == "/etc/pve") && disk.usage_percent <= 99.0 {
            continue;
        }

        let total_gb = disk.total_bytes as f64 / 1_073_741_824.0;
        let used_gb = disk.used_bytes as f64 / 1_073_741_824.0;
        let free_gb = disk.available_bytes as f64 / 1_073_741_824.0;
        let size_detail = format!("{} — {:.1} GB used / {:.1} GB total ({:.1} GB free, {:.1}%)",
            disk.mount_point, used_gb, total_gb, free_gb, disk.usage_percent);

        if free_gb < 2.0 {
            issues.push(Issue {
                severity: "critical".into(),
                category: "disk".into(),
                title: format!("Disk {} almost full ({:.1} GB free)", disk.mount_point, free_gb),
                detail: size_detail,
            });
        } else if free_gb < 10.0 {
            issues.push(Issue {
                severity: "warning".into(),
                category: "disk".into(),
                title: format!("Disk {} low on space ({:.1} GB free)", disk.mount_point, free_gb),
                detail: size_detail,
            });
        }
    }

    // ── Swap check ──
    if metrics.swap_total_bytes > 0 {
        let swap_pct = (metrics.swap_used_bytes as f64 / metrics.swap_total_bytes as f64) * 100.0;
        if swap_pct > 50.0 {
            issues.push(Issue {
                severity: "warning".into(),
                category: "swap".into(),
                title: "Significant swap usage".into(),
                detail: format!("Swap at {:.1}% — system may be low on RAM", swap_pct),
            });
        }
    }

    // ── Load average check ──
    let cpu_count = metrics.cpu_count.max(1) as f64;
    if metrics.load_avg.one > cpu_count * 2.0 {
        issues.push(Issue {
            severity: "critical".into(),
            category: "load".into(),
            title: "Load average extremely high".into(),
            detail: format!("Load {:.2} ({:.1}× CPU count {})", metrics.load_avg.one, metrics.load_avg.one / cpu_count, metrics.cpu_count),
        });
    } else if metrics.load_avg.one > cpu_count {
        issues.push(Issue {
            severity: "warning".into(),
            category: "load".into(),
            title: "Load average high".into(),
            detail: format!("Load {:.2} (>{} CPUs)", metrics.load_avg.one, metrics.cpu_count),
        });
    }

    // ── Failed systemd services ──
    if let Ok(output) = std::process::Command::new("systemctl")
        .args(["--failed", "--no-legend", "--plain"])
        .output()
    {
        let stdout = String::from_utf8_lossy(&output.stdout);
        for line in stdout.lines() {
            let parts: Vec<&str> = line.split_whitespace().collect();
            if let Some(unit) = parts.first() {
                if !unit.is_empty() {
                    issues.push(Issue {
                        severity: "warning".into(),
                        category: "service".into(),
                        title: format!("Service {} failed", unit),
                        detail: format!("systemd unit {} is in failed state", unit),
                    });
                }
            }
        }
    }

    // ── Stopped Docker containers ──
    if let Ok(output) = std::process::Command::new("docker")
        .args(["ps", "-a", "--filter", "status=exited", "--format", "{{.Names}}"])
        .output()
    {
        let stdout = String::from_utf8_lossy(&output.stdout);
        let stopped: Vec<&str> = stdout.lines().filter(|l| !l.is_empty()).collect();
        if !stopped.is_empty() {
            issues.push(Issue {
                severity: "info".into(),
                category: "container".into(),
                title: format!("{} stopped Docker container(s)", stopped.len()),
                detail: format!("Stopped: {}", stopped.join(", ")),
            });
        }
    }

    // ── Kubernetes cluster issues ──
    let k8s_clusters = crate::kubernetes::list_clusters();
    for cluster in &k8s_clusters {
        let status = crate::kubernetes::get_cluster_status(&cluster.kubeconfig_path);
        if !status.healthy {
            issues.push(Issue {
                severity: "warning".into(),
                category: "kubernetes".into(),
                title: format!("K8s cluster '{}' unhealthy", cluster.name),
                detail: format!("{}/{} nodes ready, {}/{} pods running",
                    status.nodes_ready, status.nodes_total,
                    status.pods_running, status.pods_total),
            });
        }

        // Check for NotReady nodes
        let nodes = crate::kubernetes::get_nodes(&cluster.kubeconfig_path);
        for n in &nodes {
            if n.status != "Ready" {
                issues.push(Issue {
                    severity: "critical".into(),
                    category: "kubernetes".into(),
                    title: format!("K8s node '{}' not ready", n.name),
                    detail: format!("Cluster '{}', status: {}, role: {}", cluster.name, n.status, n.roles),
                });
            }
        }

        // Check for problem pods (exclude Succeeded/Completed pods — these are finished Jobs/init containers)
        let pods = crate::kubernetes::get_pods(&cluster.kubeconfig_path, None);
        let active_pods: Vec<_> = pods.iter().filter(|p| p.status != "Succeeded").collect();
        let failed = active_pods.iter().filter(|p| p.status == "Failed" || p.status == "Unknown").count();
        let pending = active_pods.iter().filter(|p| p.status == "Pending").count();
        let high_restarts = active_pods.iter().filter(|p| p.restarts >= 10).count();

        if failed > 0 {
            issues.push(Issue {
                severity: "critical".into(),
                category: "kubernetes".into(),
                title: format!("{} failed pod(s) in cluster '{}'", failed, cluster.name),
                detail: active_pods.iter().filter(|p| p.status == "Failed" || p.status == "Unknown")
                    .take(5).map(|p| format!("{}/{}", p.namespace, p.name)).collect::<Vec<_>>().join(", "),
            });
        }
        if pending > 0 {
            issues.push(Issue {
                severity: "warning".into(),
                category: "kubernetes".into(),
                title: format!("{} pending pod(s) in cluster '{}'", pending, cluster.name),
                detail: active_pods.iter().filter(|p| p.status == "Pending")
                    .take(5).map(|p| format!("{}/{}", p.namespace, p.name)).collect::<Vec<_>>().join(", "),
            });
        }
        if high_restarts > 0 {
            issues.push(Issue {
                severity: "warning".into(),
                category: "kubernetes".into(),
                title: format!("{} pod(s) with high restarts in cluster '{}'", high_restarts, cluster.name),
                detail: active_pods.iter().filter(|p| p.restarts >= 10)
                    .take(5).map(|p| format!("{}/{} ({}x)", p.namespace, p.name, p.restarts)).collect::<Vec<_>>().join(", "),
            });
        }
    }

    // ── Clearable disk space ──

    // Journal logs
    if let Ok(output) = std::process::Command::new("journalctl")
        .args(["--disk-usage"])
        .output()
    {
        let stdout = String::from_utf8_lossy(&output.stdout);
        // Parse "Archived and active journals take up 1.2G in the file system."
        if let Some(size_str) = stdout.split("take up ").nth(1).and_then(|s| s.split(' ').next()) {
            let size_mb = parse_size_to_mb(size_str);
            if size_mb > 500.0 {
                issues.push(Issue {
                    severity: "info".into(),
                    category: "disk".into(),
                    title: format!("Journal logs using {}", size_str),
                    detail: format!("Run 'journalctl --vacuum-size=200M' to reclaim space"),
                });
            }
        }
    }

    // Package cache (apt)
    if let Ok(output) = std::process::Command::new("du")
        .args(["-sh", "/var/cache/apt/archives"])
        .output()
    {
        if output.status.success() {
            let stdout = String::from_utf8_lossy(&output.stdout);
            if let Some(size_str) = stdout.split_whitespace().next() {
                let size_mb = parse_size_to_mb(size_str);
                if size_mb > 200.0 {
                    issues.push(Issue {
                        severity: "info".into(),
                        category: "disk".into(),
                        title: format!("APT cache using {}", size_str),
                        detail: "Run 'apt clean' to reclaim space".into(),
                    });
                }
            }
        }
    }

    // Package cache (dnf/yum)
    if let Ok(output) = std::process::Command::new("du")
        .args(["-sh", "/var/cache/dnf"])
        .output()
    {
        if output.status.success() {
            let stdout = String::from_utf8_lossy(&output.stdout);
            if let Some(size_str) = stdout.split_whitespace().next() {
                let size_mb = parse_size_to_mb(size_str);
                if size_mb > 200.0 {
                    issues.push(Issue {
                        severity: "info".into(),
                        category: "disk".into(),
                        title: format!("DNF cache using {}", size_str),
                        detail: "Run 'dnf clean all' to reclaim space".into(),
                    });
                }
            }
        }
    }

    // /tmp usage
    if let Ok(output) = std::process::Command::new("du")
        .args(["-sh", "/tmp"])
        .output()
    {
        if output.status.success() {
            let stdout = String::from_utf8_lossy(&output.stdout);
            if let Some(size_str) = stdout.split_whitespace().next() {
                let size_mb = parse_size_to_mb(size_str);
                if size_mb > 500.0 {
                    issues.push(Issue {
                        severity: "info".into(),
                        category: "disk".into(),
                        title: format!("/tmp using {}", size_str),
                        detail: "Temporary files may be safe to clean up".into(),
                    });
                }
            }
        }
    }

    // Docker unused images
    if let Ok(output) = std::process::Command::new("docker")
        .args(["system", "df", "--format", "{{.Reclaimable}}"])
        .output()
    {
        if output.status.success() {
            let stdout = String::from_utf8_lossy(&output.stdout);
            // Sum up any reclaimable amounts
            let mut total_mb = 0.0f64;
            let mut total_str = String::new();
            for line in stdout.lines() {
                let clean = line.trim().split('(').next().unwrap_or("").trim();
                if !clean.is_empty() && clean != "0B" {
                    let mb = parse_size_to_mb(clean);
                    total_mb += mb;
                    if total_str.is_empty() { total_str = clean.to_string(); }
                }
            }
            if total_mb > 500.0 {
                issues.push(Issue {
                    severity: "info".into(),
                    category: "container".into(),
                    title: format!("Docker reclaimable space: {:.0} MB", total_mb),
                    detail: "Run 'docker system prune' to reclaim unused images/containers".into(),
                });
            }
        }
    }

    issues
}

/// GET /api/issues/scan — scan system for issues
pub async fn scan_issues(
    req: HttpRequest,
    state: web::Data<AppState>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }

    let st = state.clone().into_inner();
    let metrics = tokio::task::spawn_blocking(move || {
        st.monitor.lock().unwrap().collect()
    }).await.unwrap();
    let issues = collect_issues(&metrics);

    // Enrich each issue with its one-click repair (when one exists) without
    // bloating the Issue struct or its ~18 producers. Serialising the issue
    // and grafting `repair` on keeps the wire shape additive — older nodes
    // simply omit the field and the frontend treats them as non-repairable.
    let issues_json: Vec<serde_json::Value> = issues.iter().map(|i| {
        let mut v = serde_json::to_value(i).unwrap_or_else(|_| serde_json::json!({}));
        if let Some(rep) = repair_for(i) {
            if let Ok(rv) = serde_json::to_value(&rep) {
                v["repair"] = rv;
            }
        }
        v
    }).collect();

    HttpResponse::Ok().json(serde_json::json!({
        "hostname": metrics.hostname,
        "version": env!("CARGO_PKG_VERSION"),
        "issues": issues_json,
        "ai_analysis": null,
    }))
}

/// GET /api/alerts?since=ID — get recent alerts for the Tasks window
pub async fn get_alert_log(
    req: HttpRequest,
    state: web::Data<AppState>,
    query: web::Query<std::collections::HashMap<String, String>>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }

    let since_id: u64 = query.get("since")
        .and_then(|s| s.parse().ok())
        .unwrap_or(0);

    let log = state.alert_log.read().unwrap();
    let new_entries: Vec<&AlertLogEntry> = log.iter()
        .filter(|e| e.id > since_id)
        .collect();

    HttpResponse::Ok().json(serde_json::json!({
        "alerts": new_entries,
    }))
}

/// GET /api/alerts/history — paginated, filterable view over the
/// same in-memory alert log used by `get_alert_log`. Drives the
/// Alerts page → History sub-tab. Optional query params:
///   - `severity`    — filter exact match ("critical" / "warning" / ...)
///   - `cluster`     — filter exact match
///   - `host`        — filter exact match on hostname
///   - `q`           — case-insensitive substring match on title + detail
///   - `since`       — return only entries with id > since
///   - `limit`       — max rows to return; default 200, clamped to 1000
///
/// Response shape:
///   `{ alerts: [...], total: N, returned: N, oldest_id, newest_id }`
/// Frontend uses `oldest_id` as the next page cursor (set `since=oldest_id - 1`
/// won't work for forward paging; instead the History page just
/// re-queries with adjusted filters).
pub async fn get_alert_history(
    req: HttpRequest,
    state: web::Data<AppState>,
    query: web::Query<std::collections::HashMap<String, String>>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let severity = query.get("severity").cloned();
    let cluster = query.get("cluster").cloned();
    let host = query.get("host").cloned();
    let q_lower = query.get("q").map(|s| s.to_lowercase());
    let since_id: u64 = query.get("since").and_then(|s| s.parse().ok()).unwrap_or(0);
    let limit: usize = query.get("limit")
        .and_then(|s| s.parse().ok())
        .unwrap_or(200)
        .min(1000);

    // Merge sources: state.alert_log (array health / AI critical /
    // gateway audit — the legacy v23 writers) AND the new in-memory
    // alerting::history_snapshot (every send_node_alert dispatch as
    // of v24). The two sources have disjoint contents in practice;
    // unified shape is the existing AlertLogEntry. Newest-first.
    let legacy_log = state.alert_log.read().unwrap();
    let legacy_rows: Vec<AlertLogEntry> = legacy_log.iter().cloned().collect();
    drop(legacy_log);
    let history_rows: Vec<AlertLogEntry> = crate::alerting::history_snapshot()
        .into_iter()
        .map(|h| AlertLogEntry {
            // Offset the history ID range so it doesn't collide with
            // the legacy log's IDs (which start at 1 from the
            // process-lifetime start). 1_000_000+ is a safe band —
            // legacy log capped at 200, so it can never reach it.
            id: 1_000_000 + h.id,
            timestamp: h.timestamp,
            severity: h.severity,
            title: h.title,
            detail: h.detail,
            hostname: h.hostname,
            cluster: h.cluster,
        })
        .collect();

    // Combined newest-first ordering by timestamp string (RFC3339,
    // lexicographically sortable for the modern entries; legacy uses
    // a different format but is bounded to 200 rows so the imperfect
    // ordering near the boundary is acceptable).
    let mut all: Vec<AlertLogEntry> = legacy_rows.into_iter()
        .chain(history_rows.into_iter())
        .collect();
    all.sort_by(|a, b| b.timestamp.cmp(&a.timestamp));

    let matched: Vec<AlertLogEntry> = all.into_iter()
        .filter(|e| e.id > since_id)
        .filter(|e| severity.as_deref().is_none_or(|s| e.severity == s))
        .filter(|e| cluster.as_deref().is_none_or(|c| e.cluster == c))
        .filter(|e| host.as_deref().is_none_or(|h| e.hostname == h))
        .filter(|e| q_lower.as_deref().is_none_or(|q| {
            e.title.to_lowercase().contains(q) || e.detail.to_lowercase().contains(q)
        }))
        .collect();
    let total = matched.len();
    let mut truncated = matched;
    truncated.truncate(limit);
    let returned = truncated.len();
    let newest_id = truncated.first().map(|e| e.id).unwrap_or(0);
    let oldest_id = truncated.last().map(|e| e.id).unwrap_or(0);

    HttpResponse::Ok().json(serde_json::json!({
        "alerts": truncated,
        "total": total,
        "returned": returned,
        "newest_id": newest_id,
        "oldest_id": oldest_id,
    }))
}

