// ─── Patreon Integration ─────────────────────────────────────────────────────

/// GET /api/patreon/connect — start OAuth flow, redirect to Patreon
async fn patreon_connect(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) {
        return resp;
    }
    // Build the callback URL for this WolfStack instance
    let conn = req.connection_info();
    let scheme = conn.scheme();
    let host = conn.host();
    let callback_url = format!("{}://{}/api/patreon/callback", scheme, host);
    let auth_url = state.patreon.authorize_url(&callback_url);
    HttpResponse::Found()
        .append_header(("Location", auth_url))
        .finish()
}

/// GET /api/patreon/callback — receive tokens from wolfscale.org proxy
/// The proxy already exchanged the code for tokens using the client secret.
/// We receive: ?access_token=...&refresh_token=... (or ?error=...)
async fn patreon_callback(_req: HttpRequest, state: web::Data<AppState>, query: web::Query<std::collections::HashMap<String, String>>) -> HttpResponse {
    // Check for error from proxy
    if let Some(error) = query.get("error") {
        return HttpResponse::Ok().content_type("text/html").body(format!(
            r#"<!DOCTYPE html><html><head><title>Patreon Link Failed</title></head>
            <body style="display:flex;align-items:center;justify-content:center;height:100vh;font-family:sans-serif;background:#0f172a;color:#fff;">
            <div style="text-align:center"><h2>Patreon Link Failed</h2><p>Error: {}</p>
            <p><a href="/" style="color:#22c55e;">Return to dashboard</a></p></div></body></html>"#,
            error
        ));
    }

    // Receive tokens from proxy
    let access_token = match query.get("access_token") {
        Some(t) => t.clone(),
        None => {
            return HttpResponse::Ok().content_type("text/html").body(
                r#"<!DOCTYPE html><html><head><title>Patreon Link Failed</title></head>
                <body style="display:flex;align-items:center;justify-content:center;height:100vh;font-family:sans-serif;background:#0f172a;color:#fff;">
                <div style="text-align:center"><h2>Patreon Link Failed</h2><p>No access token received</p>
                <p><a href="/" style="color:#22c55e;">Return to dashboard</a></p></div></body></html>"#
            );
        }
    };
    let refresh_token = query.get("refresh_token").cloned().unwrap_or_default();

    // Save tokens
    {
        let mut config = state.patreon.config.write().unwrap();
        config.access_token = Some(access_token);
        config.refresh_token = Some(refresh_token);
        config.linked = true;
        let _ = config.save();
    }

    // Immediately sync membership info
    match state.patreon.sync_membership().await {
        Ok(tier) => {
            tracing::info!("Patreon linked successfully, tier: {:?}", tier);
        }
        Err(e) => {
            tracing::warn!("Patreon linked but membership sync failed: {}", e);
        }
    }

    HttpResponse::Ok().content_type("text/html").body(
        r#"<!DOCTYPE html><html><head><title>Patreon Linked</title></head>
        <body style="display:flex;align-items:center;justify-content:center;height:100vh;font-family:sans-serif;background:#0f172a;color:#fff;">
        <div style="text-align:center"><h2 style="color:#22c55e;">Patreon Linked Successfully!</h2>
        <p>Your support tier has been detected. You can close this window.</p>
        <p><a href="/" style="color:#22c55e;">Return to dashboard</a></p></div></body></html>"#
    )
}

/// GET /api/patreon/status — return current Patreon link status and tier
async fn patreon_status(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) {
        return resp;
    }
    let config = state.patreon.config.read().unwrap();
    let (beta_ok, beta_reason) = beta_access_granted_full(&config.tier, config.github_sponsor);
    HttpResponse::Ok().json(serde_json::json!({
        "linked": config.linked,
        "user_name": config.patreon_user_name,
        "email": config.patreon_email,
        "tier": config.tier,
        "pledge_amount_cents": config.pledge_amount_cents,
        "has_beta_access": beta_ok,
        "beta_access_reason": beta_reason,
        "github_sponsor": config.github_sponsor,
        "github_sponsor_login": config.github_sponsor_login,
        "last_checked": config.last_checked,
    }))
}

/// POST /api/sponsor/github — toggle the GitHub Sponsor self-attest
/// flag (operator-session auth). Body: `{ "enabled": bool,
/// "login": Option<String> }`. The `login` is for display purposes
/// only — never part of the access check. See `beta_access_granted_full`
/// for the reasoning behind the honour-system design.
#[derive(serde::Deserialize)]
struct SetGithubSponsorRequest {
    enabled: bool,
    #[serde(default)]
    login: Option<String>,
}
async fn set_github_sponsor(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<SetGithubSponsorRequest>,
) -> HttpResponse {
    // Operator-session ONLY (not cluster-secret) — flipping the beta
    // gate is an operator decision, not a peer-driven one.
    let _user = match req.cookie("wolfstack_session")
        .and_then(|c| state.sessions.validate(c.value()))
    {
        Some(u) => u,
        None => return HttpResponse::Unauthorized().json(serde_json::json!({
            "error": "operator session required to change GitHub Sponsor state"
        })),
    };
    let body = body.into_inner();
    if let Err(e) = state.patreon.set_github_sponsor(body.enabled, body.login) {
        return HttpResponse::InternalServerError().json(serde_json::json!({
            "error": format!("could not persist sponsor flag: {}", e)
        }));
    }
    let cfg = state.patreon.config.read().unwrap();
    let (beta_ok, beta_reason) = beta_access_granted_full(&cfg.tier, cfg.github_sponsor);
    HttpResponse::Ok().json(serde_json::json!({
        "ok": true,
        "github_sponsor": cfg.github_sponsor,
        "github_sponsor_login": cfg.github_sponsor_login,
        "has_beta_access": beta_ok,
        "beta_access_reason": beta_reason,
    }))
}

/// POST /api/patreon/sync — manually refresh membership status
async fn patreon_sync(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) {
        return resp;
    }
    match state.patreon.sync_membership().await {
        Ok(tier) => {
            let config = state.patreon.config.read().unwrap();
            let (beta_ok, beta_reason) = beta_access_granted(&tier);
            HttpResponse::Ok().json(serde_json::json!({
                "ok": true,
                "tier": tier,
                "has_beta_access": beta_ok,
                "beta_access_reason": beta_reason,
                "user_name": config.patreon_user_name,
                "last_checked": config.last_checked,
            }))
        }
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": e })),
    }
}

/// Beta-channel access is identical to supporter status (see `is_supporter`):
/// beta builds are a thank-you perk for EVERYONE who supports development, not
/// a premium upsell, so a $3 Patreon backer gets the same early-access builds
/// as a $95 one. The commercial value lives in the licence-gated features
/// (plugins, API tokens, SSO, multi-tenancy), never in the beta channel.
/// Historically this gated on Patreon Advanced+ ($25) while the nag exempted
/// Basic+ ($3) — and an unverified GitHub self-attest granted beta for free —
/// which made the levels incoherent. The grants that count:
///
///   1. **Patreon pledge** — any paying tier (Basic+, i.e. $3+/mo).
///   2. **WolfStack paid licence** — Homelab, Team, MSP/Pro, Enterprise.
///      Anyone who paid for the product earns the right to test
///      pre-release builds against their environment.
///   3. **GitHub Sponsor self-attest** — operator flag at
///      `/etc/wolfstack/patreon.json:github_sponsor=true`, settable
///      via `POST /api/sponsor/github`. Honour-system: GitHub's
///      Sponsors API requires the receiving org's auth to enumerate
///      sponsors, so we can't programmatically verify. The cost of a
///      false claim is "stranger gets beta builds"; the cost of
///      requiring verification is "real sponsors locked out by an
///      OAuth flow". We optimise for the real-sponsor path.
///
/// Returns (granted, reason) so the frontend can show "via licence"
/// vs "via sponsor" vs "via GitHub Sponsor" if it wants to.
fn beta_access_granted_full(
    patreon_tier: &crate::patreon::PatreonTier,
    github_sponsor: bool,
) -> (bool, &'static str)
{
    // Beta == supporter. Single source of truth so the two can never drift
    // apart again (a paying backer must never be offered less than a free
    // self-attest).
    is_supporter(patreon_tier, github_sponsor)
}

/// Convenience wrapper that defaults github_sponsor=false. Retained
/// for the `/api/patreon/sync` path that only knows the freshly-fetched
/// Patreon tier — that response reflects the live sponsorship state,
/// while the github_sponsor flag is sticky and reported separately.
fn beta_access_granted(patreon_tier: &crate::patreon::PatreonTier)
    -> (bool, &'static str)
{
    beta_access_granted_full(patreon_tier, false)
}

/// Whether this installation supports WolfStack by ANY means — a paid
/// licence, a paying Patreon pledge (Basic+), or the GitHub Sponsor
/// self-attest flag. Deliberately broader than `beta_access_granted_full`:
/// the login-time support nag must exempt EVERYONE who gives us money,
/// including Patreon Basic backers who don't earn beta access. Nagging a
/// paying customer is a self-own.
///
/// Returns (is_supporter, reason) so the frontend can tailor copy if it wants.
fn is_supporter(
    patreon_tier: &crate::patreon::PatreonTier,
    github_sponsor: bool,
) -> (bool, &'static str) {
    if crate::compat::platform_ready() {
        return (true, "licence");
    }
    if patreon_tier.is_paying() {
        return (true, "patreon");
    }
    if github_sponsor {
        return (true, "github_sponsor");
    }
    (false, "none")
}

/// GET /api/supporter/status — drives the login-time support nag. Reports
/// whether this install supports WolfStack by any means (licence, paying
/// Patreon pledge, or GitHub Sponsor self-attest) so the frontend can decide
/// whether to show the nag. Operator session required.
async fn supporter_status(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) {
        return resp;
    }
    // Copy the two inputs out and drop the guard BEFORE the (sync) licence
    // check — never hold the RwLock guard longer than the read needs.
    let (tier, github_sponsor) = {
        let config = state.patreon.config.read().unwrap();
        (config.tier.clone(), config.github_sponsor)
    };
    let (granted, reason) = is_supporter(&tier, github_sponsor);
    HttpResponse::Ok().json(serde_json::json!({
        "is_supporter": granted,
        "reason": reason,
    }))
}

/// POST /api/patreon/disconnect — unlink Patreon account
async fn patreon_disconnect(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) {
        return resp;
    }
    let mut config = state.patreon.config.write().unwrap();
    *config = crate::patreon::PatreonConfig::default();
    let _ = config.save();
    HttpResponse::Ok().json(serde_json::json!({ "ok": true }))
}

// ─── Icon Pack Endpoints ───

/// GET /api/icon-packs — list all available icon packs (system + custom)
async fn icon_packs_list(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let packs = crate::icons::scan_all_packs();
    HttpResponse::Ok().json(serde_json::json!({ "packs": packs }))
}

/// GET /api/icon-packs/semantic-names — list all supported semantic icon names
async fn icon_packs_semantic_names(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    HttpResponse::Ok().json(serde_json::json!({ "names": crate::icons::semantic_names() }))
}

/// POST /api/icon-packs/install — install from GitHub URL { "url": "https://github.com/..." }
async fn icon_packs_install(req: HttpRequest, state: web::Data<AppState>, body: web::Json<serde_json::Value>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let url = match body.get("url").and_then(|v| v.as_str()) {
        Some(u) => u,
        None => return HttpResponse::BadRequest().json(serde_json::json!({ "error": "missing 'url' field" })),
    };
    match crate::icons::install_from_github(url).await {
        Ok(pack) => HttpResponse::Ok().json(serde_json::json!({ "ok": true, "pack": pack })),
        Err(e) => HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
    }
}

/// DELETE /api/icon-packs/{pack_id} — remove a custom-installed pack
async fn icon_packs_remove(req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let pack_id = path.into_inner();
    match crate::icons::remove_pack(&pack_id) {
        Ok(()) => HttpResponse::Ok().json(serde_json::json!({ "ok": true })),
        Err(e) => HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
    }
}

/// GET /api/icon-packs/{pack_id}/icon/{icon_name} — serve a single icon file
/// Resolves semantic name → freedesktop icon → file on disk
async fn icon_packs_serve(req: HttpRequest, state: web::Data<AppState>, path: web::Path<(String, String)>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let (pack_id, icon_name) = path.into_inner();

    // Find the pack directory
    let packs = crate::icons::scan_all_packs();
    let pack = match packs.iter().find(|p| p.id == pack_id) {
        Some(p) => p,
        None => return HttpResponse::NotFound().json(serde_json::json!({ "error": "pack not found" })),
    };

    let theme_dir = std::path::Path::new(&pack.path);
    match crate::icons::resolve_icon(theme_dir, &icon_name) {
        Some(file_path) => {
            let mime = crate::icons::icon_mime(&file_path);
            match std::fs::read(&file_path) {
                Ok(data) => HttpResponse::Ok()
                    .content_type(mime)
                    .insert_header(("Cache-Control", "public, max-age=86400"))
                    .body(data),
                Err(_) => HttpResponse::InternalServerError().finish(),
            }
        }
        None => HttpResponse::NotFound().json(serde_json::json!({ "error": "icon not found in pack" })),
    }
}

/// GET /api/icon-packs/{pack_id}/preview — serve a grid of sample icons for previewing
async fn icon_packs_preview(req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let pack_id = path.into_inner();

    let packs = crate::icons::scan_all_packs();
    let pack = match packs.iter().find(|p| p.id == pack_id) {
        Some(p) => p,
        None => return HttpResponse::NotFound().json(serde_json::json!({ "error": "pack not found" })),
    };

    // Return a list of which semantic icons are available
    let theme_dir = std::path::Path::new(&pack.path);
    let names = crate::icons::semantic_names();
    let mut available: Vec<&str> = Vec::new();
    for name in &names {
        if crate::icons::resolve_icon(theme_dir, name).is_some() {
            available.push(name);
        }
    }
    HttpResponse::Ok().json(serde_json::json!({
        "pack_id": pack_id,
        "total_semantic": names.len(),
        "available": available,
    }))
}

// ═══════════════════════════════════════════════════════════════════
// Docker Compose Management
// ═══════════════════════════════════════════════════════════════════

/// Operator-configurable root for standalone Docker Compose stacks
/// (Settings → File Locations → "Compose Directory"). Defaults to
/// /etc/wolfstack/compose; pointing it at an existing compose root makes every
/// `<name>/docker-compose.yml` under it appear as a managed stack.
fn compose_root_dir() -> String {
    crate::paths::get().compose_dir
}
const SECRETS_FILE: &str = "/etc/wolfstack/secrets.json";

#[derive(Deserialize)]
struct ComposeCreateRequest {
    name: String,
    #[serde(default)]
    compose_yaml: String,
    #[serde(default)]
    env_content: String,
}

#[derive(Deserialize)]
struct ComposeFileRequest {
    content: String,
}

#[derive(Deserialize, Serialize, Clone)]
struct SecretEntry {
    key: String,
    value: String,
    #[serde(default)]
    description: String,
    #[serde(default)]
    created: String,
    #[serde(default)]
    updated: String,
}

#[derive(Deserialize)]
struct SecretRequest {
    key: String,
    #[serde(default)]
    value: Option<String>,
    #[serde(default)]
    description: Option<String>,
}

fn compose_project_dir(name: &str) -> std::path::PathBuf {
    std::path::PathBuf::from(compose_root_dir()).join(name)
}

/// Find the compose file in a stack directory, honouring Docker Compose's own
/// filename precedence: compose.yaml > compose.yml > docker-compose.yaml >
/// docker-compose.yml. Returns the existing file, or `docker-compose.yml` (our
/// canonical name for newly-created stacks) when none is present yet — so
/// imported stacks that use any of the standard names are picked up and edited
/// in place rather than ignored or duplicated.
fn compose_file_in(dir: &std::path::Path) -> std::path::PathBuf {
    for name in ["compose.yaml", "compose.yml", "docker-compose.yaml", "docker-compose.yml"] {
        let p = dir.join(name);
        if p.exists() { return p; }
    }
    dir.join("docker-compose.yml")
}

/// Validate compose stack name — alphanumeric, dash, underscore only
fn is_safe_compose_name(name: &str) -> bool {
    !name.is_empty()
        && name.len() <= 128
        && name.chars().all(|c| c.is_ascii_alphanumeric() || c == '-' || c == '_')
        && !name.starts_with('-')
}

/// Validate a name from a URL path parameter; returns Err(HttpResponse) on failure
fn require_safe_compose_name(name: &str) -> Result<(), HttpResponse> {
    if !is_safe_compose_name(name) {
        Err(HttpResponse::BadRequest().json(serde_json::json!({
            "error": "Invalid stack name — only alphanumeric, dash, and underscore allowed"
        })))
    } else {
        Ok(())
    }
}

/// Count compose stacks (directories under the compose root that hold a compose
/// file). Cheap dir scan; surfaced as a per-node count in the nav alongside
/// Docker/LXC/VM so an operator sees at a glance how many stacks a node has
/// (Gary/KO4BSR 2026-06-27).
pub(crate) fn compose_stack_count() -> u32 {
    let root = compose_root_dir();
    let mut n = 0u32;
    if let Ok(entries) = std::fs::read_dir(std::path::Path::new(&root)) {
        for e in entries.flatten() {
            let p = e.path();
            if p.is_dir() && compose_file_in(&p).exists() { n += 1; }
        }
    }
    n
}

/// The image references a stack resolves to (`docker compose config --images`).
fn compose_config_images(dir: &std::path::Path, compose_file: &std::path::Path) -> Vec<String> {
    match Command::new("docker")
        .args(["compose", "-f", &compose_file.to_string_lossy(), "config", "--images"])
        .envs(compose_secrets_env())
        .current_dir(dir)
        .output()
    {
        Ok(o) if o.status.success() => String::from_utf8_lossy(&o.stdout)
            .lines().map(|l| l.trim().to_string()).filter(|l| !l.is_empty()).collect(),
        _ => Vec::new(),
    }
}

/// The local image ID for a reference, or "" when the image isn't present
/// locally. Used to deterministically tell which images a pull actually changed
/// (parsing pull progress text can't distinguish "downloaded" from "up to date").
fn docker_image_id(image: &str) -> String {
    Command::new("docker")
        .args(["image", "inspect", image, "-f", "{{.Id}}"])
        .output()
        .ok()
        .filter(|o| o.status.success())
        .map(|o| String::from_utf8_lossy(&o.stdout).trim().to_string())
        .unwrap_or_default()
}

/// Snapshot of (image ref → local image ID) for every image a stack uses.
fn compose_image_id_map(dir: &std::path::Path, compose_file: &std::path::Path)
    -> Vec<(String, String)>
{
    compose_config_images(dir, compose_file)
        .into_iter()
        .map(|img| { let id = docker_image_id(&img); (img, id) })
        .collect()
}

/// Extract the names of `${VAR}`s that `docker compose config` reports as
/// undefined. Compose logs one warning per missing variable on stderr, e.g.
///   level=warning msg="The \"FOO\" variable is not set. Defaulting to a blank string."
/// We pull `FOO` out of each such line (quotes may be backslash-escaped by the
/// logger, so we strip a trailing quote/backslash before reading the
/// identifier). De-duplicated, order preserved (wabil 2026-06-26).
fn parse_undefined_compose_vars(stderr: &str) -> Vec<String> {
    let mut out: Vec<String> = Vec::new();
    for line in stderr.lines() {
        let Some(idx) = line.find("variable is not set") else { continue };
        let head = line[..idx].trim_end();
        // Drop the closing quote (and any escaping backslash) after the name.
        let head = head.trim_end_matches('"').trim_end_matches('\\');
        let name: String = head.chars().rev()
            .take_while(|c| c.is_ascii_alphanumeric() || *c == '_')
            .collect::<Vec<_>>().into_iter().rev().collect();
        if !name.is_empty() && !out.contains(&name) {
            out.push(name);
        }
    }
    out
}

/// Per-container final action parsed from `docker compose up -d` output, keeping
/// only the most significant state per container so the UI can report what
/// actually changed: lines look like " Container app-web-1  Started ". Created /
/// Recreated / Started mean the container came up fresh (e.g. a pulled image was
/// applied); Running means it was left untouched. Transitional lines (Creating,
/// Starting, …) are dropped (wabil 2026-06-26).
fn parse_compose_container_actions(output: &str) -> Vec<(String, String)> {
    fn rank(a: &str) -> u8 {
        match a {
            "Recreated" => 5,
            "Created" => 4,
            "Started" | "Restarted" => 3,
            "Running" => 1,
            _ => 0, // transitional / unknown — ignored
        }
    }
    let mut best: std::collections::BTreeMap<String, String> = std::collections::BTreeMap::new();
    for line in output.lines() {
        let t = line.trim();
        let Some(rest) = t.strip_prefix("Container ") else { continue };
        let rest = rest.trim();
        let Some(pos) = rest.rfind(char::is_whitespace) else { continue };
        let name = rest[..pos].trim().to_string();
        let action = rest[pos..].trim().to_string();
        if rank(&action) == 0 || name.is_empty() { continue; }
        let replace = best.get(&name).map(|cur| rank(&action) > rank(cur)).unwrap_or(true);
        if replace { best.insert(name, action); }
    }
    best.into_iter().collect()
}

/// GET /api/compose/stacks — list all compose projects
async fn compose_list_stacks(
    req: HttpRequest,
    state: web::Data<AppState>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }

    let compose_root = compose_root_dir();
    let dir = std::path::Path::new(&compose_root);
    if !dir.exists() {
        return HttpResponse::Ok().json(serde_json::json!({ "stacks": [] }));
    }

    let mut stacks = Vec::new();
    if let Ok(entries) = std::fs::read_dir(dir) {
        for entry in entries.flatten() {
            let path = entry.path();
            if !path.is_dir() { continue; }
            let name = entry.file_name().to_string_lossy().to_string();
            let compose_file = compose_file_in(&path);
            let env_file = path.join(".env");
            if !compose_file.exists() { continue; }

            // Get stack status via docker compose ps
            let status = Command::new("docker")
                .args(["compose", "-f", &compose_file.to_string_lossy(), "ps", "--format", "json"])
                .envs(compose_secrets_env())
                .current_dir(&path)
                .output();

            let mut services = Vec::new();
            let mut running = 0u32;
            let mut total = 0u32;
            if let Ok(out) = &status {
                let stdout = String::from_utf8_lossy(&out.stdout);
                for line in stdout.lines() {
                    if let Ok(svc) = serde_json::from_str::<serde_json::Value>(line) {
                        total += 1;
                        let state = svc.get("State").and_then(|s| s.as_str()).unwrap_or("unknown");
                        if state == "running" { running += 1; }
                        services.push(serde_json::json!({
                            "name": svc.get("Service").and_then(|s| s.as_str()).unwrap_or(""),
                            "state": state,
                            "status": svc.get("Status").and_then(|s| s.as_str()).unwrap_or(""),
                            "image": svc.get("Image").and_then(|s| s.as_str()).unwrap_or(""),
                            "ports": svc.get("Publishers").unwrap_or(&serde_json::Value::Null),
                        }));
                    }
                }
            }

            let has_env = env_file.exists();
            stacks.push(serde_json::json!({
                "name": name,
                "path": path.to_string_lossy(),
                "running": running,
                "total": total,
                "services": services,
                "has_env": has_env,
                "status": if total == 0 { "stopped" } else if running == total { "running" } else { "partial" },
            }));
        }
    }

    HttpResponse::Ok().json(serde_json::json!({ "stacks": stacks }))
}

/// POST /api/compose/stacks — create a new compose project
async fn compose_create_stack(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<ComposeCreateRequest>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }

    let name = body.name.trim();
    if let Err(e) = require_safe_compose_name(name) { return e; }

    let dir = compose_project_dir(name);
    if dir.exists() {
        return HttpResponse::Conflict().json(serde_json::json!({ "error": "Stack already exists" }));
    }

    if let Err(e) = std::fs::create_dir_all(&dir) {
        return HttpResponse::InternalServerError().json(serde_json::json!({ "error": format!("Failed to create directory: {}", e) }));
    }

    let yaml = if body.compose_yaml.is_empty() {
        format!("# Docker Compose for {}\nservices:\n  app:\n    image: nginx:latest\n    ports:\n      - \"8080:80\"\n    restart: unless-stopped\n", name)
    } else {
        body.compose_yaml.clone()
    };

    if let Err(e) = std::fs::write(dir.join("docker-compose.yml"), &yaml) {
        return HttpResponse::InternalServerError().json(serde_json::json!({ "error": format!("Failed to write compose file: {}", e) }));
    }

    if !body.env_content.is_empty() {
        if let Err(e) = std::fs::write(dir.join(".env"), &body.env_content) {
            return HttpResponse::InternalServerError().json(serde_json::json!({ "error": format!("Failed to write .env: {}", e) }));
        }
    }

    HttpResponse::Ok().json(serde_json::json!({ "message": "Stack created", "name": name }))
}

/// DELETE /api/compose/stacks/{name} — delete a compose project (runs down first)
async fn compose_delete_stack(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }

    let name = path.into_inner();
    if let Err(e) = require_safe_compose_name(&name) { return e; }
    let dir = compose_project_dir(&name);
    if !dir.exists() {
        return HttpResponse::NotFound().json(serde_json::json!({ "error": "Stack not found" }));
    }

    // Run docker compose down first
    let compose_file = compose_file_in(&dir);
    match Command::new("docker")
        .args(["compose", "-f", &compose_file.to_string_lossy(), "down", "--remove-orphans"])
        .envs(compose_secrets_env())
        .current_dir(&dir)
        .output()
    {
        Ok(out) if !out.status.success() => {
            warn!("compose down failed for '{}': {}", name, String::from_utf8_lossy(&out.stderr).trim());
        }
        Err(e) => {
            warn!("compose down failed for '{}': {}", name, e);
        }
        _ => {}
    }

    if let Err(e) = std::fs::remove_dir_all(&dir) {
        return HttpResponse::InternalServerError().json(serde_json::json!({ "error": format!("Failed to delete: {}", e) }));
    }

    HttpResponse::Ok().json(serde_json::json!({ "message": "Stack deleted" }))
}

/// GET /api/compose/stacks/{name}/compose — read docker-compose.yml
async fn compose_read_yaml(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }

    let name = path.into_inner();
    if let Err(e) = require_safe_compose_name(&name) { return e; }
    let file = compose_file_in(&compose_project_dir(&name));
    match std::fs::read_to_string(&file) {
        Ok(content) => HttpResponse::Ok().json(serde_json::json!({ "content": content })),
        Err(e) => HttpResponse::NotFound().json(serde_json::json!({ "error": format!("{}", e) })),
    }
}

/// POST /api/compose/stacks/{name}/compose — write docker-compose.yml
async fn compose_write_yaml(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
    body: web::Json<ComposeFileRequest>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }

    let name = path.into_inner();
    if let Err(e) = require_safe_compose_name(&name) { return e; }
    let file = compose_file_in(&compose_project_dir(&name));
    match std::fs::write(&file, &body.content) {
        Ok(_) => HttpResponse::Ok().json(serde_json::json!({ "message": "Saved" })),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": format!("{}", e) })),
    }
}

/// GET /api/compose/stacks/{name}/env — read .env file
async fn compose_read_env(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }

    let name = path.into_inner();
    if let Err(e) = require_safe_compose_name(&name) { return e; }
    let file = compose_project_dir(&name).join(".env");
    let content = std::fs::read_to_string(&file).unwrap_or_default();
    HttpResponse::Ok().json(serde_json::json!({ "content": content }))
}

/// POST /api/compose/stacks/{name}/env — write .env file
async fn compose_write_env(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
    body: web::Json<ComposeFileRequest>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }

    let name = path.into_inner();
    if let Err(e) = require_safe_compose_name(&name) { return e; }
    let file = compose_project_dir(&name).join(".env");
    match std::fs::write(&file, &body.content) {
        Ok(_) => HttpResponse::Ok().json(serde_json::json!({ "message": "Saved" })),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": format!("{}", e) })),
    }
}

/// POST /api/compose/stacks/{name}/up — docker compose up -d
async fn compose_up(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }

    let name = path.into_inner();
    if let Err(e) = require_safe_compose_name(&name) { return e; }
    let dir = compose_project_dir(&name);
    let compose_file = compose_file_in(&dir);
    if !compose_file.exists() {
        return HttpResponse::NotFound().json(serde_json::json!({ "error": "Stack not found" }));
    }

    let output = Command::new("docker")
        .args(["compose", "-f", &compose_file.to_string_lossy(), "up", "-d", "--remove-orphans"])
        .envs(compose_secrets_env())
        .current_dir(&dir)
        .output();

    match output {
        Ok(out) => {
            let stdout = String::from_utf8_lossy(&out.stdout).to_string();
            let stderr = String::from_utf8_lossy(&out.stderr).to_string();
            let combined = format!("{}{}", stdout, stderr);
            if out.status.success() {
                // Report which containers came up fresh (Created/Recreated/
                // Started — i.e. a pulled image was applied) vs left running
                // unchanged, so the operator sees what `up` actually did
                // (wabil 2026-06-26).
                let actions = parse_compose_container_actions(&combined);
                let started: Vec<&str> = actions.iter()
                    .filter(|(_, a)| a != "Running")
                    .map(|(c, _)| c.as_str()).collect();
                let unchanged = actions.iter().filter(|(_, a)| a == "Running").count();
                let message = if actions.is_empty() {
                    "Stack started".to_string()
                } else if started.is_empty() {
                    format!("Stack up to date — {} container{} already running",
                        unchanged, if unchanged == 1 { "" } else { "s" })
                } else {
                    format!("Started {} container{} with the latest image{}",
                        started.len(), if started.len() == 1 { "" } else { "s" },
                        if unchanged > 0 { format!("; {} unchanged", unchanged) } else { String::new() })
                };
                let actions_json: Vec<serde_json::Value> = actions.iter()
                    .map(|(c, a)| serde_json::json!({ "container": c, "action": a }))
                    .collect();
                HttpResponse::Ok().json(serde_json::json!({
                    "message": message,
                    "output": combined,
                    "actions": actions_json,
                    "started": started,
                    "unchanged": unchanged,
                }))
            } else {
                HttpResponse::BadRequest().json(serde_json::json!({ "error": stderr, "output": stdout }))
            }
        }
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": format!("{}", e) })),
    }
}

