/// GET /api/compose/stacks/{name}/logs — docker compose logs (last 200 lines)
async fn compose_logs(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
    query: web::Query<std::collections::HashMap<String, String>>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }

    let name = path.into_inner();
    if let Err(e) = require_safe_compose_name(&name) { return e; }
    let dir = compose_project_dir(&name);
    let compose_file = compose_file_in(&dir);
    if !compose_file.exists() {
        return HttpResponse::NotFound().json(serde_json::json!({ "error": "Stack not found" }));
    }

    let lines = query.get("lines").and_then(|l| l.parse::<u32>().ok()).unwrap_or(200).min(5000);
    let file_str = compose_file.to_string_lossy().into_owned();
    let lines_str = lines.to_string();
    let mut cmd_args = vec!["compose", "-f", &file_str, "logs", "--no-color", "--tail", &lines_str];

    // Validate service name to prevent argument injection
    let service_owned: String;
    if let Some(service) = query.get("service") {
        if !service.is_empty() {
            if !service.chars().all(|c| c.is_ascii_alphanumeric() || c == '-' || c == '_') {
                return HttpResponse::BadRequest().json(serde_json::json!({ "error": "Invalid service name" }));
            }
            service_owned = service.clone();
            cmd_args.push(&service_owned);
        }
    }

    let output = Command::new("docker")
        .args(&cmd_args)
        .envs(compose_secrets_env())
        .current_dir(&dir)
        .output();

    match output {
        Ok(out) => {
            let logs = String::from_utf8_lossy(&out.stdout).to_string();
            let stderr = String::from_utf8_lossy(&out.stderr).to_string();
            HttpResponse::Ok().json(serde_json::json!({ "logs": format!("{}{}", logs, stderr) }))
        }
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": format!("{}", e) })),
    }
}

#[derive(serde::Deserialize)]
struct ComposeValidateBody {
    /// The editor's current (possibly unsaved) compose YAML. When present we
    /// validate THIS via a temp file rather than the on-disk file, so Validate
    /// never mutates the saved stack (wabil: Validate used to save first).
    content: Option<String>,
}

/// POST /api/compose/stacks/{name}/validate — validate docker-compose.yml.
///
/// If the editor posts its current content, validate that (via a throwaway file
/// in the stack dir, so `.env` + relative paths still resolve) WITHOUT touching
/// the saved compose file. With no body, validate the on-disk file (older UIs).
async fn compose_validate(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
    body: Option<web::Json<ComposeValidateBody>>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }

    let name = path.into_inner();
    if let Err(e) = require_safe_compose_name(&name) { return e; }
    let dir = compose_project_dir(&name);
    if !dir.exists() {
        return HttpResponse::NotFound().json(serde_json::json!({ "error": "Stack not found" }));
    }

    let posted = body.and_then(|b| b.into_inner().content);
    let temp_file = dir.join(".wolfstack-validate.yml");
    let file_str = match &posted {
        Some(content) => {
            if let Err(e) = std::fs::write(&temp_file, content) {
                return HttpResponse::InternalServerError()
                    .json(serde_json::json!({ "error": format!("could not stage validation: {}", e) }));
            }
            temp_file.to_string_lossy().into_owned()
        }
        None => {
            let compose_file = compose_file_in(&dir);
            if !compose_file.exists() {
                return HttpResponse::NotFound().json(serde_json::json!({ "error": "Stack not found" }));
            }
            compose_file.to_string_lossy().into_owned()
        }
    };

    let output = Command::new("docker")
        .args(["compose", "-f", &file_str, "config", "--quiet"])
        .envs(compose_secrets_env())
        .current_dir(&dir)
        .output();

    // Remove the throwaway file regardless of the outcome — never leave it behind.
    if posted.is_some() {
        let _ = std::fs::remove_file(&temp_file);
    }

    match output {
        Ok(out) => {
            // `config` emits a warning per undefined ${VAR} on stderr even when
            // the YAML itself is valid (exit 0). Surface those so Validate also
            // catches "you referenced a variable that isn't set in .env / the
            // environment" — not just YAML syntax (wabil 2026-06-26).
            let stderr = String::from_utf8_lossy(&out.stderr).to_string();
            let missing_vars = parse_undefined_compose_vars(&stderr);
            if out.status.success() {
                HttpResponse::Ok().json(serde_json::json!({
                    "valid": true,
                    "missing_vars": missing_vars,
                }))
            } else {
                HttpResponse::Ok().json(serde_json::json!({
                    "valid": false,
                    "error": stderr,
                    "missing_vars": missing_vars,
                }))
            }
        }
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": format!("{}", e) })),
    }
}

// ═══════════════════════════════════════════════════════════════════
// Secrets Manager
// ═══════════════════════════════════════════════════════════════════

fn load_secrets() -> Vec<SecretEntry> {
    let path = std::path::Path::new(SECRETS_FILE);
    if !path.exists() { return Vec::new(); }
    std::fs::read_to_string(path)
        .ok()
        .and_then(|s| serde_json::from_str(&s).ok())
        .unwrap_or_default()
}

/// True if `k` can be a POSIX environment-variable name — what `docker
/// compose` can interpolate via `${k}`. Secrets with other names (spaces,
/// dashes, leading digit) are skipped rather than passed as malformed env
/// entries.
fn is_valid_env_var_name(k: &str) -> bool {
    let mut chars = k.chars();
    match chars.next() {
        Some(c) if c.is_ascii_alphabetic() || c == '_' => {}
        _ => return false,
    }
    chars.all(|c| c.is_ascii_alphanumeric() || c == '_')
}

/// Variables that change how the `docker` subprocess itself behaves rather
/// than feed the stack. A secret with one of these names must never be
/// injected — `PATH=` would strip the CLI's lookup path, `DOCKER_HOST` would
/// redirect the daemon connection, `LD_PRELOAD` would inject a library into
/// the docker client. Self-inflicted-only (the operator writes the store),
/// but cheap to make impossible (code review 2026-06-10).
const COMPOSE_ENV_DENYLIST: &[&str] = &[
    "PATH", "HOME", "SHELL", "IFS",
    "LD_PRELOAD", "LD_LIBRARY_PATH",
    "DOCKER_HOST", "DOCKER_TLS_VERIFY", "DOCKER_CERT_PATH",
    "DOCKER_CONFIG", "DOCKER_CONTEXT", "DOCKER_API_VERSION",
    "COMPOSE_FILE", "COMPOSE_PROJECT_NAME", "COMPOSE_PROFILES",
];

/// Environment pairs for `docker compose` subprocesses: every Secrets-Manager
/// entry whose key is a valid env-var name (and not on the denylist above).
/// Compose resolves `${KEY}` in the YAML (and `.env`-style references) from
/// the process environment, so injecting the store here makes
/// `environment: - DB_PASSWORD=${DB_PASSWORD}` work without ever writing the
/// secret to disk next to the stack. Process env outranks the stack's `.env`
/// file in compose's precedence, so a stale blank `KEY=` line in `.env`
/// can't shadow a real secret. Secrets are per-node — a stack only sees the
/// store of the node it runs on. Note a secret used via `environment:` ends
/// up in the container's env like any other env var (visible to `docker
/// inspect`) — inherent to env-var secrets, not to this injection.
/// (Gary KO4BSR 2026-06-10: secrets referenced from compose came through
/// blank because nothing ever injected them.)
pub(crate) fn compose_secrets_env() -> Vec<(String, String)> {
    load_secrets()
        .into_iter()
        .filter(|s| is_injectable_secret_key(&s.key))
        .map(|s| (s.key, s.value))
        .collect()
}

/// Combined gate for `compose_secrets_env` — a valid env-var name that isn't
/// a behaviour-altering variable. Split out so it's unit-testable without
/// touching the on-disk store.
fn is_injectable_secret_key(k: &str) -> bool {
    is_valid_env_var_name(k) && !COMPOSE_ENV_DENYLIST.contains(&k)
}

fn save_secrets(secrets: &[SecretEntry]) -> Result<(), String> {
    let dir = std::path::Path::new(SECRETS_FILE).parent().unwrap();
    std::fs::create_dir_all(dir).map_err(|e| format!("{}", e))?;
    let json = serde_json::to_string_pretty(secrets).map_err(|e| format!("{}", e))?;

    // Atomic write: write to temp file with restricted permissions, then rename
    let tmp = format!("{}.tmp.{}.{}", SECRETS_FILE, std::process::id(), chrono::Utc::now().timestamp_nanos_opt().unwrap_or(0));
    std::fs::write(&tmp, &json).map_err(|e| format!("{}", e))?;
    #[cfg(unix)]
    {
        use std::os::unix::fs::PermissionsExt;
        let _ = std::fs::set_permissions(&tmp, std::fs::Permissions::from_mode(0o600));
    }
    std::fs::rename(&tmp, SECRETS_FILE).map_err(|e| {
        let _ = std::fs::remove_file(&tmp);
        format!("{}", e)
    })?;
    Ok(())
}

fn now_iso() -> String {
    chrono::Utc::now().format("%Y-%m-%dT%H:%M:%S").to_string()
}

/// GET /api/secrets — list all secrets (values masked)
async fn secrets_list(
    req: HttpRequest,
    state: web::Data<AppState>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }

    let secrets = load_secrets();
    let masked: Vec<serde_json::Value> = secrets.iter().map(|s| {
        let masked_val = if s.value.len() > 4 {
            format!("****{}", &s.value[s.value.len()-4..])
        } else {
            "****".to_string()
        };
        serde_json::json!({
            "key": s.key,
            "value_masked": masked_val,
            "description": s.description,
            "created": s.created,
            "updated": s.updated,
        })
    }).collect();

    HttpResponse::Ok().json(serde_json::json!({ "secrets": masked }))
}

/// GET /api/secrets/{key} — get a single secret (full value)
async fn secrets_get(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }

    let key = path.into_inner();
    let secrets = load_secrets();
    match secrets.iter().find(|s| s.key == key) {
        Some(s) => HttpResponse::Ok().json(serde_json::json!({
            "key": s.key,
            "value": s.value,
            "description": s.description,
            "created": s.created,
            "updated": s.updated,
        })),
        None => HttpResponse::NotFound().json(serde_json::json!({ "error": "Secret not found" })),
    }
}

/// POST /api/secrets — create or update a secret
async fn secrets_save(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<SecretRequest>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }

    let key = body.key.trim().to_string();
    if key.is_empty() {
        return HttpResponse::BadRequest().json(serde_json::json!({ "error": "Key is required" }));
    }

    let mut secrets = load_secrets();
    let now = now_iso();

    if let Some(existing) = secrets.iter_mut().find(|s| s.key == key) {
        if let Some(ref v) = body.value { existing.value = v.clone(); }
        if let Some(ref d) = body.description { existing.description = d.clone(); }
        existing.updated = now;
    } else {
        secrets.push(SecretEntry {
            key: key.clone(),
            value: body.value.clone().unwrap_or_default(),
            description: body.description.clone().unwrap_or_default(),
            created: now.clone(),
            updated: now,
        });
    }

    match save_secrets(&secrets) {
        Ok(_) => HttpResponse::Ok().json(serde_json::json!({ "message": "Secret saved", "key": key })),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": e })),
    }
}

/// DELETE /api/secrets/{key} — delete a secret
async fn secrets_delete(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
) -> HttpResponse {
    if let Err(e) = require_auth(&req, &state) { return e; }

    let key = path.into_inner();
    let mut secrets = load_secrets();
    let len = secrets.len();
    secrets.retain(|s| s.key != key);
    if secrets.len() == len {
        return HttpResponse::NotFound().json(serde_json::json!({ "error": "Secret not found" }));
    }

    match save_secrets(&secrets) {
        Ok(_) => HttpResponse::Ok().json(serde_json::json!({ "message": "Secret deleted" })),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": e })),
    }
}

// ─── WolfNote Integration ───

/// POST /api/wolfnote/login — login to WolfNote and store the token
#[derive(Deserialize)]
pub struct WolfNoteLoginRequest {
    pub username: String,
    pub password: String,
    #[serde(default)]
    pub company: String,
    #[serde(default = "wolfnote_default_url")]
    pub url: String,
}
fn wolfnote_default_url() -> String { "https://app.wolfnote.org".to_string() }

pub async fn wolfnote_login(
    req: HttpRequest, state: web::Data<AppState>,
    body: web::Json<WolfNoteLoginRequest>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }

    let base_url = if body.url.is_empty() { "https://app.wolfnote.org" } else { &body.url };

    match crate::wolfnote::WolfNoteClient::login(base_url, &body.username, &body.password, &body.company).await {
        Ok(login_resp) => {
            // Save token and config
            let mut config = crate::wolfnote::WolfNoteConfig::load();
            config.url = base_url.to_string();
            config.token = login_resp.token;
            config.username = login_resp.user.username.clone();
            config.company = body.company.clone();
            if let Err(e) = config.save() {
                return HttpResponse::InternalServerError().json(serde_json::json!({ "error": e }));
            }
            HttpResponse::Ok().json(serde_json::json!({
                "connected": true,
                "username": login_resp.user.username,
            }))
        }
        Err(e) => HttpResponse::Ok().json(serde_json::json!({
            "connected": false,
            "error": e,
        })),
    }
}

/// POST /api/wolfnote/disconnect — clear the stored token
pub async fn wolfnote_disconnect(
    req: HttpRequest, state: web::Data<AppState>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let mut config = crate::wolfnote::WolfNoteConfig::load();
    config.token.clear();
    config.username.clear();
    if let Err(e) = config.save() {
        return HttpResponse::InternalServerError().json(serde_json::json!({ "error": e }));
    }
    HttpResponse::Ok().json(serde_json::json!({ "disconnected": true }))
}

/// GET /api/wolfnote/config — get current WolfNote config (token masked)
pub async fn wolfnote_config_get(
    req: HttpRequest, state: web::Data<AppState>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let config = crate::wolfnote::WolfNoteConfig::load();
    HttpResponse::Ok().json(serde_json::json!({
        "url": config.url,
        "connected": config.is_connected(),
        "username": config.username,
        "company": config.company,
        "features": config.features,
    }))
}

/// POST /api/wolfnote/config — save feature toggles
pub async fn wolfnote_config_save(
    req: HttpRequest, state: web::Data<AppState>,
    body: web::Json<serde_json::Value>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let mut config = crate::wolfnote::WolfNoteConfig::load();

    if let Some(features) = body.get("features") {
        if let Ok(f) = serde_json::from_value::<crate::wolfnote::WolfNoteFeatures>(features.clone()) {
            config.features = f;
        }
    }
    if let Some(url) = body.get("url").and_then(|v| v.as_str()) {
        if !url.is_empty() {
            config.url = url.to_string();
        }
    }

    match config.save() {
        Ok(()) => HttpResponse::Ok().json(serde_json::json!({ "saved": true })),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": e })),
    }
}

