/// GET /api/support/entitlement — does this node qualify for support? Used by
/// the UI to show/hide the Support tab. Auth required (dashboard user).
pub async fn support_entitlement(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    HttpResponse::Ok().json(serde_json::json!({ "entitled": crate::support::entitled() }))
}

/// Map a `crate::support::call` result to an HttpResponse.
fn support_result(r: Result<serde_json::Value, String>) -> HttpResponse {
    match r {
        Ok(v) => HttpResponse::Ok().json(v),
        Err(e) => HttpResponse::BadGateway().json(serde_json::json!({ "error": e })),
    }
}

/// GET /api/support/tickets — list this node's tickets.
pub async fn support_tickets_list(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    support_result(crate::support::call("list", serde_json::Map::new()).await)
}

/// POST /api/support/tickets — create a ticket. Body: { subject, body }.
pub async fn support_ticket_create(req: HttpRequest, state: web::Data<AppState>, body: web::Json<serde_json::Value>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let mut m = serde_json::Map::new();
    m.insert("subject".into(), body.get("subject").cloned().unwrap_or(serde_json::Value::String(String::new())));
    m.insert("body".into(), body.get("body").cloned().unwrap_or(serde_json::Value::String(String::new())));
    support_result(crate::support::call("create", m).await)
}

/// GET /api/support/tickets/{id} — ticket + messages (polled for chat).
pub async fn support_ticket_get(req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let mut m = serde_json::Map::new();
    m.insert("ticket_id".into(), serde_json::Value::String(path.into_inner()));
    support_result(crate::support::call("get", m).await)
}

/// POST /api/support/tickets/{id}/message — post a chat message. Body: { body }.
pub async fn support_ticket_message(req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>, body: web::Json<serde_json::Value>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let mut m = serde_json::Map::new();
    m.insert("ticket_id".into(), serde_json::Value::String(path.into_inner()));
    m.insert("body".into(), body.get("body").cloned().unwrap_or(serde_json::Value::String(String::new())));
    support_result(crate::support::call("message", m).await)
}

// ─── OIDC Authentication Endpoints ───
// ═══════════════════════════════════════════════════════════════════════════

/// GET /api/auth/oidc/providers — list available OIDC providers (no auth)
pub async fn oidc_providers() -> HttpResponse {
    if !crate::compat::platform_ready() {
        return HttpResponse::Ok().json(serde_json::json!([]));
    }
    let config = crate::auth::oidc::OidcConfig::load();
    if !config.enabled {
        return HttpResponse::Ok().json(serde_json::json!([]));
    }
    let providers: Vec<serde_json::Value> = config.providers.iter()
        .filter(|p| p.enabled)
        .map(|p| serde_json::json!({
            "id": p.id,
            "name": p.name,
            "button_label": format!("Sign in with {}", p.name),
        }))
        .collect();
    HttpResponse::Ok().json(providers)
}

/// Gate helper for the SSO admin endpoints — requires a licence that grants the
/// `sso` feature (Team / MSP / Enterprise). Returns Some(response) to short-
/// circuit when not entitled, None when allowed.
fn require_sso_feature() -> Option<HttpResponse> {
    if crate::compat::has_feature("sso") {
        None
    } else {
        Some(HttpResponse::Forbidden().json(serde_json::json!({
            "error": "Single Sign-On requires a Team, MSP or Enterprise licence."
        })))
    }
}

/// GET /api/auth/oidc/config — full OIDC config for the admin UI. Secrets are
/// NEVER returned (not even the encrypted blob) — only a `has_secret` flag.
/// Auth + `sso` feature required.
pub async fn oidc_get_config(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    if let Some(resp) = require_sso_feature() { return resp; }
    let config = crate::auth::oidc::OidcConfig::load();
    let providers: Vec<serde_json::Value> = config.providers.iter().map(|p| serde_json::json!({
        "id": p.id,
        "name": p.name,
        "issuer_url": p.issuer_url,
        "client_id": p.client_id,
        // Secret is write-only over the API. Tell the UI whether one is set so
        // it can show "configured" without ever shipping the value.
        "has_secret": !p.client_secret.is_empty(),
        "scopes": p.scopes,
        "role_claim": p.role_claim,
        "role_mappings": p.role_mappings,
        "enabled": p.enabled,
    })).collect();
    HttpResponse::Ok().json(serde_json::json!({
        "enabled": config.enabled,
        "providers": providers,
    }))
}

/// POST /api/auth/oidc/config — save OIDC config from the admin UI.
/// Auth + `sso` feature required. Secret handling: a provider whose
/// `client_secret` arrives EMPTY keeps its existing (encrypted) secret — the UI
/// never receives the secret, so empty means "unchanged". A non-empty value is
/// encrypted at rest (AES-256-GCM via the cluster secret).
pub async fn oidc_save_config(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<crate::auth::oidc::OidcConfig>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    if let Some(resp) = require_sso_feature() { return resp; }

    let existing = crate::auth::oidc::OidcConfig::load();
    let mut cfg = body.into_inner();

    let mut seen_ids: std::collections::HashSet<String> = std::collections::HashSet::new();
    for p in &mut cfg.providers {
        p.id = p.id.trim().to_string();
        p.name = p.name.trim().to_string();
        p.issuer_url = p.issuer_url.trim().trim_end_matches('/').to_string();
        p.client_id = p.client_id.trim().to_string();
        if p.scopes.trim().is_empty() {
            p.scopes = "openid profile email".to_string();
        }
        if p.id.is_empty() || p.name.is_empty() || p.issuer_url.is_empty() || p.client_id.is_empty() {
            return HttpResponse::BadRequest().json(serde_json::json!({
                "error": "Each provider needs a name, issuer URL and client ID."
            }));
        }
        // Block SSRF issuers (loopback / link-local / cloud-metadata) at SAVE
        // time. The saved issuer is fetched server-side during the (pre-auth)
        // login discovery, so validating here also protects that path — not just
        // the admin Test button.
        if let Err(e) = validate_outbound_url(&p.issuer_url) {
            return HttpResponse::BadRequest().json(serde_json::json!({
                "error": format!("Issuer URL for '{}': {}", p.name, e)
            }));
        }
        if !seen_ids.insert(p.id.clone()) {
            return HttpResponse::BadRequest().json(serde_json::json!({
                "error": format!("Duplicate provider id '{}'", p.id)
            }));
        }
        // Secret: empty = keep existing (UI never receives it); else encrypt.
        if p.client_secret.is_empty() {
            if let Some(old) = existing.providers.iter().find(|o| o.id == p.id) {
                p.client_secret = old.client_secret.clone();
            }
        } else {
            match crate::auth::oidc::encrypt_secret(&p.client_secret, &state.cluster_secret) {
                Ok(enc) => p.client_secret = enc,
                Err(e) => return HttpResponse::InternalServerError().json(serde_json::json!({
                    "error": format!("Failed to encrypt client secret: {}", e)
                })),
            }
        }
        // A provider can't actually be used without a secret (confidential
        // client). Surface that as a clear error rather than a silent broken login.
        if p.enabled && p.client_secret.is_empty() {
            return HttpResponse::BadRequest().json(serde_json::json!({
                "error": format!("Provider '{}' is enabled but has no client secret.", p.name)
            }));
        }
    }

    match cfg.save() {
        Ok(()) => HttpResponse::Ok().json(serde_json::json!({ "status": "ok" })),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({ "error": e })),
    }
}

#[derive(Deserialize)]
pub struct OidcTestRequest {
    pub issuer_url: String,
}

/// POST /api/auth/oidc/test — probe an issuer's discovery document so the
/// operator can validate the URL before saving. Auth + `sso` feature required.
pub async fn oidc_test_discovery(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<OidcTestRequest>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    if let Some(resp) = require_sso_feature() { return resp; }
    let issuer = body.issuer_url.trim().trim_end_matches('/');
    if let Err(e) = validate_outbound_url(issuer) {
        return HttpResponse::Ok().json(serde_json::json!({ "ok": false, "error": e }));
    }
    match crate::auth::oidc::probe_discovery(issuer).await {
        Ok((auth_ep, token_ep)) => HttpResponse::Ok().json(serde_json::json!({
            "ok": true,
            "authorization_endpoint": auth_ep,
            "token_endpoint": token_ep,
        })),
        Err(e) => HttpResponse::Ok().json(serde_json::json!({ "ok": false, "error": e })),
    }
}

/// GET /api/auth/oidc/login/{provider_id} — initiate OIDC login (no auth, returns 302)
pub async fn oidc_login(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
) -> HttpResponse {
    let provider_id = path.into_inner();
    let config = crate::auth::oidc::OidcConfig::load();
    if !config.enabled {
        return HttpResponse::BadRequest().json(serde_json::json!({ "error": "OIDC is not enabled" }));
    }
    let provider = match config.providers.iter().find(|p| p.id == provider_id && p.enabled) {
        Some(p) => p.clone(),
        None => return HttpResponse::NotFound().json(serde_json::json!({ "error": "Provider not found" })),
    };

    let conn = req.connection_info();
    let redirect_uri_base = format!("{}://{}", conn.scheme(), conn.host());

    match crate::auth::oidc::build_auth_url(&provider, &redirect_uri_base).await {
        Ok((auth_url, pending)) => {
            let csrf_state = pending.csrf_state.clone();
            state.oidc_pending_flows.write().unwrap().insert(csrf_state, pending);
            HttpResponse::Found().append_header(("Location", auth_url)).finish()
        }
        Err(e) => {
            error!("OIDC build_auth_url failed: {}", e);
            HttpResponse::InternalServerError().json(serde_json::json!({ "error": e }))
        }
    }
}

#[derive(Deserialize)]
pub struct OidcCallbackQuery {
    pub code: String,
    pub state: String,
}

/// GET /api/auth/oidc/callback — OIDC callback (no auth, returns 302 to dashboard)
pub async fn oidc_callback(
    req: HttpRequest,
    state: web::Data<AppState>,
    query: web::Query<OidcCallbackQuery>,
) -> HttpResponse {
    // Look up and remove the pending flow (single use)
    let pending = {
        let mut flows = state.oidc_pending_flows.write().unwrap();
        flows.remove(&query.state)
    };
    let pending = match pending {
        Some(p) => p,
        None => return HttpResponse::BadRequest().json(serde_json::json!({
            "error": "Invalid or expired OIDC state token"
        })),
    };

    // Find the provider
    let config = crate::auth::oidc::OidcConfig::load();
    let provider = match config.providers.iter().find(|p| p.id == pending.provider_id) {
        Some(p) => p.clone(),
        None => return HttpResponse::InternalServerError().json(serde_json::json!({
            "error": "OIDC provider no longer configured"
        })),
    };

    let conn = req.connection_info();
    let redirect_uri_base = format!("{}://{}", conn.scheme(), conn.host());

    // Exchange the authorization code for claims
    let claims = match crate::auth::oidc::exchange_code(
        &provider, &query.code, &pending, &redirect_uri_base, &state.cluster_secret,
    ).await {
        Ok(c) => c,
        Err(e) => {
            error!("OIDC code exchange failed: {}", e);
            return HttpResponse::InternalServerError().json(serde_json::json!({ "error": e }));
        }
    };

    // Extract username from claims (preferred_username → email → sub)
    let username = claims.get("preferred_username")
        .or_else(|| claims.get("email"))
        .or_else(|| claims.get("sub"))
        .and_then(|v| v.as_str())
        .unwrap_or("oidc-user")
        .to_string();

    // Map IdP claims to a WolfStack role using the provider's role_claim + role_mappings
    let role = crate::auth::oidc::map_claims_to_role(&claims, &provider);
    tracing::info!("OIDC login: user='{}', provider='{}', role='{}'", username, provider.id, role);

    // Create session and set cookie
    let token = state.sessions.create_session(&username);
    let mut cookie = Cookie::build("wolfstack_session", &token)
        .path("/")
        .http_only(true)
        .same_site(actix_web::cookie::SameSite::Lax)
        .max_age(actix_web::cookie::time::Duration::hours(8))
        .finish();
    if state.tls_enabled {
        cookie.set_secure(true);
    }

    HttpResponse::Found()
        .cookie(cookie)
        .append_header(("Location", "/index.html"))
        .finish()
}

