// ─── Federation API ───
//
// Cross-cluster registry — each entry is "another WolfStack cluster
// I trust to read shares (and future inventory) from". Stored at
// /etc/wolfstack/federations.json (mode 0600).

#[derive(Deserialize)]
pub struct FederationCreateRequest {
    pub name: String,
    pub base_url: String,
    pub api_key: String,
    #[serde(default)] pub insecure_tls: bool,
    /// Optional — when updating an existing entry. Empty means create.
    #[serde(default)] pub id: String,
}

/// GET /api/federations — list (api_key redacted).
pub async fn federations_list(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let s = state.federations.read().unwrap_or_else(|e| e.into_inner());
    HttpResponse::Ok().json(s.redacted())
}

/// POST /api/federations — create or update (id present = update).
pub async fn federations_save(req: HttpRequest, state: web::Data<AppState>, body: web::Json<FederationCreateRequest>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let body = body.into_inner();
    let entry = crate::federation::FederatedCluster {
        id: body.id,
        name: body.name,
        base_url: body.base_url,
        api_key: body.api_key,
        insecure_tls: body.insecure_tls,
        created_at: String::new(),
        last_ok_unix: 0,
        last_error: None,
    };
    if let Err(errs) = crate::federation::validate(&entry) {
        return HttpResponse::BadRequest().json(serde_json::json!({ "errors": errs }));
    }
    let stored = {
        let mut s = state.federations.write().unwrap_or_else(|e| e.into_inner());
        let stored = s.upsert(entry);
        if let Err(e) = s.save() {
            tracing::warn!(target: "wolfstack::federation", "save failed: {}", e);
        }
        stored
    };
    invalidate_gateway_cluster_cache(&state);
    invalidate_array_cluster_cache(&state);
    HttpResponse::Ok().json(serde_json::json!({
        "id": stored.id,
        "name": stored.name,
        "base_url": stored.base_url,
    }))
}

/// DELETE /api/federations/{id} — remove an entry.
pub async fn federations_delete(req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let id = path.into_inner();
    let removed = {
        let mut s = state.federations.write().unwrap_or_else(|e| e.into_inner());
        let removed = s.remove(&id);
        if removed { let _ = s.save(); }
        removed
    };
    if removed {
        invalidate_gateway_cluster_cache(&state);
        invalidate_array_cluster_cache(&state);
        HttpResponse::Ok().json(serde_json::json!({ "deleted": id }))
    } else {
        HttpResponse::NotFound().json(serde_json::json!({ "error": "federation not found" }))
    }
}

/// POST /api/federations/{id}/test — issue a probe call to verify the
/// entry works. Returns timing + error chain like AI test-connection.
pub async fn federations_test(req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let id = path.into_inner();
    let entry = {
        let s = state.federations.read().unwrap_or_else(|e| e.into_inner());
        match s.clusters.iter().find(|c| c.id == id) {
            Some(c) => c.clone(),
            None => return HttpResponse::NotFound().json(serde_json::json!({ "error": "federation not found" })),
        }
    };
    let started = std::time::Instant::now();
    // Probe the cheapest endpoint that requires auth — `/api/agent/status`
    // works on every WolfStack release back to the API-key landing.
    let result = crate::federation::fetch_json(&entry, "/api/agent/status").await;
    let elapsed_ms = started.elapsed().as_millis() as u64;

    // Update last_ok / last_error so the UI badge reflects this probe.
    {
        let mut s = state.federations.write().unwrap_or_else(|e| e.into_inner());
        if let Some(c) = s.clusters.iter_mut().find(|c| c.id == id) {
            match &result {
                Ok(_) => {
                    c.last_ok_unix = std::time::SystemTime::now()
                        .duration_since(std::time::UNIX_EPOCH).map(|d| d.as_secs()).unwrap_or(0);
                    c.last_error = None;
                }
                Err(e) => {
                    c.last_error = Some(e.clone());
                }
            }
        }
        let _ = s.save();
    }
    match result {
        Ok(_) => HttpResponse::Ok().json(serde_json::json!({
            "ok": true, "elapsed_ms": elapsed_ms,
            "name": entry.name, "base_url": entry.base_url,
        })),
        Err(e) => HttpResponse::Ok().json(serde_json::json!({
            "ok": false, "elapsed_ms": elapsed_ms,
            "name": entry.name, "base_url": entry.base_url,
            "error": e,
        })),
    }
}

/// POST /api/gateways/sync — receive a peer's gateway snapshot.
/// Inter-node only (X-WolfStack-Secret header).
pub async fn gateways_sync(req: HttpRequest, state: web::Data<AppState>, body: web::Json<Vec<crate::gateway::Gateway>>) -> HttpResponse {
    let provided = req.headers().get("X-WolfStack-Secret")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    // Stage 5 — gate default-secret acceptance via the shared helper.
    if !crate::auth::validate_inter_node_secret(provided, &state.cluster_secret)
    {
        return HttpResponse::Unauthorized().finish();
    }
    let incoming = body.into_inner();
    let changed = {
        let mut s = state.gateways.write().unwrap_or_else(|e| e.into_inner());
        s.merge_from_peer(incoming)
    };
    if changed {
        let s = state.gateways.read().unwrap_or_else(|e| e.into_inner());
        let _ = s.save();
        invalidate_gateway_cluster_cache(&state);
    }
    HttpResponse::Ok().json(serde_json::json!({ "merged": changed }))
}

// ─── Gateway internals ───

/// Append a gateway audit entry to the shared alert_log. Surfaced in
/// the Tasks panel so operators see who created/edited/deleted what.
/// `actor` is the username string returned by `require_auth` — either
/// a real account, "cluster-node" for inter-node calls, or
/// "apikey:<name>" for API-key authenticated mutations.
fn gateway_audit(
    state: &web::Data<AppState>,
    actor: &str,
    severity: &str,
    title: &str,
    detail: &str,
) {
    let now = chrono::Utc::now().format("%Y-%m-%d %H:%M:%S UTC").to_string();
    let hostname = state.cluster.get_all_nodes().into_iter()
        .find(|n| n.is_self).map(|n| n.hostname).unwrap_or_default();
    let cluster = state.cluster.get_self_cluster_name();
    let mut log = state.alert_log.write().unwrap_or_else(|e| e.into_inner());
    let id = log.last().map(|e| e.id + 1).unwrap_or(1);
    log.push(AlertLogEntry {
        id,
        timestamp: now,
        severity: severity.into(),
        title: title.into(),
        detail: format!("{} (by {})", detail, actor),
        hostname,
        cluster,
    });
    while log.len() > 200 {
        log.remove(0);
    }
}

/// Verify the local node owns the gateway. Returns 409 with a clear
/// "open the originating cluster" message otherwise — only the owner
/// node serves the SMB/NFS daemons, so a remote mutation here would
/// lie about taking effect.
fn require_owner<'a>(
    state: &web::Data<AppState>,
    id: &str,
) -> Result<crate::gateway::Gateway, HttpResponse> {
    let s = state.gateways.read().unwrap_or_else(|e| e.into_inner());
    let Some(g) = s.get(id).cloned() else {
        return Err(HttpResponse::NotFound().json(serde_json::json!({ "error": "gateway not found" })));
    };
    if g.origin_node_id != state.node_id && !g.origin_node_id.is_empty() {
        return Err(HttpResponse::Conflict().json(serde_json::json!({
            "error": format!(
                "this share is served from node '{}'. Open that node's dashboard to manage it — \
                 v1.0 single-node-serve doesn't support cross-node mutation.",
                g.origin_node_id
            ),
            "origin_node_id": g.origin_node_id,
        })));
    }
    Ok(g)
}

async fn apply_and_persist(state: &web::Data<AppState>, g: crate::gateway::Gateway, id: &str) -> HttpResponse {
    // Apply first — if mounting/daemon-config fails, don't persist
    // a half-broken gateway. On failure, immediately tear down so a
    // partial Samba snippet or stale mount doesn't leak between
    // create attempts.
    let stored = match crate::gateway::orchestrator::apply(&g) {
        Ok(rt) => {
            let mut s = state.gateways.write().unwrap_or_else(|e| e.into_inner());
            let stored = s.upsert(g.clone());
            s.runtime.insert(id.to_string(), rt);
            if let Err(e) = s.save() {
                tracing::warn!(target: "wolfstack::gateway", "save failed: {}", e);
            }
            stored
        }
        Err(e) => {
            crate::gateway::orchestrator::teardown(&g);
            return HttpResponse::InternalServerError().json(serde_json::json!({
                "error": e.to_string(),
            }));
        }
    };
    invalidate_gateway_cluster_cache(state);
    // Post-persist orphan-user prune — must run after the new
    // gateway is on disk so the active-users set is current.
    crate::gateway::samba::reconcile_managed_users();
    push_to_peers(state).await;
    let s = state.gateways.read().unwrap_or_else(|e| e.into_inner());
    HttpResponse::Ok().json(gateway_to_json(&stored, &s))
}

/// Push the local gateway snapshot to every online wolfstack peer.
/// Best-effort — peers that are slow / offline catch up on their next
/// boot via merge_from_peer in the receive path.
async fn push_to_peers(state: &web::Data<AppState>) {
    let snapshot: Vec<crate::gateway::Gateway> = {
        let s = state.gateways.read().unwrap_or_else(|e| e.into_inner());
        crate::gateway::snapshot_for_sync(&s)
    };
    let peers: Vec<_> = state.cluster.get_all_nodes().into_iter()
        .filter(|n| !n.is_self && n.node_type == "wolfstack" && n.online)
        .collect();
    if peers.is_empty() { return; }
    let secret = state.cluster_secret.clone();
    let client = (*API_HTTP_CLIENT).clone();
    tokio::spawn(async move {
        for peer in peers {
            let urls = build_node_urls(&peer.address, peer.port, "/api/gateways/sync");
            for url in urls {
                let res = client.post(&url)
                    .timeout(std::time::Duration::from_secs(5))
                    .header("X-WolfStack-Secret", &secret)
                    .json(&snapshot)
                    .send().await;
                if let Ok(resp) = res {
                    let success = resp.status().is_success();
                    let _ = resp.bytes().await;
                    if success { break; }
                }
            }
        }
    });
}

// ─── Xen Orchestra / XCP-ng integration (P1: read-only inventory) ─

/// Validate a hostname / VM name as RFC 1123: 1–63 chars,
/// alphanumeric or hyphen, must start and end with alphanumeric.
/// Used everywhere we interpolate user input into shell or YAML
/// downstream (cloud-init, hostnamectl, XO `name_label`).
fn is_valid_hostname(s: &str) -> bool {
    let s = s.trim();
    if s.is_empty() || s.len() > 63 { return false; }
    let bytes = s.as_bytes();
    let alnum = |b: u8| b.is_ascii_alphanumeric();
    if !alnum(bytes[0]) || !alnum(bytes[bytes.len() - 1]) { return false; }
    bytes.iter().all(|&b| alnum(b) || b == b'-')
}

// ─── TrueNAS integration ────────────────────────────────────────────
// Multi-instance external NAS appliances. Mirrors the XO handlers: API keys
// stay encrypted in the store and are never returned to the browser; the store
// is loaded per-request (admin-only, low-frequency UI actions).

#[derive(serde::Deserialize)]
pub struct TrueNasRegisterRequest {
    pub label: String,
    #[serde(default)] pub cluster: Option<String>,
    pub api_url: String,
    pub api_key: String,
    #[serde(default)] pub pool_name: String,
    #[serde(default = "tn_default_insecure")] pub insecure_tls: bool,
    #[serde(default = "tn_default_ttl")] pub cache_ttl_secs: u64,
}
fn tn_default_insecure() -> bool { true }
fn tn_default_ttl() -> u64 { 300 }

#[derive(serde::Deserialize)]
pub struct TrueNasUpdateRequest {
    pub label: String,
    #[serde(default)] pub cluster: Option<String>,
    pub api_url: String,
    #[serde(default)] pub pool_name: String,
    #[serde(default = "tn_default_insecure")] pub insecure_tls: bool,
    #[serde(default = "tn_default_ttl")] pub cache_ttl_secs: u64,
    /// Blank/absent = keep the stored key.
    #[serde(default)] pub api_key: Option<String>,
}

#[derive(serde::Deserialize)]
pub struct TrueNasSnapshotCreateRequest {
    pub dataset: String,
    pub name: String,
    #[serde(default)] pub recursive: bool,
}

/// GET /api/truenas/instances — registered TrueNAS servers (keys redacted).
pub async fn truenas_list(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let list = crate::truenas::TrueNasStore::load().list();
    let safe: Vec<serde_json::Value> = list.iter().map(|i| i.redacted()).collect();
    HttpResponse::Ok().json(safe)
}

/// POST /api/truenas/instances — register a server (test-connection before persist).
pub async fn truenas_register(
    req: HttpRequest, state: web::Data<AppState>, body: web::Json<TrueNasRegisterRequest>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let r = body.into_inner();
    if r.label.trim().is_empty() || r.api_url.trim().is_empty() || r.api_key.trim().is_empty() {
        return HttpResponse::BadRequest().json(serde_json::json!({"error": "label, api_url and api_key are all required"}));
    }
    if let Err(e) = validate_outbound_url(&r.api_url) {
        return HttpResponse::BadRequest().json(serde_json::json!({"error": e}));
    }
    let mut inst = crate::truenas::TrueNasInstance {
        id: String::new(),
        label: r.label.trim().to_string(),
        // Strict cluster scoping (v24.38.4): a registration is never
        // cluster-less. Omitted/blank (older UI, raw API calls) defaults to
        // this node's own cluster — the instance lives in this node's store.
        cluster: r.cluster.filter(|c| !c.trim().is_empty())
            .or_else(|| Some(crate::agent::ClusterState::self_cluster_label())),
        api_url: r.api_url.trim().trim_end_matches('/').to_string(),
        api_key_enc: crate::truenas::obfuscate_key(r.api_key.trim()),
        pool_name: r.pool_name.trim().to_string(),
        insecure_tls: r.insecure_tls,
        cache_ttl_secs: r.cache_ttl_secs,
        last_seen: String::new(),
        status: String::new(),
    };
    // Verify the key/URL work before storing — bad creds never persist.
    let client = crate::truenas::TrueNasClient::for_instance(&inst);
    match client.test_connection().await {
        Ok(_) => { inst.status = "ok".into(); inst.last_seen = chrono::Utc::now().to_rfc3339(); }
        Err(e) => return HttpResponse::BadGateway().json(serde_json::json!({"error": format!("Couldn't reach the TrueNAS API: {}", e)})),
    }
    let mut store = crate::truenas::TrueNasStore::load();
    match store.add(inst) {
        Ok(id) => HttpResponse::Created().json(serde_json::json!({"id": id, "status": "ok"})),
        Err(e) => HttpResponse::InternalServerError().json(serde_json::json!({"error": e})),
    }
}

/// PUT /api/truenas/instances/{id} — edit a server (blank api_key keeps the stored one).
pub async fn truenas_update(
    req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>, body: web::Json<TrueNasUpdateRequest>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let id = path.into_inner();
    let r = body.into_inner();
    if let Err(e) = validate_outbound_url(&r.api_url) {
        return HttpResponse::BadRequest().json(serde_json::json!({"error": e}));
    }
    let mut store = crate::truenas::TrueNasStore::load();
    match store.update(&id, r.label.trim().to_string(),
        r.cluster.filter(|c| !c.trim().is_empty()),
        r.api_url.trim().trim_end_matches('/').to_string(),
        r.pool_name.trim().to_string(), r.insecure_tls, r.cache_ttl_secs, r.api_key)
    {
        Ok(_) => HttpResponse::Ok().json(serde_json::json!({"status": "updated"})),
        // Same 400-vs-404 split as the Unraid handler (code review 2026-06-11).
        Err(e) if e.contains("not found") => HttpResponse::NotFound().json(serde_json::json!({"error": e})),
        Err(e) => HttpResponse::BadRequest().json(serde_json::json!({"error": e})),
    }
}

/// DELETE /api/truenas/instances/{id} — unregister a server.
pub async fn truenas_delete(
    req: HttpRequest, state: web::Data<AppState>, path: web::Path<String>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let id = path.into_inner();
    match crate::truenas::TrueNasStore::load().remove(&id) {
        Ok(_) => HttpResponse::Ok().json(serde_json::json!({"status": "removed"})),
        Err(e) => HttpResponse::NotFound().json(serde_json::json!({"error": e})),
    }
}

