// ═══════════════════════════════════════════════════
// ─── SQL Connections API ───
// ═══════════════════════════════════════════════════

/// GET /api/sql-connections — list every configured connection with
/// passwords masked (just `has_password: true|false`).
///
/// Enterprise: filters connections by the caller's username against
/// `SqlConnection::allowed_users`. Empty allowlist = visible to all
/// (the default, and the only behaviour on the free tier).
/// Cluster-node callers always see everything — profiles are
/// cluster-wide config, not per-user scope, and the proxy endpoint
/// needs to resolve profiles regardless of who initiated.
pub async fn sql_connections_list(req: HttpRequest, state: web::Data<AppState>) -> HttpResponse {
    let caller = match require_auth(&req, &state) {
        Ok(c) => c,
        Err(resp) => return resp,
    };
    let enterprise = crate::compat::platform_ready();
    let is_cluster_node = caller == "cluster-node";
    let cfg = crate::sql_connections::load();
    let safe: Vec<serde_json::Value> = cfg.connections.iter()
        .filter(|c| is_cluster_node || c.user_permitted(&caller, enterprise))
        .map(|c| c.to_safe_json())
        .collect();
    HttpResponse::Ok().json(serde_json::json!({ "connections": safe }))
}

/// POST /api/sql-connections — create a new profile. Body is the
/// SqlConnection struct with plaintext password; we encrypt before
/// persisting. `id` is optional — if empty we generate one.
pub async fn sql_connections_create(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<crate::sql_connections::SqlConnection>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let mut conn = body.into_inner();
    if conn.id.trim().is_empty() {
        conn.id = crate::sql_connections::gen_id(&conn.label);
    }
    let mut cfg = crate::sql_connections::load();
    if cfg.connections.iter().any(|c| c.id == conn.id) {
        return HttpResponse::Conflict().json(serde_json::json!({
            "error": format!("connection id '{}' already exists", conn.id)
        }));
    }
    if let Err(e) = crate::sql_connections::prepare_for_save(&mut conn, None, &state.cluster_secret) {
        return HttpResponse::InternalServerError().json(serde_json::json!({ "error": e }));
    }
    cfg.connections.push(conn.clone());
    if let Err(e) = crate::sql_connections::save(&cfg) {
        return HttpResponse::InternalServerError().json(serde_json::json!({ "error": e }));
    }
    // Fan-out: every WolfStack peer needs this profile so queries to
    // its node_id can be served cluster-wide.
    replicate_sql_connections_to_cluster(state.clone());
    HttpResponse::Ok().json(serde_json::json!({ "connection": conn.to_safe_json() }))
}

/// PUT /api/sql-connections/{id} — update existing. Empty password
/// means "keep the existing one".
pub async fn sql_connections_update(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
    body: web::Json<crate::sql_connections::SqlConnection>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let id = path.into_inner();
    let mut cfg = crate::sql_connections::load();
    let idx = match cfg.connections.iter().position(|c| c.id == id) {
        Some(i) => i,
        None => return HttpResponse::NotFound().json(serde_json::json!({ "error": "not found" })),
    };
    let mut incoming = body.into_inner();
    incoming.id = id.clone();
    let existing = cfg.connections[idx].clone();
    if let Err(e) = crate::sql_connections::prepare_for_save(&mut incoming, Some(&existing), &state.cluster_secret) {
        return HttpResponse::InternalServerError().json(serde_json::json!({ "error": e }));
    }
    cfg.connections[idx] = incoming.clone();
    if let Err(e) = crate::sql_connections::save(&cfg) {
        return HttpResponse::InternalServerError().json(serde_json::json!({ "error": e }));
    }
    // save() already drops all pools; no extra invalidation needed.
    replicate_sql_connections_to_cluster(state.clone());
    HttpResponse::Ok().json(serde_json::json!({ "connection": incoming.to_safe_json() }))
}

#[derive(Deserialize)]
pub struct SqlPasswordBody {
    pub password: String,
}

/// POST /api/sql-connections/{id}/password — recovery after a cluster-secret
/// rotation orphaned the stored password (decrypt fails). Re-encrypts the
/// supplied password under the CURRENT cluster secret, re-saves, and re-
/// replicates so every peer (which now shares the rotated secret) can decrypt
/// it. The UI calls this when it sees `error_code: password_decrypt_failed`.
pub async fn sql_connections_set_password(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
    body: web::Json<SqlPasswordBody>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let id = path.into_inner();
    match crate::sql_connections::set_connection_password(&id, &body.password, &state.cluster_secret) {
        Ok(()) => {
            replicate_sql_connections_to_cluster(state.clone());
            HttpResponse::Ok().json(serde_json::json!({ "ok": true }))
        }
        Err(e) => HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
    }
}

/// DELETE /api/sql-connections/{id}
pub async fn sql_connections_delete(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let id = path.into_inner();
    let mut cfg = crate::sql_connections::load();
    let before = cfg.connections.len();
    cfg.connections.retain(|c| c.id != id);
    if cfg.connections.len() == before {
        return HttpResponse::NotFound().json(serde_json::json!({ "error": "not found" }));
    }
    if let Err(e) = crate::sql_connections::save(&cfg) {
        return HttpResponse::InternalServerError().json(serde_json::json!({ "error": e }));
    }
    replicate_sql_connections_to_cluster(state.clone());
    HttpResponse::Ok().json(serde_json::json!({ "deleted": id }))
}

/// POST /api/sql-connections/{id}/test — attempt a connection and run
/// a cheap probe (SELECT VERSION() / SELECT version()). Returns the
/// server version on success so the operator can eyeball it.
/// When a SQL operation fails because the stored password can't be decrypted
/// (the cluster secret was rotated since it was saved), return a structured
/// 409 the Database Manager keys off to re-prompt for the password and re-save
/// it under the current secret. Returns None for any other error.
fn sql_decrypt_error_response(e: &str, id: &str) -> Option<HttpResponse> {
    if crate::sql_connections::is_password_decrypt_error(e) {
        Some(HttpResponse::Conflict().json(serde_json::json!({
            "error": e,
            "error_code": "password_decrypt_failed",
            "connection_id": id,
        })))
    } else {
        None
    }
}

pub async fn sql_connections_test(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let id = path.into_inner();
    let cfg = crate::sql_connections::load();
    let conn = match cfg.connections.iter().find(|c| c.id == id) {
        Some(c) => c.clone(),
        None => return HttpResponse::NotFound().json(serde_json::json!({ "error": "not found" })),
    };
    match crate::sql_connections::test(&conn, &state.cluster_secret, Some(&state.cluster)).await {
        Ok(version) => HttpResponse::Ok().json(serde_json::json!({
            "ok": true, "version": version,
        })),
        Err(e) => {
            // Surface the re-prompt signal even on the test path so "Test
            // connection" after a secret rotation guides the operator to fix it.
            let needs_pw = crate::sql_connections::is_password_decrypt_error(&e);
            HttpResponse::Ok().json(serde_json::json!({
                "ok": false,
                "error": e,
                "error_code": if needs_pw { "password_decrypt_failed" } else { "" },
                "connection_id": id,
            }))
        }
    }
}

#[derive(Deserialize)]
pub struct SqlQueryRequest {
    pub query: String,
    #[serde(default)]
    pub permission: Option<String>,  // "read" | "update" | "delete" | "schema"
    #[serde(default)]
    pub timeout_secs: Option<u64>,
    #[serde(default)]
    pub schema: Option<String>,       // optional DB/search_path override
}

/// POST /api/sql-connections/{id}/validate — parse-only check.
///
/// Runs the SQL through the same `sqlparser` classifier as the
/// executor, but never dispatches to the database. Returns the
/// detected permission tier (`read` / `update` / `delete`) so the
/// UI can preview what tier a query will need before the operator
/// clicks Run, or flag a parse error inline without round-tripping
/// to a live database.
pub async fn sql_connections_validate(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
    body: web::Json<SqlQueryRequest>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let id = path.into_inner();
    let cfg = crate::sql_connections::load();
    let conn = match cfg.connections.iter().find(|c| c.id == id) {
        Some(c) => c.clone(),
        None => return HttpResponse::NotFound().json(serde_json::json!({ "error": "not found" })),
    };
    match crate::sql_connections::classify(&body.query, conn.kind) {
        Ok(tier) => {
            let tier_str = match tier {
                crate::sql_connections::SqlPermission::Read => "read",
                crate::sql_connections::SqlPermission::Update => "update",
                crate::sql_connections::SqlPermission::Delete => "delete",
                crate::sql_connections::SqlPermission::Schema => "schema",
            };
            HttpResponse::Ok().json(serde_json::json!({ "ok": true, "tier": tier_str }))
        }
        Err(e) => HttpResponse::Ok().json(serde_json::json!({ "ok": false, "error": e })),
    }
}

/// POST /api/sql-connections/{id}/query — ad-hoc query from the
/// Settings UI (the "Run query" button on a connection). Requires
/// logged-in auth. Audit-logs as `ui:<username>`.
pub async fn sql_connections_query(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
    body: web::Json<SqlQueryRequest>,
) -> HttpResponse {
    // require_auth returns Ok(principal) — either the session username
    // or "cluster-node" / "api-key:<id>" for non-interactive callers.
    // That's exactly what we want to stamp into the audit log.
    let username = match require_auth(&req, &state) {
        Ok(u) => u,
        Err(resp) => return resp,
    };
    let id = path.into_inner();

    // Enterprise per-user ACL. Cluster-secret callers are exempt —
    // they're the query-proxy path or an internal subsystem.
    if username != "cluster-node" {
        let enterprise = crate::compat::platform_ready();
        let cfg = crate::sql_connections::load();
        if let Some(conn) = cfg.connections.iter().find(|c| c.id == id) {
            if !conn.user_permitted(&username, enterprise) {
                return HttpResponse::Forbidden().json(serde_json::json!({
                    "error": format!(
                        "user '{}' is not in the allowed_users list for connection '{}'",
                        username, id
                    )
                }));
            }
        }
    }

    let perm = match body.permission.as_deref().unwrap_or("read") {
        "schema" => crate::sql_connections::SqlPermission::Schema,
        "delete" => crate::sql_connections::SqlPermission::Delete,
        "update" => crate::sql_connections::SqlPermission::Update,
        _ => crate::sql_connections::SqlPermission::Read,
    };
    let timeout = body.timeout_secs.map(std::time::Duration::from_secs);
    let caller_username = username.clone();
    let schema = body.schema.as_deref();
    match crate::sql_connections::execute_with_schema(
        &id, &body.query, perm,
        crate::sql_connections::Caller::Ui(username),
        &state.cluster_secret,
        timeout,
        Some(&state.cluster),
        schema,
    ).await {
        Ok(r) => {
            // Record in per-user history (non-blocking — failure just
            // means the dropdown won't show this query later).
            if caller_username != "cluster-node" {
                let _ = crate::sql_connections::push_history(&caller_username, &id, &body.query);
            }
            HttpResponse::Ok().json(r)
        }
        Err(e) => {
            if let Some(r) = sql_decrypt_error_response(&e, &id) { return r; }
            HttpResponse::BadRequest().json(serde_json::json!({ "error": e }))
        }
    }
}

#[derive(Deserialize)]
pub struct SavedQueryBody {
    pub name: String,
    pub sql: String,
}

#[derive(Deserialize)]
pub struct SqlMultiRequest {
    pub statements: Vec<String>,
    #[serde(default)]
    pub permission: Option<String>,
    #[serde(default)]
    pub timeout_secs: Option<u64>,
    #[serde(default)]
    pub stop_on_error: Option<bool>,  // default true
    #[serde(default)]
    pub schema: Option<String>,
}

/// POST /api/sql-connections/{id}/query-multi — run a batch of
/// statements one at a time. Used by:
///   - the Database Manager's "Execute SQL file" upload flow
///   - dump-restore and bulk INSERT paths that would otherwise round-
///     trip hundreds of single-statement requests
///
/// Each statement is classified + executed independently (the classifier
/// rejects stacked statements, so we split up-front on the client).
/// Returns a per-statement outcome array so the UI can report "stmt 47
/// failed at byte N" without losing the successes before it.
pub async fn sql_connections_query_multi(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
    body: web::Json<SqlMultiRequest>,
) -> HttpResponse {
    let username = match require_auth(&req, &state) {
        Ok(u) => u,
        Err(resp) => return resp,
    };
    let id = path.into_inner();

    // ACL check identical to /query.
    if username != "cluster-node" {
        let enterprise = crate::compat::platform_ready();
        let cfg = crate::sql_connections::load();
        if let Some(conn) = cfg.connections.iter().find(|c| c.id == id) {
            if !conn.user_permitted(&username, enterprise) {
                return HttpResponse::Forbidden().json(serde_json::json!({
                    "error": format!("user '{}' is not in the allowed_users list for connection '{}'", username, id)
                }));
            }
        }
    }

    let perm = match body.permission.as_deref().unwrap_or("read") {
        "schema" => crate::sql_connections::SqlPermission::Schema,
        "delete" => crate::sql_connections::SqlPermission::Delete,
        "update" => crate::sql_connections::SqlPermission::Update,
        _ => crate::sql_connections::SqlPermission::Read,
    };
    let timeout = body.timeout_secs.map(std::time::Duration::from_secs);
    let stop_on_error = body.stop_on_error.unwrap_or(true);

    let mut results = Vec::with_capacity(body.statements.len());
    let mut failed_at: Option<usize> = None;
    for (i, stmt) in body.statements.iter().enumerate() {
        let s = stmt.trim();
        if s.is_empty() { results.push(serde_json::json!({ "skipped": true })); continue; }
        let caller = crate::sql_connections::Caller::Ui(username.clone());
        match crate::sql_connections::execute_with_schema(
            &id, s, perm, caller, &state.cluster_secret, timeout, Some(&state.cluster),
            body.schema.as_deref(),
        ).await {
            Ok(r) => results.push(serde_json::json!({
                "ok": true,
                "row_count": r.row_count,
                "affected_rows": r.affected_rows,
                "elapsed_ms": r.elapsed_ms,
            })),
            Err(e) => {
                // A decrypt failure hits every statement identically — short-
                // circuit with the re-prompt signal instead of N copies.
                if let Some(r) = sql_decrypt_error_response(&e, &id) { return r; }
                results.push(serde_json::json!({ "ok": false, "error": e }));
                if stop_on_error { failed_at = Some(i); break; }
            }
        }
    }
    HttpResponse::Ok().json(serde_json::json!({
        "results": results,
        "failed_at": failed_at,
        "total": body.statements.len(),
    }))
}

