#[derive(Deserialize)]
pub struct SqlProxyRequest {
    pub query: String,
    #[serde(default)]
    pub permission: Option<String>,
    #[serde(default)]
    pub timeout_secs: Option<u64>,
    #[serde(default)]
    pub schema: Option<String>,
    /// Opaque caller tag from the originator — included in the target
    /// node's audit log so a trace like "ui:paul via wolfstack-1 →
    /// wolfstack-2" is visible on every hop.
    #[serde(default)]
    pub origin_caller: Option<String>,
}

/// GET /api/nodes/{id}/ips — enumerate IPs reachable FROM that node,
/// for the SQL-connections IP picker. Returns local interfaces, the
/// WolfNet overlay range (if configured), Docker and LXC container
/// IPs (with container name for quick recognition), and VM WolfNet
/// IPs (with VM name). Session auth — operator-only.
///
/// When `id == self`, enumeration happens locally. Otherwise we
/// cluster-secret-proxy the same call to the target peer, which runs
/// it in its own local context and returns the list. No port-scanning
/// or probing — the node just reports IPs it is already aware of.
pub async fn node_ips_list(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
) -> HttpResponse {
    if let Err(resp) = require_auth(&req, &state) { return resp; }
    let node_id = path.into_inner();
    let self_id = crate::agent::self_node_id();

    if node_id == self_id {
        return HttpResponse::Ok().json(serde_json::json!({
            "node_id": node_id,
            "ips": enumerate_local_ips(&state).await,
        }));
    }

    // Remote — find the peer and proxy the same URL with cluster secret.
    let peer = match state.cluster.get_node(&node_id) {
        Some(n) => n,
        None => return HttpResponse::NotFound().json(serde_json::json!({
            "error": format!("node '{}' not found in cluster state", node_id)
        })),
    };
    if !peer.online {
        return HttpResponse::Ok().json(serde_json::json!({
            "node_id": node_id,
            "ips": [],
            "error": format!("peer '{}' is offline", peer.hostname),
        }));
    }

    let urls = build_node_urls(&peer.address, peer.port,
        &format!("/api/nodes/{}/ips", urlencoding_simple(&node_id)));
    let client = &*API_HTTP_CLIENT;
    for url in &urls {
        match client.get(url)
            .header("X-WolfStack-Secret", &state.cluster_secret)
            .timeout(std::time::Duration::from_secs(8))
            .send().await
        {
            Ok(r) if r.status().is_success() => {
                match r.bytes().await {
                    Ok(body) => return HttpResponse::Ok()
                        .content_type("application/json")
                        .body(body),
                    Err(e) => return HttpResponse::BadGateway()
                        .json(serde_json::json!({
                            "error": format!("read body: {}", e)
                        })),
                }
            }
            Ok(r) => {
                let _ = r.bytes().await;
                continue;  // try next URL
            }
            Err(_) => continue,
        }
    }
    HttpResponse::BadGateway().json(serde_json::json!({
        "error": format!("could not reach peer '{}'", peer.hostname)
    }))
}

/// Enumerate every IP this node would realistically want to expose as
/// a database target — host interfaces, WolfNet overlay, Docker + LXC
/// containers (with their human name), and VMs. Each entry carries a
/// `source` tag so the UI can group them.
async fn enumerate_local_ips(state: &web::Data<AppState>) -> Vec<serde_json::Value> {
    let mut out: Vec<serde_json::Value> = Vec::new();

    // Host-side interfaces via `ip -4 -o addr`. One line per interface.
    if let Ok(o) = std::process::Command::new("ip").args(["-4", "-o", "addr"]).output() {
        if o.status.success() {
            let text = String::from_utf8_lossy(&o.stdout);
            for line in text.lines() {
                // Format: "2: eth0    inet 10.0.0.5/24 brd 10.0.0.255 scope global eth0"
                let parts: Vec<&str> = line.split_whitespace().collect();
                if parts.len() < 4 { continue; }
                let iface = parts.get(1).unwrap_or(&"").to_string();
                let cidr = parts.get(3).unwrap_or(&"").to_string();
                let addr = cidr.split('/').next().unwrap_or("").to_string();
                if addr.is_empty() || addr.starts_with("127.") { continue; }
                out.push(serde_json::json!({
                    "address": addr,
                    "source": format!("iface:{}", iface),
                    "label": format!("{} ({})", addr, iface),
                }));
            }
        }
    }

    // Docker containers
    for c in crate::containers::docker_list_all_cached() {
        // ip_address may be "10.0.0.5" or "10.0.0.5, 10.0.1.7 (wolfnet)" etc.
        for part in c.ip_address.split(',').map(|s| s.trim()).filter(|s| !s.is_empty()) {
            let addr = part.split_whitespace().next().unwrap_or("").to_string();
            if addr.is_empty() { continue; }
            let tag = if part.contains("wolfnet") { "docker-wolfnet" } else { "docker" };
            out.push(serde_json::json!({
                "address": addr,
                "source": format!("{}:{}", tag, c.name),
                "label": format!("{} — docker:{}", addr, c.name),
            }));
        }
    }

    // LXC containers
    for c in crate::containers::lxc_list_all_cached() {
        for part in c.ip_address.split(',').map(|s| s.trim()).filter(|s| !s.is_empty()) {
            let addr = part.split_whitespace().next().unwrap_or("").to_string();
            if addr.is_empty() { continue; }
            let tag = if part.contains("wolfnet") { "lxc-wolfnet" } else { "lxc" };
            out.push(serde_json::json!({
                "address": addr,
                "source": format!("{}:{}", tag, c.name),
                "label": format!("{} — lxc:{}", addr, c.name),
            }));
        }
    }

    // VMs — only WolfNet IP is known without guest-agent probing,
    // which is fine for DB hosting (typically one WolfNet IP per VM).
    let vms = state.vms.lock().unwrap().list_vms();
    for vm in vms {
        if let Some(ip) = &vm.wolfnet_ip {
            if !ip.trim().is_empty() {
                out.push(serde_json::json!({
                    "address": ip,
                    "source": format!("vm:{}", vm.name),
                    "label": format!("{} — vm:{}", ip, vm.name),
                }));
            }
        }
    }

    // Deduplicate by address while keeping the first source tag.
    let mut seen = std::collections::HashSet::new();
    out.retain(|v| {
        let addr = v.get("address").and_then(|a| a.as_str()).unwrap_or("").to_string();
        seen.insert(addr)
    });
    out
}

/// POST /api/sql-connections/{id}/query-proxy — inter-node query
/// execution endpoint.
///
/// **Cluster-secret auth ONLY.** Session auth is explicitly rejected:
/// permission for this call is already enforced on the originating
/// node (where the UI session / agent / workflow lives). Letting a
/// remote session hit this endpoint directly would bypass the
/// originator's authorization. The cluster secret is the trust
/// token; any node holding it is trusted peer-equivalent.
///
/// On success the target node executes locally (its own `node_id`
/// matches the profile's) and returns the `SqlResult` body. The
/// target's audit log records the call with the originator's caller
/// tag so cross-node traces are intact.
pub async fn sql_connections_query_proxy(
    req: HttpRequest,
    state: web::Data<AppState>,
    path: web::Path<String>,
    body: web::Json<SqlProxyRequest>,
) -> HttpResponse {
    // Cluster-secret-only: deliberately distinct from the UI
    // /query handler so a session-authenticated user can't reach
    // this path directly. `require_cluster_auth` rejects requests
    // that either lack the X-WolfStack-Secret header or present an
    // invalid one; it does NOT fall back to session auth.
    if let Err(resp) = require_cluster_auth(&req, &state) { return resp; }

    let id = path.into_inner();
    let perm = match body.permission.as_deref().unwrap_or("read") {
        "schema" => crate::sql_connections::SqlPermission::Schema,
        "delete" => crate::sql_connections::SqlPermission::Delete,
        "update" => crate::sql_connections::SqlPermission::Update,
        _ => crate::sql_connections::SqlPermission::Read,
    };
    let timeout = body.timeout_secs.map(std::time::Duration::from_secs);

    // Reconstruct the caller from the origin tag. The tag string is
    // opaque ("agent:foo", "workflow:x:step", "ui:paul") — we wrap it
    // as Caller::Ui so the target's audit log shows the origin exactly
    // as the originator stamped it.
    let caller = crate::sql_connections::Caller::Ui(
        body.origin_caller.clone().unwrap_or_else(|| "remote".into())
    );

    // Force local execution: the originator has already routed to us.
    // Re-running the routing logic on the receiver is harmful because the
    // stored `node_id` was resolved from the originator's cluster snapshot
    // and may not match the receiver's `self_node_id` verbatim (id drift,
    // manual join-with-different-id, etc.). The originator's choice to
    // POST us this request IS the authorisation to execute locally.
    match crate::sql_connections::execute_as_target(
        &id, &body.query, perm,
        caller,
        &state.cluster_secret,
        timeout,
        body.schema.as_deref(),
    ).await {
        Ok(r) => HttpResponse::Ok().json(r),
        Err(e) => HttpResponse::BadRequest().json(serde_json::json!({ "error": e })),
    }
}

/// POST /api/sql-connections/receive — receive the full connection
/// list from a cluster peer and overwrite local config. Cluster-secret
/// auth only — same threat model as /api/router/config-receive.
///
/// We treat profiles as cluster-wide: every WolfStack node holds the
/// same list so any node can serve as the query-proxy target for any
/// connection. Proxmox-only peers are excluded from the replication
/// fan-out in `replicate_sql_connections_to_cluster` because they don't
/// run WolfStack.
pub async fn sql_connections_receive(
    req: HttpRequest,
    state: web::Data<AppState>,
    body: web::Json<crate::sql_connections::SqlConnectionsConfig>,
) -> HttpResponse {
    // Cluster-secret-only. A session-auth user on node A has no
    // business overwriting node B's SQL connection config — writes
    // go through the regular /api/sql-connections CRUD on the
    // originator, and the originator fans out via
    // `replicate_sql_connections_to_cluster` with the cluster secret.
    if let Err(resp) = require_cluster_auth(&req, &state) { return resp; }
    let cfg = body.into_inner();
    if let Err(e) = crate::sql_connections::save(&cfg) {
        return HttpResponse::InternalServerError().json(serde_json::json!({ "error": e }));
    }
    HttpResponse::Ok().json(serde_json::json!({ "received": cfg.connections.len() }))
}

/// Push the current SQL-connections config to every online WolfStack
/// peer. Fire-and-forget from the caller's perspective (spawns a task
/// so the originating HTTP handler can return immediately). Excludes
/// Proxmox-only peers, which don't run WolfStack.
fn replicate_sql_connections_to_cluster(state: web::Data<AppState>) {
    let cluster = state.cluster.clone();
    let cluster_secret = state.cluster_secret.clone();
    let self_id = crate::agent::self_node_id();
    tokio::spawn(async move {
        let cfg = crate::sql_connections::load();
        let body = match serde_json::to_string(&cfg) {
            Ok(b) => b,
            Err(e) => {
                tracing::warn!("sql-connections replicate: serialize failed: {}", e);
                return;
            }
        };
        let nodes = cluster.get_all_nodes();
        let client = &*API_HTTP_CLIENT;
        for node in nodes {
            if node.is_self || node.id == self_id { continue; }
            if !node.online { continue; }
            if node.node_type != "wolfstack" { continue; }
            let urls = build_node_urls(&node.address, node.port, "/api/sql-connections/receive");
            for url in &urls {
                let res = client.post(url)
                    .header("X-WolfStack-Secret", &cluster_secret)
                    .header("Content-Type", "application/json")
                    .timeout(std::time::Duration::from_secs(10))
                    .body(body.clone())
                    .send().await;
                match res {
                    Ok(r) if r.status().is_success() => {
                        let _ = r.bytes().await;
                        tracing::debug!("sql-connections replicated to {}", node.id);
                        break;
                    }
                    Ok(r) => {
                        let _ = r.bytes().await;
                        // Non-success = authoritative failure on that URL
                        // scheme; don't try the other URL variants.
                        break;
                    }
                    Err(_) => {
                        // Transport error — try next URL in the fallback chain.
                    }
                }
            }
        }
    });
}

/// GET /status/{slug} — public status page on dedicated port 8550.
/// Uses slug-only lookup. Data integrity is guaranteed by replication filters
/// (broadcast and pull only store own-cluster data), so a node only has its own pages.
pub async fn statuspage_public_page_dedicated(state: web::Data<AppState>, path: web::Path<String>) -> HttpResponse {
    let slug = path.into_inner();
    let page = state.statuspage.find_page_by_slug(&slug);
    match page {
        Some(p) => {
            match crate::statuspage::render_public_page_inner(&state.statuspage, &p) {
                Some(html) => HttpResponse::Ok().content_type("text/html; charset=utf-8").body(html),
                None => HttpResponse::NotFound().content_type("text/html; charset=utf-8").body(
                    r#"<!DOCTYPE html><html><head><title>Not Found</title></head><body style="display:flex;align-items:center;justify-content:center;height:100vh;font-family:sans-serif;background:#0f172a;color:#fff;"><p>Status page not found.</p></body></html>"#
                ),
            }
        }
        None => HttpResponse::NotFound().content_type("text/html; charset=utf-8").body(
            r#"<!DOCTYPE html><html><head><title>Not Found</title></head><body style="display:flex;align-items:center;justify-content:center;height:100vh;font-family:sans-serif;background:#0f172a;color:#fff;"><p>Status page not found.</p></body></html>"#
        ),
    }
}

/// Minimal config for the dedicated status page HTTP listener (port 8550).
pub fn configure_statuspage_only(cfg: &mut web::ServiceConfig) {
    cfg
        .route("/", web::get().to(statuspage_public_index))
        .route("/status", web::get().to(statuspage_public_index))
        .route("/status/{slug}", web::get().to(statuspage_public_page_dedicated));
}

#[cfg(test)]
mod compose_parse_tests {
    use super::{parse_undefined_compose_vars, parse_compose_container_actions};

    #[test]
    fn undefined_vars_extracted_from_compose_config_warnings() {
        // The real logger escapes the inner quotes (msg="The \"FOO\" ...").
        let stderr = r#"time="2026-06-27T08:20:18+01:00" level=warning msg="The \"MY_UNDEFINED_VAR\" variable is not set. Defaulting to a blank string."
time="2026-06-27T08:20:18+01:00" level=warning msg="The \"DB_PASSWORD\" variable is not set. Defaulting to a blank string."
some unrelated line
time="..." level=warning msg="The \"MY_UNDEFINED_VAR\" variable is not set. Defaulting to a blank string.""#;
        let vars = parse_undefined_compose_vars(stderr);
        assert_eq!(vars, vec!["MY_UNDEFINED_VAR".to_string(), "DB_PASSWORD".to_string()],
            "extracts each name once, order preserved, dedup");
        // Unescaped variant (in case a logger doesn't escape) also works.
        let plain = r#"The "FOO" variable is not set. Defaulting to a blank string."#;
        assert_eq!(parse_undefined_compose_vars(plain), vec!["FOO".to_string()]);
        // Nothing to report.
        assert!(parse_undefined_compose_vars("all good\nno warnings here").is_empty());
    }

    #[test]
    fn up_actions_keep_most_significant_state_per_container() {
        // A recreated container emits Recreate→Recreated→Starting→Started; an
        // unchanged one emits a single Running. We want one row per container,
        // the meaningful one.
        let out = "\
 Network app_default Created
 Container app-web-1  Recreate
 Container app-web-1  Recreated
 Container app-web-1  Starting
 Container app-web-1  Started
 Container app-cache-1  Running
";
        let actions = parse_compose_container_actions(out);
        // BTreeMap → sorted by container name.
        assert_eq!(actions, vec![
            ("app-cache-1".to_string(), "Running".to_string()),
            ("app-web-1".to_string(), "Recreated".to_string()),
        ]);
        // A purely up-to-date stack: every container just Running.
        let same = " Container x-1  Running\n Container y-1  Running\n";
        let a = parse_compose_container_actions(same);
        assert!(a.iter().all(|(_, act)| act == "Running"));
        // Network/Volume lines and transitional-only noise produce no rows.
        assert!(parse_compose_container_actions(" Network app_default Created\n Container z-1  Starting\n")
            .is_empty());
    }
}

#[cfg(test)]
mod compose_secrets_tests {
    use super::{is_injectable_secret_key, is_valid_env_var_name};

    #[test]
    fn env_var_name_filter() {
        // Valid POSIX env names — what docker compose can interpolate.
        assert!(is_valid_env_var_name("DB_PASSWORD"));
        assert!(is_valid_env_var_name("_private"));
        assert!(is_valid_env_var_name("key2"));
        // Invalid: empty, leading digit, dashes, spaces, dots, unicode.
        assert!(!is_valid_env_var_name(""));
        assert!(!is_valid_env_var_name("2fast"));
        assert!(!is_valid_env_var_name("my-secret"));
        assert!(!is_valid_env_var_name("my secret"));
        assert!(!is_valid_env_var_name("api.key"));
        assert!(!is_valid_env_var_name("clé"));
    }

    #[test]
    fn behaviour_altering_vars_never_injected() {
        // A secret named like these would change how the docker subprocess
        // runs (redirect the daemon, strip PATH, preload a library) — the
        // denylist must keep them out of the injected env.
        for k in ["PATH", "HOME", "LD_PRELOAD", "LD_LIBRARY_PATH",
                  "DOCKER_HOST", "DOCKER_CONFIG", "COMPOSE_FILE"] {
            assert!(!is_injectable_secret_key(k), "{} must be denied", k);
        }
        // Normal secrets still pass; the denylist is exact-match (case-
        // sensitive, like the environment itself) so DB_PATH etc. are fine.
        assert!(is_injectable_secret_key("DB_PASSWORD"));
        assert!(is_injectable_secret_key("DB_PATH"));
        assert!(is_injectable_secret_key("docker_host_token"));
    }
}

#[cfg(test)]
mod predictive_forward_tests {
    use super::{is_inter_node_forward, is_operator_request};

    #[test]
    fn inter_node_forward_is_a_cycle_breaker() {
        // A peer-authenticated action (require_auth → "cluster-node") is
        // itself a forward and must NOT re-fan-out to local peers — that
        // recursion is the fleet-wide CPU storm on "Mark applied". The
        // operator (session username) and API-key callers reach this
        // node as the first hop, not as a relay.
        assert!(is_inter_node_forward("cluster-node"));
        assert!(!is_inter_node_forward("admin"));
        assert!(!is_inter_node_forward("apikey:ci-bot"));
        assert!(!is_inter_node_forward(""));
    }

    #[test]
    fn only_operator_requests_fan_out_to_federations() {
        // Only a direct operator (browser session) action may take the
        // cross-cluster federation hop. A relayed forward — intra-cluster
        // ("cluster-node") or a federation relay ("apikey:…") — must not
        // re-federate, or two mutually-federated clusters ping-pong it
        // forever (A→B→A).
        assert!(is_operator_request("admin"));
        assert!(is_operator_request("paul"));
        assert!(!is_operator_request("cluster-node"));
        assert!(!is_operator_request("apikey:peer-cluster"));
        // Boundary: only the "apikey:" prefix (with colon) is the relay
        // sentinel — a username that merely starts with "apikey" is a
        // normal operator and may federate.
        assert!(is_operator_request("apikey"));
        assert!(is_operator_request("apikeys-admin"));
    }
}

#[cfg(test)]
mod external_url_tests {
    use super::{build_external_urls, build_node_urls, hostnames_same_node, is_ssrf_blocked_address};

    #[test]
    fn ssrf_guard_blocks_loopback_and_link_local_in_every_spelling() {
        assert!(is_ssrf_blocked_address("127.0.0.1"));
        assert!(is_ssrf_blocked_address("169.254.169.254"));
        assert!(is_ssrf_blocked_address("localhost"));
        assert!(is_ssrf_blocked_address("::1"));
        assert!(is_ssrf_blocked_address("[::1]"));      // bracketed must not slip past
        assert!(is_ssrf_blocked_address("fe80::1"));    // v6 link-local
        assert!(is_ssrf_blocked_address("[fe80::1]"));
        assert!(!is_ssrf_blocked_address("192.168.1.10"));
        assert!(!is_ssrf_blocked_address("2001:db8::1"));
        assert!(!is_ssrf_blocked_address("nas.lan"));
    }

    #[test]
    fn external_urls_bare_v6_is_not_split_at_its_last_group() {
        // Pre-fix: "https://::1" split host=":" port=1 — mangled AND past
        // the SSRF guard. A bare v6 loopback must yield no URLs at all.
        assert!(build_external_urls("::1", "/api/x").is_empty());
        assert!(build_external_urls("https://::1", "/api/x").is_empty());
        // A bare global v6 target survives intact, bracketed in the URL.
        let urls = build_external_urls("2001:db8::1", "/api/x");
        assert_eq!(urls, vec!["https://[2001:db8::1]:8553/api/x".to_string()]);
        // Bracketed with explicit port: exact URL first, then 8553 retry.
        let urls = build_external_urls("https://[2001:db8::1]:9000", "/api/x");
        assert_eq!(urls[0], "https://[2001:db8::1]:9000/api/x");
        assert_eq!(urls[1], "https://[2001:db8::1]:8553/api/x");
        // v4 + hostname behavior unchanged.
        let urls = build_external_urls("peer.lan", "/api/x");
        assert_eq!(urls, vec!["https://peer.lan:8553/api/x".to_string()]);
        let urls = build_external_urls("http://10.0.0.5:8554", "/api/x");
        assert_eq!(urls[0], "http://10.0.0.5:8554/api/x");
    }

    #[test]
    fn node_urls_bracket_bare_v6_only() {
        let urls = build_node_urls("fd00:10::7", 8553, "/api/agent/status");
        assert_eq!(urls[0], "https://[fd00:10::7]:8553/api/agent/status");
        assert!(urls.last().unwrap().starts_with("http://[fd00:10::7]:8553"));
        // v4 output is byte-identical to the pre-IPv6 builder.
        let urls = build_node_urls("192.168.1.7", 8553, "/p");
        assert_eq!(urls[0], "https://192.168.1.7:8553/p");
        assert!(urls.last().unwrap().starts_with("http://192.168.1.7:8553"));
    }

    #[test]
    fn hostnames_same_node_matches_and_rejects() {
        // Exact (case-insensitive).
        assert!(hostnames_same_node("immich", "immich"));
        assert!(hostnames_same_node("Immich", "immich"));
        // Short vs FQDN.
        assert!(hostnames_same_node("immich", "immich.lan"));
        assert!(hostnames_same_node("immich.example.com", "immich"));
        assert!(hostnames_same_node("immich.lan", "immich.example.com"));
        // The regression: a stale `docker-immich` peer must NOT be treated as
        // the live `immich` node (the old substring test kept it forever).
        assert!(!hostnames_same_node("docker-immich", "immich"));
        assert!(!hostnames_same_node("immich", "docker-immich"));
        // Distinct nodes never collide.
        assert!(!hostnames_same_node("pm2", "pm3"));
        assert!(!hostnames_same_node("web1", "web2"));
        // Empty names are never a match.
        assert!(!hostnames_same_node("", "immich"));
        assert!(!hostnames_same_node("immich", ""));
    }

    #[test]
    fn returning_identity_matches_reimage_and_address_move_but_not_distinct_nodes() {
        use super::node_is_returning_identity;
        // Build a registry Node from a small JSON object — most fields default.
        fn node(over: serde_json::Value) -> crate::agent::Node {
            let mut base = serde_json::json!({
                "id": "node-old", "hostname": "ws-host", "address": "10.0.0.9",
                "port": 8553, "last_seen": 0, "metrics": null,
                "components": [], "online": false, "is_self": false
            });
            for (k, v) in over.as_object().unwrap() { base[k] = v.clone(); }
            serde_json::from_value(base).unwrap()
        }

        // Reimage case: self_id regenerated (ws-new), hostname unchanged → match
        // on hostname.
        let stale = node(serde_json::json!({
            "hostname": "ws-host", "self_id": "ws-old", "cluster_name": "WolfStack"
        }));
        assert!(node_is_returning_identity(&stale, "ws-new", "ws-host", "WolfStack"));

        // Address-move case: same self_id, different hostname spelling → match
        // on self_id.
        let moved = node(serde_json::json!({
            "hostname": "old-name", "self_id": "ws-keep", "cluster_name": "WolfStack"
        }));
        assert!(node_is_returning_identity(&moved, "ws-keep", "totally-different", "WolfStack"));

        // Distinct node, different hostname AND different self_id → NO match,
        // even in the same cluster (this is the merge we must never make).
        let other = node(serde_json::json!({
            "hostname": "ws-other", "self_id": "ws-other-id", "cluster_name": "WolfStack"
        }));
        assert!(!node_is_returning_identity(&other, "ws-new", "ws-host", "WolfStack"));

        // Same hostname but a DIFFERENT cluster → never collapsed across clusters.
        let cross = node(serde_json::json!({
            "hostname": "ws-host", "self_id": "ws-x", "cluster_name": "OtherCluster"
        }));
        assert!(!node_is_returning_identity(&cross, "ws-new", "ws-host", "WolfStack"));

        // Cluster comparison is case-insensitive (matches every other
        // cluster-name comparison in the codebase).
        let cased = node(serde_json::json!({
            "hostname": "ws-host", "self_id": "ws-old", "cluster_name": "wolfstack"
        }));
        assert!(node_is_returning_identity(&cased, "ws-new", "ws-host", "WolfStack"));

        // Empty inbound identity never matches (a failed status fetch must not
        // collapse anything).
        assert!(!node_is_returning_identity(&stale, "", "", "WolfStack"));
    }

    #[test]
    fn wolfnet_ip_conflict_only_flags_confirmed_foreign_owners() {
        use super::wolfnet_ip_conflicts;
        use std::collections::{HashMap, HashSet};

        let mut routes: HashMap<String, String> = HashMap::new();
        routes.insert("10.10.10.5".into(), "10.0.0.7".into());   // owned by a LIVE peer
        routes.insert("10.10.10.9".into(), "10.0.0.42".into());  // owned by the stale self
        routes.insert("10.10.10.4".into(), "10.0.0.55".into());  // owned by a DELETED node (stale route)
        let live: HashSet<String> = ["10.0.0.7".to_string(), "10.0.0.42".to_string()].into_iter().collect();
        let stale: HashSet<String> = ["10.0.0.42".to_string()].into_iter().collect();

        // IP owned by a DIFFERENT live node → genuine conflict.
        let c = wolfnet_ip_conflicts(&["10.10.10.5".into()], &routes, &live, &stale, "10.0.0.99");
        assert_eq!(c, vec!["10.10.10.5".to_string()]);

        // IP whose route owner is a DELETED node (not in live_addrs) → NOT a
        // conflict: a stale cache entry must never block re-adding that IP
        // (wabil deleted the whole cluster then couldn't re-add 10.10.10.4).
        let c = wolfnet_ip_conflicts(&["10.10.10.4".into()], &routes, &live, &stale, "10.0.0.99");
        assert!(c.is_empty());

        // IP owned by the joining node's OWN stale (reimaged) entry → not a
        // conflict (this is the rejoin we must not reject).
        let c = wolfnet_ip_conflicts(&["10.10.10.9".into()], &routes, &live, &stale, "10.0.0.99");
        assert!(c.is_empty());

        // IP owned by the joining node's own (new) address → not a conflict.
        let mut r2 = routes.clone();
        r2.insert("10.10.10.1".into(), "10.0.0.99".into());
        let mut live2 = live.clone();
        live2.insert("10.0.0.99".into());
        let c = wolfnet_ip_conflicts(&["10.10.10.1".into()], &r2, &live2, &stale, "10.0.0.99");
        assert!(c.is_empty());

        // Unknown owner (route cache has no entry) → fail open, never reject.
        let c = wolfnet_ip_conflicts(&["10.10.10.250".into()], &routes, &live, &stale, "10.0.0.99");
        assert!(c.is_empty());

        // CIDR suffix on the reported IP is stripped before lookup.
        let c = wolfnet_ip_conflicts(&["10.10.10.5/24".into()], &routes, &live, &stale, "10.0.0.99");
        assert_eq!(c, vec!["10.10.10.5".to_string()]);
    }
}

#[cfg(test)]
mod passkey_origin_tests {
    use super::derive_passkey_rp_origin;

    // Direct local access (no reverse proxy)
    #[test]
    fn direct_http_local_no_tls() {
        let r = derive_passkey_rp_origin(Some("192.168.1.10:8553"), None, None, false).unwrap();
        assert_eq!(r.0, "192.168.1.10");
        assert_eq!(r.1, "http://192.168.1.10:8553");
    }
    #[test]
    fn direct_https_local_with_tls() {
        let r = derive_passkey_rp_origin(Some("wolfstack.local:8553"), None, None, true).unwrap();
        assert_eq!(r.0, "wolfstack.local");
        assert_eq!(r.1, "https://wolfstack.local:8553");
    }

    // Reverse proxy terminating TLS (the bug we just fixed) — wolfstack
    // itself runs HTTP (tls_enabled=false) but X-Forwarded-Proto says https.
    // Without the fix, origin would be http:// and webauthn-rs rejects.
    #[test]
    fn reverse_proxy_terminating_tls() {
        let r = derive_passkey_rp_origin(
            Some("10.0.0.5:8553"),         // wolfstack sees Host as the proxy's upstream
            Some("wolfstack.example.com"), // X-Forwarded-Host preserved by nginx
            Some("https"),                 // X-Forwarded-Proto from nginx
            false,                         // wolfstack itself isn't running TLS
        ).unwrap();
        assert_eq!(r.0, "wolfstack.example.com");
        assert_eq!(r.1, "https://wolfstack.example.com");
    }

    // Reverse proxy without X-Forwarded-Host (some setups only set proto).
    #[test]
    fn reverse_proxy_only_proto() {
        let r = derive_passkey_rp_origin(
            Some("wolfstack.example.com"), // proxy has rewritten Host to upstream
            None,
            Some("https"),
            false,
        ).unwrap();
        assert_eq!(r.0, "wolfstack.example.com");
        assert_eq!(r.1, "https://wolfstack.example.com");
    }

    // Multi-hop proxy chain: X-Forwarded-Host has comma-separated values,
    // the first is the original client-facing host.
    #[test]
    fn multi_hop_takes_first_value() {
        let r = derive_passkey_rp_origin(
            Some("internal:8553"),
            Some("external.example.com, edge-proxy.internal"),
            Some("https, http"),
            false,
        ).unwrap();
        assert_eq!(r.0, "external.example.com");
        assert_eq!(r.1, "https://external.example.com");
    }

    // X-Forwarded-Host empty (some proxies set it to "" rather than dropping it).
    #[test]
    fn empty_forwarded_host_falls_back_to_host() {
        let r = derive_passkey_rp_origin(Some("ws.local:8553"), Some(""), None, false).unwrap();
        assert_eq!(r.0, "ws.local");
        assert_eq!(r.1, "http://ws.local:8553");
    }

    // Bogus X-Forwarded-Proto values are ignored — fall back to local TLS.
    #[test]
    fn bogus_proto_falls_back() {
        let r = derive_passkey_rp_origin(Some("ws.local"), None, Some("garbage"), true).unwrap();
        assert_eq!(r.1, "https://ws.local");
        let r = derive_passkey_rp_origin(Some("ws.local"), None, Some("ftp"), false).unwrap();
        assert_eq!(r.1, "http://ws.local");
    }

    // Strip port for rp_id, keep port in origin.
    #[test]
    fn port_handling() {
        let r = derive_passkey_rp_origin(Some("host.example.com:8553"), None, None, true).unwrap();
        assert_eq!(r.0, "host.example.com");
        assert_eq!(r.1, "https://host.example.com:8553");
    }

    // No Host at all → error (we can't construct an origin without one).
    #[test]
    fn missing_host_errors() {
        let r = derive_passkey_rp_origin(None, None, None, false);
        assert!(r.is_err());
    }
    #[test]
    fn empty_host_errors() {
        let r = derive_passkey_rp_origin(Some(""), Some(""), None, false);
        assert!(r.is_err());
    }

    // IPv6 in host: rsplit_once(':') would chop on every colon. Verify the
    // "all-digits port" check protects IPv6 literals like [::1]:8553 from
    // being mangled. (The Host header for IPv6 is bracketed.)
    #[test]
    fn ipv6_host_with_port() {
        let r = derive_passkey_rp_origin(Some("[::1]:8553"), None, None, false).unwrap();
        assert_eq!(r.0, "[::1]");
        assert_eq!(r.1, "http://[::1]:8553");
    }
    #[test]
    fn ipv6_host_no_port() {
        let r = derive_passkey_rp_origin(Some("[fe80::1]"), None, None, false).unwrap();
        assert_eq!(r.0, "[fe80::1]");
        assert_eq!(r.1, "http://[fe80::1]");
    }
}

#[cfg(test)]
mod issue_repair_tests {
    use super::{valid_unit_name, repair_kind_for_unit, repair_for, Issue};

    fn svc_issue(unit: &str) -> Issue {
        Issue {
            severity: "warning".into(),
            category: "service".into(),
            title: format!("Service {} failed", unit),
            detail: format!("systemd unit {} is in failed state", unit),
        }
    }

    // ── Security boundary: only well-formed unit names reach systemctl ──
    #[test]
    fn valid_unit_names_accepted() {
        for u in [
            "logrotate.service", "clamav-freshclam.service", "chkrootkit.service",
            "snap.certbot.renew.service", "lxc-net.service", "minio.service",
            "getty@tty1.service", "systemd-networkd.socket", "foo.timer",
        ] {
            assert!(valid_unit_name(u), "should accept {}", u);
        }
    }

    #[test]
    fn injection_and_malformed_unit_names_rejected() {
        for u in [
            "",                                   // empty
            "foo",                                // no suffix
            "foo.conf",                           // wrong suffix
            "foo.service; rm -rf /",              // shell metachars
            "foo.service && reboot",
            "foo.service\nrm -rf /",              // newline
            "../../etc/passwd.service",           // path traversal chars (/)
            "foo bar.service",                    // space
            "$(id).service",                      // command substitution
            "`id`.service",                       // backticks
            "foo|bar.service",                    // pipe
        ] {
            assert!(!valid_unit_name(u), "should reject {:?}", u);
        }
    }

    #[test]
    fn overlong_unit_name_rejected() {
        let long = format!("{}.service", "a".repeat(130));
        assert!(!valid_unit_name(&long));
    }

    // ── Per-service classification ──
    #[test]
    fn unit_classification_routes_to_correct_recipe() {
        assert_eq!(repair_kind_for_unit("clamav-freshclam.service"), "clamav");
        assert_eq!(repair_kind_for_unit("clamav-daemon.service"), "clamav");
        assert_eq!(repair_kind_for_unit("chkrootkit.service"), "chkrootkit");
        assert_eq!(repair_kind_for_unit("certbot.service"), "certbot");
        assert_eq!(repair_kind_for_unit("snap.certbot.renew.service"), "certbot");
        assert_eq!(repair_kind_for_unit("lxc-net.service"), "service");
        assert_eq!(repair_kind_for_unit("minio.service"), "service");
    }

    // ── repair_for: parses the unit from detail and picks the recipe ──
    #[test]
    fn repair_for_service_issue() {
        let rep = repair_for(&svc_issue("logrotate.service")).expect("repairable");
        assert_eq!(rep.kind, "service");
        assert_eq!(rep.target, "logrotate.service");
        assert_eq!(rep.label, "Repair");

        let rep = repair_for(&svc_issue("clamav-freshclam.service")).unwrap();
        assert_eq!(rep.kind, "clamav");
    }

    #[test]
    fn repair_for_malformed_service_detail_is_none() {
        // A service issue whose detail doesn't carry a valid unit yields no button.
        let bad = Issue {
            severity: "warning".into(), category: "service".into(),
            title: "Service weird".into(),
            detail: "systemd unit not a; unit is in failed state".into(),
        };
        assert!(repair_for(&bad).is_none());
    }

    #[test]
    fn repair_for_disk_kinds() {
        let journal = Issue { severity: "info".into(), category: "disk".into(),
            title: "Journal logs using 3.1G".into(), detail: "…".into() };
        assert_eq!(repair_for(&journal).unwrap().kind, "journal");
        assert_eq!(repair_for(&journal).unwrap().label, "Clean");

        let apt = Issue { severity: "info".into(), category: "disk".into(),
            title: "APT cache using 500M".into(), detail: "…".into() };
        assert_eq!(repair_for(&apt).unwrap().kind, "apt");

        // /tmp is deliberately NOT one-click cleanable (malware staging path).
        let tmp = Issue { severity: "info".into(), category: "disk".into(),
            title: "/tmp using 2.3G".into(), detail: "…".into() };
        assert!(repair_for(&tmp).is_none());
    }

    #[test]
    fn non_repairable_categories_have_no_button() {
        for cat in ["cpu", "memory", "load", "swap", "kubernetes", "container"] {
            let i = Issue { severity: "warning".into(), category: cat.into(),
                title: "x".into(), detail: "y".into() };
            assert!(repair_for(&i).is_none(), "{} should not be one-click repairable", cat);
        }
    }
}

#[cfg(test)]
mod loopback_nfs_rewrite_tests {
    use super::rewrite_loopback_nfs_source;
    use std::net::IpAddr;

    fn ip(s: &str) -> IpAddr { s.parse().unwrap() }

    #[test]
    fn loopback_v4_and_localhost_rewritten_to_sender() {
        assert_eq!(
            rewrite_loopback_nfs_source("127.0.0.1:/srv/share", ip("10.0.0.5")),
            "10.0.0.5:/srv/share"
        );
        assert_eq!(
            rewrite_loopback_nfs_source("localhost:/exports/data", ip("10.0.0.5")),
            "10.0.0.5:/exports/data"
        );
    }

    #[test]
    fn loopback_v6_and_bracketed_handled() {
        assert_eq!(
            rewrite_loopback_nfs_source("[::1]:/srv/share", ip("10.0.0.5")),
            "10.0.0.5:/srv/share"
        );
        // sender is v6 → bracket the substituted host
        assert_eq!(
            rewrite_loopback_nfs_source("127.0.0.1:/srv/share", ip("fd00::5")),
            "[fd00::5]:/srv/share"
        );
    }

    #[test]
    fn real_server_source_never_rewritten() {
        assert_eq!(
            rewrite_loopback_nfs_source("10.0.0.9:/srv/share", ip("10.0.0.5")),
            "10.0.0.9:/srv/share"
        );
        assert_eq!(
            rewrite_loopback_nfs_source("nas.lan:/srv/share", ip("10.0.0.5")),
            "nas.lan:/srv/share"
        );
        // Malformed (no ":/") returned as-is.
        assert_eq!(rewrite_loopback_nfs_source("garbage", ip("10.0.0.5")), "garbage");
    }
}

#[cfg(test)]
mod cluster_join_hardening_tests {
    use super::is_silent_recluster;

    #[test]
    fn fresh_single_node_install_is_not_recluster() {
        // No peers yet — joining ANY cluster is fine (this is the normal
        // first-time join). Must never be blocked.
        assert!(!is_silent_recluster(false, "WolfStack", "ProdFleet"));
        assert!(!is_silent_recluster(false, "WolfStack", ""));
    }

    #[test]
    fn rejoin_same_cluster_is_not_recluster() {
        // Already a member, but the master is adding us into the SAME
        // cluster we're already in — a no-op join, allowed.
        assert!(!is_silent_recluster(true, "ProdFleet", "ProdFleet"));
    }

    #[test]
    fn join_into_different_cluster_with_peers_is_blocked() {
        // The security case: an active member of cluster A is being grafted
        // into cluster B. Hard-blocked (absent the local override).
        assert!(is_silent_recluster(true, "ProdFleet", "AttackerFleet"));
    }

    #[test]
    fn unnamed_incoming_on_fresh_node_is_allowed() {
        // First-time join (no peers) with an omitted cluster name must NOT
        // be blocked — legacy/unnamed first joins still work.
        assert!(!is_silent_recluster(false, "WolfStack", ""));
    }

    #[test]
    fn unnamed_incoming_on_active_member_is_blocked() {
        // SECURITY: an already-joined node must only accept a re-add that
        // explicitly names the cluster it's in. Omitting the name on a node
        // with peers is treated as a silent re-cluster (hard-blocked) so it
        // can't be used to bypass the guard.
        assert!(is_silent_recluster(true, "ProdFleet", ""));
    }
}

#[cfg(test)]
mod target_admin_verification_tests {
    // verify_target_admin is exercised here for its INPUT-VALIDATION and
    // role-gating behaviour that doesn't depend on /etc/shadow. Empty
    // credentials must always be rejected — a missing password must never
    // be treated as a successful admin proof. (Full crypt()/group checks
    // require a real /etc/shadow + /etc/group and are validated in
    // integration / live testing, declared in the summary.)
    use crate::auth::verify_target_admin;

    #[test]
    fn empty_credentials_rejected() {
        assert!(!verify_target_admin("", ""));
        assert!(!verify_target_admin("root", ""));
        assert!(!verify_target_admin("", "hunter2"));
    }

    #[test]
    fn unknown_user_with_garbage_password_rejected() {
        // A user that exists in neither the WolfStack store nor /etc/shadow
        // with a random password must not authenticate.
        assert!(!verify_target_admin("definitely-not-a-real-user-xyz", "nope"));
    }
}
